/* =====================================================================
   SES Terminale — Banque de questions (extension 8) : DOUBLEMENT
   ---------------------------------------------------------------------
   Ajouté à window.SES_QUIZ. Gros lot couvrant les 12 chapitres
   (généré puis filtré sans collision avec quiz.js..quiz8.js).
   ===================================================================== */
(function () {
  var Q = window.SES_QUIZ; if (!Q) { window.SES_QUIZ = Q = {}; }
  function add(id, extra){
    var t = Q[id]; if (!t) { t = Q[id] = { qcm:[], vf:[], trous:[] }; }
    ["qcm","vf","trous"].forEach(function(k){ if (extra[k]) t[k] = (t[k]||[]).concat(extra[k]); });
  }
  add("eco-croissance", {"qcm":[{"q":"Combien de formes d'innovation Schumpeter distingue-t-il ?","o":["Trois","Cinq","Deux","Sept"],"c":1,"e":"Schumpeter distingue cinq formes : nouveau produit, nouveau procédé, nouveau débouché, nouvelle source de matières premières, nouvelle organisation."},{"q":"Selon Schumpeter, les innovations majeures ont tendance à :","o":["se répartir uniformément dans le temps","se regrouper en grappes","apparaître uniquement en période de crise","ne concerner que l'industrie lourde"],"c":1,"e":"Schumpeter parle de « grappes d'innovations » qui se diffusent par vagues et soutiennent l'expansion."},{"q":"Les cycles longs d'environ 40 à 60 ans associés aux vagues d'innovation portent le nom de :","o":["les cycles courts des affaires dits de Juglar","cycles de Kitchin","cycles de Keynes","cycles de Kondratiev"],"c":3,"e":"Les cycles longs (40-60 ans) tirés par les innovations majeures sont les cycles de Kondratiev."},{"q":"Pourquoi la connaissance est-elle souvent qualifiée de bien « non rival » ?","o":["parce qu'elle est gratuite à produire","parce que son usage par un agent n'empêche pas son usage par un autre","parce qu'elle ne s'achète pas","parce qu'elle disparaît quand on l'utilise"],"c":1,"e":"Un bien non rival peut être utilisé simultanément par plusieurs agents sans que cela diminue la quantité disponible : c'est le cas du savoir."},{"q":"Le brevet confère à l'innovateur :","o":["une subvention publique versée à perpétuité par l'État","une exonération totale d'impôt","la propriété du marché concerné","un monopole temporaire d'exploitation"],"c":3,"e":"Le brevet accorde un droit exclusif d'exploitation pour une durée limitée, afin d'inciter à innover."},{"q":"Le « paradoxe de Solow » désigne le fait que :","o":["les ordinateurs sont partout sauf dans les statistiques de productivité","la croissance enrichit les pauvres","le capital remplace toujours le travail","l'épargne nuit à l'investissement"],"c":0,"e":"Solow ironisait : « on voit des ordinateurs partout sauf dans les statistiques de productivité », soulignant le décalage entre diffusion technologique et gains mesurés."},{"q":"Une innovation de procédé consiste à :","o":["ouvrir un débouché commercial sur un marché étranger","introduire une nouvelle méthode de production","fusionner deux entreprises","lancer un produit inédit"],"c":1,"e":"L'innovation de procédé porte sur la façon de produire (nouvelle technique, nouvelle organisation de la fabrication)."},{"q":"Pourquoi le marché tend-il à sous-produire la recherche fondamentale ?","o":["parce que ses bénéfices sont difficilement appropriables par celui qui finance","parce qu'elle coûte peu","parce qu'elle est interdite aux entreprises","parce qu'elle ne sert à rien"],"c":0,"e":"Les externalités positives et la non-rivalité du savoir empêchent l'innovateur d'en capter tous les bénéfices : d'où une sous-production sans intervention publique."},{"q":"L'intervention de l'État dans la R&D se justifie principalement par :","o":["la volonté de nationaliser les entreprises","l'existence de défaillances de marché","le refus de la concurrence","la baisse des salaires"],"c":1,"e":"Externalités et non-rivalité du savoir constituent des défaillances de marché qui justifient subventions, financement public et protection de la propriété intellectuelle."},{"q":"L'empreinte écologique mesure :","o":["la surface bioproductive nécessaire pour répondre à la consommation humaine","la richesse monétaire moyenne produite par habitant d'un pays sur une année","le taux de chômage","l'inflation"],"c":0,"e":"L'empreinte écologique évalue la surface productive nécessaire pour fournir les ressources consommées et absorber les déchets."},{"q":"On parle de « découplage » lorsque :","o":["la croissance et les pressions environnementales évoluent dans le même sens","le PIB cesse de croître","les inégalités se réduisent","la croissance augmente alors que les pressions environnementales diminuent"],"c":3,"e":"Le découplage désigne une croissance économique qui s'accompagne d'une moindre dégradation environnementale."},{"q":"Dans la soutenabilité faible, les différents types de capital sont supposés :","o":["non substituables","tous d'origine naturelle","substituables entre eux","sans valeur économique"],"c":2,"e":"La soutenabilité faible postule que le capital naturel peut être remplacé par du capital physique ou technologique."},{"q":"Quel auteur a popularisé l'idée que les institutions « inclusives » expliquent la prospérité des nations ?","o":["Jean Tirole","David Ricardo","Daron Acemoglu","Thomas Malthus"],"c":2,"e":"Acemoglu et Robinson opposent institutions inclusives (favorables à la croissance) et institutions extractives."},{"q":"Le capital physique correspond :","o":["aux savoirs, qualifications et compétences accumulés par les salariés","aux ressources naturelles","à l'ensemble des machines, bâtiments et équipements productifs","aux brevets détenus"],"c":2,"e":"Le capital physique (ou technique) regroupe les biens de production durables : machines, locaux, équipements."},{"q":"Une externalité négative liée à la croissance est typiquement :","o":["la formation des travailleurs","la diffusion des connaissances","la hausse de l'espérance de vie","la pollution"],"c":3,"e":"La pollution est un coût supporté par la collectivité sans contrepartie marchande : une externalité négative."},{"q":"Pour internaliser une externalité négative comme la pollution, l'État peut :","o":["instaurer une taxe (taxe pigouvienne)","augmenter uniformément tous les salaires du secteur privé","supprimer les impôts","interdire l'investissement"],"c":0,"e":"Une taxe (dite pigouvienne) fait payer au pollueur le coût social, l'incitant à réduire son activité polluante."},{"q":"Le capital naturel désigne :","o":["l'épargne des ménages","les infrastructures publiques","le savoir-faire des entreprises","l'ensemble des ressources et écosystèmes fournis par la nature"],"c":3,"e":"Le capital naturel regroupe les ressources naturelles et services écosystémiques mobilisables par l'activité économique."},{"q":"La croissance économique contribue généralement à l'amélioration du niveau de vie car elle permet :","o":["une baisse mécanique des inégalités","la disparition du chômage","une hausse du revenu par habitant","la fin de la pollution"],"c":2,"e":"La croissance augmente le PIB par habitant et le pouvoir d'achat, mais ne réduit pas automatiquement inégalités ou pollution."},{"q":"Parmi ces indicateurs, lequel cherche à corriger le PIB en intégrant le bien-être ?","o":["l'IDH","le taux d'inflation","la balance commerciale","le taux d'épargne"],"c":0,"e":"L'IDH dépasse le seul revenu en intégrant santé (espérance de vie) et éducation, indicateurs de développement humain."},{"q":"Les dépenses de R&D sont considérées comme :","o":["une consommation intermédiaire détruite","un investissement immatériel source de croissance","une dépense improductive","un transfert social"],"c":1,"e":"La R&D est un investissement immatériel : elle accumule des connaissances qui nourrissent le progrès technique."},{"q":"Selon les théories de la croissance endogène, le progrès technique est :","o":["un don gratuit tombé du ciel","totalement imprévisible","le produit de décisions d'investissement des agents","sans lien avec l'éducation"],"c":2,"e":"La croissance endogène fait du progrès technique le résultat d'investissements en R&D, capital humain et infrastructures."},{"q":"Un effet de la croissance sur l'espérance de vie est généralement :","o":["négatif partout","nul","impossible à mesurer","positif via l'amélioration des conditions sanitaires"],"c":3,"e":"La croissance permet d'investir dans la santé, l'alimentation et les infrastructures, ce qui élève l'espérance de vie."},{"q":"Les rendements croissants évoqués par la croissance endogène signifient que :","o":["la production augmente moins vite que les facteurs","les facteurs sont toujours décroissants","la croissance s'arrête fatalement","l'accumulation de connaissances accroît l'efficacité globale"],"c":3,"e":"Grâce aux externalités de connaissance, l'investissement engendre des rendements croissants au niveau global, soutenant une croissance auto-entretenue."},{"q":"Une « invention » se transforme en « innovation » lorsqu'elle est :","o":["brevetée par un laboratoire","appliquée et introduite avec succès sur le marché","publiée dans une revue scientifique","financée par l'État"],"c":1,"e":"Pour Schumpeter, l'innovation suppose l'application économique de l'invention : sa mise sur le marché."},{"q":"Le capital humain s'accroît notamment par :","o":["l'achat de nouvelles machines par les entreprises industrielles","l'extraction de pétrole","l'éducation et la formation","la construction de routes"],"c":2,"e":"Éducation, formation et expérience augmentent les compétences des individus, donc le capital humain."},{"q":"La règle de soutenabilité forte impose de :","o":["remplacer librement la nature par des machines","préserver un stock minimal de capital naturel","maximiser le PIB à court terme","ignorer les générations futures"],"c":1,"e":"La soutenabilité forte considère le capital naturel comme non substituable : un stock critique doit être maintenu."},{"q":"Le progrès technique peut être source de chômage :","o":["de manière transitoire par destruction d'emplois (chômage technologique)","jamais","de façon définitive et totale","seulement dans l'agriculture"],"c":0,"e":"La destruction créatrice détruit des emplois anciens tout en en créant de nouveaux : le chômage technologique est surtout transitoire."},{"q":"Le financement de l'innovation peut être assuré par :","o":["des sources variées : autofinancement, marchés financiers, capital-risque, aides publiques","uniquement l'État","exclusivement les banques centrales","les seuls ménages"],"c":0,"e":"L'innovation se finance par autofinancement, emprunt, marchés financiers, capital-risque et soutien public combinés."},{"q":"Une croissance « verte » désigne une croissance qui :","o":["cherche à concilier activité économique et préservation écologique","ignore l'environnement","supprime toute industrie","repose uniquement sur l'agriculture"],"c":0,"e":"La croissance verte vise un découplage entre création de richesses et dégradation de l'environnement."},{"q":"Le PIB ne comptabilise pas :","o":["la production marchande des entreprises","les services publics non marchands","le travail domestique non rémunéré","la valeur ajoutée industrielle"],"c":2,"e":"Le travail domestique, le bénévolat et l'économie souterraine échappent au PIB, l'une de ses principales limites."}],"vf":[{"s":"Schumpeter distingue cinq formes d'innovation, dont l'ouverture d'un nouveau débouché.","a":true,"e":"Les cinq formes sont : nouveau produit, nouveau procédé, nouveau débouché, nouvelle source de matières premières, nouvelle organisation."},{"s":"Les innovations majeures se diffusent de façon régulière et continue dans le temps.","a":false,"e":"Schumpeter montre qu'elles se regroupent en « grappes », ce qui explique les cycles longs (Kondratiev)."},{"s":"La connaissance est un bien non rival : son usage par un agent n'en prive pas les autres.","a":true,"e":"La non-rivalité du savoir explique les externalités positives de connaissance et la sous-production marchande."},{"s":"Le brevet accorde un monopole d'exploitation permanent et illimité.","a":false,"e":"Le brevet confère un monopole temporaire (durée limitée), pas permanent."},{"s":"Dans la soutenabilité faible, le capital naturel peut être remplacé par du capital technique.","a":true,"e":"La soutenabilité faible suppose la substituabilité des capitaux ; la soutenabilité forte la refuse."},{"s":"L'empreinte écologique mesure la richesse monétaire produite par un pays.","a":false,"e":"Elle mesure la surface bioproductive nécessaire à la consommation humaine, pas une richesse monétaire."},{"s":"On parle de découplage quand la croissance se poursuit en réduisant les pressions environnementales.","a":true,"e":"Le découplage sépare la trajectoire de la croissance de celle des dégradations écologiques."},{"s":"Selon Acemoglu, des institutions inclusives favorisent la croissance.","a":true,"e":"Acemoglu et Robinson opposent institutions inclusives (favorables) et extractives (défavorables) à la croissance."},{"s":"Le marché finance spontanément un niveau optimal de recherche fondamentale.","a":false,"e":"Externalités et non-rivalité du savoir entraînent une sous-production : l'intervention publique est justifiée."},{"s":"Une taxe sur les émissions polluantes permet d'internaliser une externalité négative.","a":true,"e":"La taxe pigouvienne fait supporter au pollueur le coût social de son activité."},{"s":"Le PIB comptabilise le travail domestique non rémunéré.","a":false,"e":"Le travail domestique échappe au PIB, ce qui en constitue une limite reconnue."},{"s":"Le capital physique regroupe les machines, équipements et bâtiments productifs.","a":true,"e":"Le capital physique (ou technique) désigne les biens durables utilisés pour produire."},{"s":"Le paradoxe de Solow souligne un décalage entre diffusion des technologies et gains de productivité mesurés.","a":true,"e":"Solow : « on voit des ordinateurs partout sauf dans les statistiques de productivité »."},{"s":"La croissance économique réduit automatiquement les inégalités de revenus.","a":false,"e":"La croissance élève le revenu moyen mais peut accroître ou réduire les inégalités selon sa répartition."},{"s":"Les dépenses de R&D constituent un investissement immatériel favorable à la croissance.","a":true,"e":"La R&D accumule des connaissances, moteur du progrès technique et de la croissance endogène."}],"trous":[{"t":"Schumpeter distingue _____ formes d'innovation (nombre en chiffres ou en lettres).","a":"cinq","alt":["5"],"e":"Nouveau produit, nouveau procédé, nouveau débouché, nouvelle source de matières premières, nouvelle organisation."},{"t":"Les innovations majeures se regroupent dans le temps en _____ d'innovations (Schumpeter).","a":"grappes","alt":["grappe"],"e":"Les « grappes d'innovations » expliquent les vagues d'expansion et les cycles longs."},{"t":"Les cycles longs d'environ 40 à 60 ans portés par les innovations sont les cycles de _____.","a":"Kondratiev","alt":["Kondratieff"],"e":"Les cycles longs liés aux vagues technologiques sont nommés d'après Kondratiev."},{"t":"Un bien dont l'usage par un agent n'empêche pas l'usage par un autre est dit _____.","a":"non rival","alt":["non-rival","non rivale"],"e":"La connaissance est un bien non rival, d'où ses externalités positives."},{"t":"Le titre qui accorde à l'innovateur un monopole temporaire d'exploitation est le _____.","a":"brevet","e":"Le brevet protège l'innovation et incite à la R&D en garantissant un retour sur investissement."},{"t":"La surface bioproductive nécessaire pour répondre à la consommation humaine est l'empreinte _____.","a":"écologique","e":"L'empreinte écologique mesure la pression de l'activité humaine sur les ressources naturelles."},{"t":"Quand la croissance se poursuit tout en réduisant les pressions environnementales, on parle de _____.","a":"découplage","e":"Le découplage sépare la création de richesses de la dégradation écologique."},{"t":"Pour Acemoglu, des institutions _____ (favorables à la participation et à l'innovation) soutiennent la croissance.","a":"inclusives","alt":["inclusive"],"e":"Opposées aux institutions « extractives », les institutions inclusives encouragent l'investissement et l'innovation."},{"t":"L'ensemble des machines, bâtiments et équipements servant à produire constitue le capital _____.","a":"physique","alt":["technique"],"e":"Le capital physique (ou technique) est l'un des facteurs accumulables de la croissance."},{"t":"L'ensemble des ressources et écosystèmes fournis par la nature forme le capital _____.","a":"naturel","e":"Le capital naturel est au cœur du débat sur la soutenabilité de la croissance."},{"t":"Une taxe qui fait payer au pollueur le coût social de la pollution est une taxe _____.","a":"pigouvienne","alt":["pigovienne"],"e":"La taxe pigouvienne internalise l'externalité négative."},{"t":"Le décalage relevé par Solow entre informatisation et gains de productivité est appelé le _____ de Solow.","a":"paradoxe","e":"« On voit des ordinateurs partout sauf dans les statistiques de productivité »."},{"t":"Dans la soutenabilité _____, le capital naturel est jugé substituable par du capital technique.","a":"faible","e":"À l'inverse, la soutenabilité forte considère le capital naturel comme non substituable."},{"t":"L'activité de recherche-développement, notée R&D, est un investissement _____ (par opposition à matériel).","a":"immatériel","alt":["immatérielle"],"e":"La R&D accumule des connaissances : c'est un investissement immatériel."},{"t":"Pour transformer une invention en innovation, il faut la mettre sur le _____ (Schumpeter).","a":"marché","e":"L'innovation suppose l'application économique et la commercialisation de l'invention."}]});
  add("eco-commerce", {"qcm":[{"q":"Le taux d'ouverture d'une économie se calcule en rapportant au PIB :","o":["la moyenne des exportations et des importations de biens et services","le solde de la balance commerciale","la seule valeur des exportations de marchandises","les investissements directs reçus de l'étranger"],"c":0,"e":"Taux d'ouverture = [(exportations + importations)/2] / PIB, exprimé en %. Il mesure le degré d'insertion dans le commerce mondial."},{"q":"La balance commerciale d'un pays est excédentaire lorsque :","o":["ses importations dépassent ses exportations","la valeur de ses exportations de biens dépasse celle de ses importations de biens","ses entrées d'IDE dépassent ses sorties d'IDE","sa monnaie s'apprécie"],"c":1,"e":"La balance commerciale (biens) est excédentaire si exportations > importations. Le solde est alors positif."},{"q":"Soit deux pays produisant du drap et du vin : le Portugal est meilleur dans les deux biens mais relativement plus avantagé dans le vin. Selon Ricardo :","o":["seul le Portugal gagne à l'échange","le Portugal doit tout produire lui-même","le Portugal se spécialise dans le vin et l'Angleterre dans le drap, les deux gagnant à l'échange","l'Angleterre n'a aucun intérêt à commercer faute d'avantage absolu"],"c":2,"e":"Chaque pays se spécialise là où son avantage relatif est le plus fort (ou son désavantage le plus faible) : les deux y gagnent."},{"q":"Le théorème HOS prévoit qu'un pays exporte le bien qui utilise intensément :","o":["le facteur de production le plus rare chez lui","le facteur de production le plus abondant chez lui","exclusivement du travail qualifié","le capital, quelle que soit sa dotation"],"c":1,"e":"Heckscher-Ohlin : un pays exporte le bien intensif dans le facteur dont il est relativement le mieux doté (donc le moins cher)."},{"q":"Les « gains de variété » liés au commerce international désignent :","o":["la hausse du prix des produits importés","l'accès des consommateurs à une plus grande diversité de produits","la baisse du nombre de firmes sur le marché","la réduction des échanges intra-branche"],"c":1,"e":"L'ouverture élargit la gamme de biens disponibles : les consommateurs bénéficient d'un choix accru, un gain souligné par Krugman."},{"q":"L'externalisation (outsourcing) se distingue de la délocalisation car elle consiste à :","o":["confier une activité à une autre entreprise, qui peut rester dans le même pays","toujours transférer la production à l'étranger","fermer définitivement une unité de production","importer uniquement des matières premières"],"c":0,"e":"Externaliser = faire réaliser une tâche par un tiers (sous-traitance), ici ou ailleurs ; délocaliser = transférer la production à l'étranger. Les deux notions ne se recouvrent pas."},{"q":"L'OMC, créée en 1995, succède au :","o":["FMI","GATT","Plan Marshall","Système de Bretton Woods monétaire"],"c":1,"e":"L'Organisation mondiale du commerce prend la suite du GATT (Accord général sur les tarifs douaniers et le commerce) signé en 1947."},{"q":"Une mesure protectionniste de type « barrière non tarifaire » est :","o":["un droit de douane ad valorem","une norme sanitaire ou technique restreignant l'accès au marché","une dévaluation de la monnaie","un impôt sur les sociétés exportatrices"],"c":1,"e":"Les barrières non tarifaires (normes, quotas, formalités) limitent les importations sans recourir aux droits de douane."},{"q":"Un quota d'importation est un instrument protectionniste qui :","o":["taxe chaque unité importée","limite la quantité d'un bien pouvant être importée","subventionne les exportateurs nationaux","fixe un prix minimum à l'exportation"],"c":1,"e":"Le quota plafonne en volume les importations d'un produit : c'est une barrière non tarifaire quantitative."},{"q":"Les principaux gagnants directs du libre-échange dans un pays sont généralement :","o":["les secteurs concurrencés par les importations","les consommateurs et les secteurs exportateurs compétitifs","uniquement l'État via les droits de douane","les seuls travailleurs non qualifiés"],"c":1,"e":"Consommateurs (prix plus bas, variété) et secteurs exportant leur avantage comparatif gagnent ; les secteurs concurrencés par les importations peuvent perdre."},{"q":"Une subvention à l'exportation est considérée comme une mesure :","o":["de libre-échange pur","protectionniste, car elle fausse la concurrence en faveur des producteurs nationaux","monétaire","sans effet sur les échanges"],"c":1,"e":"Subventionner ses exportateurs revient à soutenir artificiellement la compétitivité nationale : c'est une forme de protectionnisme encadrée par l'OMC."},{"q":"Selon le théorème HOS, l'ouverture commerciale tend à :","o":["égaliser les rémunérations relatives des facteurs entre pays","supprimer tout échange entre nations","faire disparaître les dotations factorielles","rendre le travail qualifié partout plus rare"],"c":0,"e":"Stolper-Samuelson / égalisation des prix des facteurs : le commerce rapproche les rémunérations relatives du facteur abondant et du facteur rare."},{"q":"Dans le modèle de Melitz, l'ouverture au commerce conduit à :","o":["la survie des seules firmes les moins productives","la sélection des firmes les plus productives, qui seules exportent","l'uniformisation de la productivité des firmes","la disparition des échanges intra-branche"],"c":1,"e":"Melitz montre que seules les firmes les plus productives supportent les coûts d'exportation : le commerce opère une sélection au sein d'une même branche."},{"q":"Une chaîne de valeur mondiale (CVM) désigne :","o":["la concentration de toute la production dans un seul pays","la répartition des étapes de production d'un bien entre plusieurs pays","un accord de libre-échange régional","la liste des droits de douane d'un produit"],"c":1,"e":"La CVM correspond à la fragmentation internationale des étapes (conception, composants, assemblage, distribution) entre différents pays."},{"q":"Une dégradation des termes de l'échange d'un pays signifie que :","o":["ses prix à l'exportation augmentent plus vite que ses prix à l'importation","il faut exporter davantage pour importer la même quantité de biens","sa balance commerciale devient excédentaire","ses droits de douane baissent"],"c":1,"e":"Termes de l'échange = prix des exportations / prix des importations. Leur dégradation oblige à exporter plus pour un même volume d'importations."},{"q":"L'argument de List en faveur d'un protectionnisme « éducateur » suppose que la protection soit :","o":["permanente et générale","temporaire et ciblée sur les industries naissantes","réservée aux secteurs déjà dominants à l'export","appliquée seulement aux biens agricoles"],"c":1,"e":"List défend une protection limitée dans le temps, le temps que l'industrie naissante atteigne une taille compétitive, puis levée."},{"q":"La compétitivité-prix d'un pays dépend notamment :","o":["de la qualité et de l'image de marque","du coût du travail, de la productivité et du taux de change","du nombre de brevets déposés","de la diversité des produits offerts"],"c":1,"e":"La compétitivité-prix joue sur les coûts (salaires, productivité) et le taux de change ; qualité et innovation relèvent de la compétitivité hors-prix."},{"q":"Une firme réalise un IDE « horizontal » lorsqu'elle :","o":["fragmente ses étapes de production entre pays","implante à l'étranger une unité reproduisant son activité pour servir le marché local","exporte simplement ses produits","achète des titres financiers étrangers sans contrôle"],"c":1,"e":"IDE horizontal = duplication de l'activité à l'étranger pour accéder au marché ; IDE vertical = fragmentation de la production. L'achat de titres sans contrôle relève de l'investissement de portefeuille."},{"q":"Un droit de douane « ad valorem » est :","o":["un montant fixe par unité importée","un pourcentage de la valeur du bien importé","une interdiction totale d'importer","une subvention versée à l'importateur"],"c":1,"e":"Le droit ad valorem est proportionnel à la valeur du bien (ex. 10 %), contrairement au droit spécifique qui est un montant fixe par unité."},{"q":"L'apparition d'un commerce intra-branche entre pays développés s'explique surtout par :","o":["des dotations factorielles très différentes","les économies d'échelle et la différenciation des produits","l'absence totale de droits de douane","la pénurie de facteurs de production"],"c":1,"e":"Krugman : entre pays similaires, l'échange croisé de produits proches mais différenciés repose sur les rendements croissants (économies d'échelle) et le goût pour la variété."},{"q":"Le principe de la « nation la plus favorisée » à l'OMC impose à un membre :","o":["de réserver ses meilleures conditions à un seul partenaire","d'étendre à tous les membres tout avantage commercial accordé à l'un d'eux","de fermer son marché aux pays en développement","de subventionner ses exportations"],"c":1,"e":"La clause de la nation la plus favorisée garantit la non-discrimination : un avantage tarifaire concédé à un membre doit être généralisé à tous."},{"q":"Un IDE « vertical » vise principalement à :","o":["servir le marché local du pays d'accueil","exploiter des différences de coûts en localisant certaines étapes à l'étranger","spéculer sur les devises","contourner les normes comptables"],"c":1,"e":"L'IDE vertical fragmente la chaîne de production pour profiter de coûts plus bas (main-d'oeuvre, ressources) à l'étranger."},{"q":"Le « contenu en importations des exportations » mesure :","o":["la part de biens importés incorporés dans les produits qu'un pays exporte","le total des droits de douane perçus","le nombre de firmes exportatrices","la balance des services"],"c":0,"e":"Dans les chaînes de valeur mondiales, une part croissante de la valeur exportée provient d'intrants importés : un même bien traverse plusieurs frontières."},{"q":"Une politique protectionniste comporte des coûts car elle :","o":["réduit toujours le chômage durablement","renchérit les biens pour les consommateurs et peut provoquer des représailles","accroît mécaniquement la productivité","supprime les dotations factorielles"],"c":1,"e":"Le protectionnisme augmente les prix intérieurs, réduit la variété et expose à des mesures de rétorsion (guerre commerciale)."},{"q":"La différenciation « horizontale » des produits désigne des biens :","o":["de qualités nettement hiérarchisées","de qualité comparable mais aux caractéristiques différentes (couleur, style)","strictement identiques","tous fabriqués dans le même pays"],"c":1,"e":"Différenciation horizontale = variétés de qualité proche répondant à des goûts différents ; la différenciation verticale, elle, hiérarchise les produits par la qualité."},{"q":"Le « dumping » est combattu par l'OMC notamment par :","o":["des subventions aux importateurs","des droits antidumping compensant la vente à perte","une baisse générale des tarifs","l'interdiction des IDE"],"c":1,"e":"Face à la vente à un prix inférieur au coût (ou au prix du marché domestique), l'OMC autorise des droits antidumping pour rétablir une concurrence loyale."},{"q":"Une zone de libre-échange se distingue d'une union douanière car elle :","o":["impose un tarif extérieur commun","supprime les droits entre membres sans tarif extérieur commun","instaure une monnaie unique","interdit toute circulation des capitaux"],"c":1,"e":"Zone de libre-échange : suppression des droits entre membres, chacun gardant sa politique douanière externe. L'union douanière y ajoute un tarif extérieur commun."},{"q":"L'« avantage comparatif » d'un pays peut être construit (et non seulement hérité) grâce :","o":["aux seules dotations naturelles","aux politiques d'éducation, de R&D et d'innovation","à la suppression de tout commerce","au protectionnisme permanent"],"c":1,"e":"Au-delà des dotations héritées, un pays peut bâtir son avantage comparatif via le capital humain, la R&D et l'innovation (avantages comparatifs construits)."},{"q":"La spécialisation internationale d'un pays présente le risque de :","o":["supprimer toute concurrence étrangère","le rendre vulnérable aux chocs frappant ses secteurs spécialisés","accroître sans limite ses dotations factorielles","annuler ses termes de l'échange"],"c":1,"e":"Se spécialiser expose à une forte dépendance : un choc de demande ou de prix sur le secteur de spécialisation fragilise toute l'économie."},{"q":"Le commerce international peut accroître les inégalités salariales dans un pays développé en :","o":["augmentant la demande de travail non qualifié","pénalisant le travail non qualifié, concurrencé par les pays à bas salaires","supprimant le travail qualifié","égalisant tous les salaires nationaux"],"c":1,"e":"L'ouverture met le travail non qualifié des pays développés en concurrence avec celui des pays à bas coût, tendant à creuser l'écart de rémunération qualifiés/non-qualifiés."}],"vf":[{"s":"Le taux d'ouverture rapporte la moyenne des exportations et importations au PIB.","a":true,"e":"Taux d'ouverture = [(X + M)/2] / PIB ; il mesure l'insertion d'une économie dans les échanges mondiaux."},{"s":"Une balance commerciale déficitaire signifie que les exportations de biens dépassent les importations.","a":false,"e":"Un déficit commercial signifie au contraire que les importations de biens excèdent les exportations."},{"s":"L'OMC a été créée en 1995 et a succédé au GATT.","a":true,"e":"L'Organisation mondiale du commerce, instituée en 1995, prend la suite du GATT de 1947."},{"s":"Un quota d'importation est une barrière tarifaire.","a":false,"e":"Le quota limite les quantités importées : c'est une barrière non tarifaire, pas un droit de douane."},{"s":"Selon le théorème HOS, un pays exporte le bien intensif dans son facteur le plus abondant.","a":true,"e":"Heckscher-Ohlin : la spécialisation suit la dotation relative en facteurs, le pays exportant le bien qui utilise son facteur abondant."},{"s":"L'externalisation implique nécessairement un transfert de production à l'étranger.","a":false,"e":"L'externalisation (sous-traitance) peut se faire dans le même pays ; seule la délocalisation suppose un transfert à l'étranger."},{"s":"Les gains de variété correspondent à l'élargissement de la gamme de produits offerts aux consommateurs grâce au commerce.","a":true,"e":"L'ouverture donne accès à davantage de variétés de biens : c'est un gain à l'échange mis en avant par Krugman."},{"s":"Une subvention à l'exportation est une mesure de libre-échange.","a":false,"e":"Subventionner ses exportateurs fausse la concurrence en faveur des producteurs nationaux : c'est une mesure protectionniste."},{"s":"Les termes de l'échange se dégradent quand les prix à l'importation augmentent plus vite que les prix à l'exportation.","a":true,"e":"Termes de l'échange = prix X / prix M ; si les prix d'importation montent plus vite, le rapport baisse, donc dégradation."},{"s":"Dans le modèle de Melitz, l'ouverture sélectionne les firmes les plus productives au sein d'une branche.","a":true,"e":"Seules les firmes les plus productives supportent les coûts fixes d'exportation : le commerce opère une sélection intra-branche."},{"s":"Une chaîne de valeur mondiale concentre toutes les étapes de production dans un seul pays.","a":false,"e":"Au contraire, la CVM répartit (fragmente) les étapes de production entre plusieurs pays."},{"s":"Un IDE horizontal consiste à dupliquer son activité à l'étranger pour servir le marché local.","a":true,"e":"L'IDE horizontal reproduit l'activité dans le pays d'accueil ; l'IDE vertical fragmente la production pour réduire les coûts."},{"s":"La clause de la nation la plus favorisée autorise un membre de l'OMC à discriminer entre ses partenaires.","a":false,"e":"Cette clause impose la non-discrimination : tout avantage accordé à un membre doit être étendu à tous les autres."},{"s":"Le protectionnisme peut entraîner des représailles commerciales de la part des partenaires.","a":true,"e":"Les mesures protectionnistes exposent à des mesures de rétorsion, pouvant déclencher une guerre commerciale."},{"s":"L'avantage comparatif d'un pays est uniquement hérité de ses dotations naturelles et ne peut être construit.","a":false,"e":"Un avantage comparatif peut aussi être construit par l'éducation, la R&D et l'innovation, au-delà des dotations héritées."}],"trous":[{"t":"Le rapport entre la moyenne des exportations et importations et le PIB est le taux d'_____.","a":"ouverture","e":"Le taux d'ouverture mesure l'insertion d'une économie dans le commerce mondial."},{"t":"L'organisation créée en 1995 pour réguler le commerce mondial, qui succède au GATT, est l'_____ (sigle).","a":"OMC","alt":["O.M.C."],"e":"L'Organisation mondiale du commerce a remplacé le GATT en 1995."},{"t":"Une barrière protectionniste qui limite en quantité les importations d'un bien est un _____.","a":"quota","e":"Le quota est une barrière non tarifaire quantitative."},{"t":"Vendre un produit à l'étranger à un prix inférieur à son coût ou à son prix domestique s'appelle le _____.","a":"dumping","e":"Le dumping est combattu par des droits antidumping autorisés par l'OMC."},{"t":"Le rapport entre le prix des exportations et le prix des importations d'un pays correspond aux _____ de l'échange.","a":"termes","e":"Les termes de l'échange se dégradent quand il faut exporter davantage pour importer autant."},{"t":"Le solde positif ou négatif entre exportations et importations de biens figure dans la _____ commerciale.","a":"balance","e":"La balance commerciale est excédentaire si les exportations de biens dépassent les importations."},{"t":"Confier une activité à une autre entreprise, éventuellement dans le même pays, est une _____.","a":"externalisation","alt":["sous-traitance"],"e":"L'externalisation se distingue de la délocalisation, qui suppose un transfert à l'étranger."},{"t":"La répartition des étapes de production d'un bien entre plusieurs pays forme une chaîne de _____ mondiale.","a":"valeur","e":"La chaîne de valeur mondiale (CVM) traduit la fragmentation internationale de la production."},{"t":"L'accès des consommateurs à une plus grande diversité de produits grâce au commerce constitue un gain de _____.","a":"variété","e":"Les gains de variété sont un des bénéfices du commerce soulignés par Krugman."},{"t":"Selon la théorie HOS, un pays exporte le bien qui utilise intensément son facteur le plus _____.","a":"abondant","e":"Le facteur abondant étant relativement moins cher, le pays se spécialise dans le bien qui l'utilise intensément."},{"t":"Le principe de l'OMC étendant à tous les membres tout avantage accordé à l'un d'eux est la clause de la nation la plus _____.","a":"favorisée","e":"Cette clause garantit la non-discrimination entre partenaires commerciaux."},{"t":"Un droit de douane proportionnel à la valeur du bien importé est dit _____.","a":"ad valorem","alt":["ad-valorem"],"e":"Le droit ad valorem (en %) s'oppose au droit spécifique, montant fixe par unité."},{"t":"Une prise de participation durable d'une firme dans une entreprise étrangère qui reproduit son activité est un IDE _____.","a":"horizontal","e":"L'IDE horizontal vise le marché local ; l'IDE vertical fragmente la production."},{"t":"List justifie une protection temporaire des industries naissantes : on parle de protectionnisme _____.","a":"éducateur","e":"Le protectionnisme éducateur protège l'industrie le temps qu'elle devienne compétitive, puis est levé."},{"t":"Les ventes croisées de produits proches de qualité comparable, qui répondent à des goûts différents, relèvent de la différenciation _____.","a":"horizontale","e":"La différenciation horizontale distingue des variétés de qualité voisine ; la différenciation verticale hiérarchise par la qualité."}]});
  add("eco-chomage", {"qcm":[{"q":"Le « NAIRU » désigne :","o":["le taux de chômage en dessous duquel l'inflation tend à s'accélérer","le nombre total de chômeurs indemnisés par l'État","un dispositif de formation des demandeurs d'emploi","le salaire plancher fixé par les conventions collectives"],"c":0,"e":"Le NAIRU (Non-Accelerating Inflation Rate of Unemployment) est le taux de chômage compatible avec une inflation stable ; en dessous, l'inflation accélère."},{"q":"L'« hystérèse » du chômage désigne le mécanisme par lequel :","o":["le chômage baisse spontanément avec le temps","un chômage conjoncturel élevé finit par s'enraciner et devenir structurel","les salaires s'ajustent instantanément à l'équilibre","le chômage frictionnel disparaît en période de croissance"],"c":1,"e":"L'hystérèse traduit la persistance : un choc conjoncturel prolongé dégrade l'employabilité (perte de qualifications, découragement) et transforme le chômage en chômage structurel."},{"q":"La théorie « insider / outsider » explique une rigidité des salaires par :","o":["la faiblesse de la demande globale adressée aux entreprises","l'absence totale de syndicats dans l'entreprise","le pouvoir de négociation des salariés en place qui protègent leur emploi au détriment des chômeurs","la flexibilité parfaite du marché du travail"],"c":2,"e":"Les « insiders » (salariés en poste) disposent d'un pouvoir de négociation lié aux coûts de rotation ; ils obtiennent des salaires élevés qui freinent l'embauche des « outsiders » (chômeurs)."},{"q":"Le chômage dit « classique » provient principalement :","o":["d'une insuffisance de la demande adressée aux entreprises","d'un coût du travail trop élevé qui réduit la demande de travail des entreprises","des délais de recherche d'un premier emploi","d'un excès d'investissement public"],"c":1,"e":"Le chômage classique résulte d'un coût du travail (salaires + cotisations) supérieur à la productivité, ce qui dissuade les entreprises d'embaucher."},{"q":"Le salaire minimum peut, selon l'analyse néoclassique, créer du chômage parce qu'il :","o":["augmente la demande de travail des entreprises","est fixé au-dessus du salaire d'équilibre du marché","réduit le coût du travail pour l'employeur","supprime toute asymétrie d'information"],"c":1,"e":"Fixé au-dessus du prix d'équilibre, le salaire minimum crée un excès d'offre de travail : certains actifs ne trouvent pas preneur, d'où du chômage."},{"q":"Les allègements de cotisations sociales sur les bas salaires visent d'abord à :","o":["augmenter le pouvoir d'achat immédiat des cadres","réduire le coût du travail pour favoriser l'embauche des moins qualifiés","financer les retraites par répartition","relancer la demande globale par la consommation"],"c":1,"e":"En diminuant le coût du travail au voisinage du SMIC, ces allègements cherchent à stimuler la demande de travail peu qualifié, le plus exposé au chômage classique."},{"q":"La théorie de l'appariement (matching, Mortensen-Pissarides) met l'accent sur :","o":["l'insuffisance générale de la demande","le temps et l'information nécessaires pour qu'offre et demande de travail se rencontrent","la suppression du salaire minimum","le rôle exclusif de la politique monétaire"],"c":1,"e":"Le marché du travail n'est pas instantané : la rencontre entre postes vacants et chômeurs prend du temps et de l'information imparfaite, ce qui génère du chômage frictionnel."},{"q":"Une politique « passive » de l'emploi consiste essentiellement à :","o":["former et accompagner les chômeurs vers l'emploi","indemniser les chômeurs pour maintenir leur revenu","subventionner directement les embauches","créer des emplois aidés dans le secteur public"],"c":1,"e":"Les politiques passives (indemnisation chômage) garantissent un revenu de remplacement sans agir directement sur le retour à l'emploi, contrairement aux politiques actives."},{"q":"Le « taux d'activité » se calcule en rapportant :","o":["les chômeurs à la population active","les actifs (occupés + chômeurs) à la population en âge de travailler","les personnes en emploi à la population totale","les inactifs à la population active"],"c":1,"e":"Taux d'activité = population active (emploi + chômage) / population en âge de travailler. Il mesure la part de la population qui se présente sur le marché du travail."},{"q":"Le salaire d'efficience désigne un salaire :","o":["fixé volontairement au-dessus de l'équilibre pour accroître la productivité et la motivation","égal au strict minimum légal","indexé uniquement sur l'inflation","calculé sur le seul temps de présence"],"c":0,"e":"Verser un salaire supérieur à l'équilibre réduit le turn-over, attire les meilleurs et incite à l'effort ; mais ce surcoût peut limiter l'embauche et créer du chômage."},{"q":"La flexibilité « externe quantitative » du marché du travail correspond surtout :","o":["à la modulation du temps de travail des salariés en poste","au recours aux contrats courts (CDD, intérim) pour ajuster les effectifs","à la formation continue des salariés","à la polyvalence des tâches au sein de l'entreprise"],"c":1,"e":"La flexibilité externe quantitative ajuste le volume d'emploi via des contrats temporaires que l'entreprise peut faire varier selon l'activité."},{"q":"Le « halo autour du chômage » regroupe des personnes qui :","o":["sont comptées comme chômeurs au sens du BIT","occupent un emploi à temps plein","souhaitent travailler mais ne remplissent pas tous les critères BIT (disponibilité ou recherche active)","sont retraitées et ne cherchent pas d'emploi"],"c":2,"e":"Le halo désigne des inactifs « au sens du BIT » proches du chômage : ils veulent un emploi mais ne sont pas disponibles immédiatement ou ne recherchent pas activement."},{"q":"Une asymétrie d'information sur le marché du travail peut générer du chômage car :","o":["l'employeur connaît parfaitement la productivité de chaque candidat","l'employeur ne peut pas observer directement l'effort ou la qualité réelle du salarié","les salaires sont parfaitement flexibles","l'État fixe tous les salaires"],"c":1,"e":"L'employeur n'observe pas la productivité réelle d'un candidat : pour limiter ce risque il peut verser un salaire d'efficience ou trier les candidats, ce qui pèse sur l'emploi."},{"q":"La flexisécurité (modèle danois) cherche à concilier :","o":["bas salaires et forte protection de l'emploi","facilité de licenciement et forte sécurisation du revenu et des parcours","suppression de l'indemnisation et hausse du SMIC","rigidité des contrats et faible formation"],"c":1,"e":"La flexisécurité associe une grande flexibilité d'embauche/licenciement, une indemnisation chômage généreuse et un accompagnement actif (formation) entre deux emplois."},{"q":"Le chômage frictionnel se distingue du chômage structurel en ce qu'il :","o":["est durable et lié à une inadéquation profonde des qualifications","est de courte durée et correspond au temps normal de transition entre deux emplois","provient d'une insuffisance de la demande globale","résulte uniquement du niveau du SMIC"],"c":1,"e":"Le chômage frictionnel est transitoire (recherche d'un emploi adapté), alors que le chômage structurel est durable et tient aux caractéristiques du marché (qualifications, institutions)."},{"q":"Une « politique active » de l'emploi privilégie :","o":["le versement d'allocations chômage","la formation, l'accompagnement et les aides à l'embauche pour ramener vers l'emploi","la baisse des taux d'intérêt par la banque centrale","la dévaluation de la monnaie"],"c":1,"e":"Les politiques actives agissent directement sur le retour à l'emploi (formation, conseil, subventions à l'embauche), ciblant surtout le chômage structurel."},{"q":"La « courbe de Beveridge » relie :","o":["le taux de chômage et le taux d'inflation","le taux de chômage et le taux d'emplois vacants","les salaires et la productivité","le déficit public et la dette"],"c":1,"e":"La courbe de Beveridge représente la relation négative entre taux de chômage et taux d'emplois vacants ; un déplacement vers l'extérieur signale un mauvais appariement."},{"q":"Réduire le coût du travail des moins qualifiés relève d'une logique de lutte contre le chômage :","o":["conjoncturel par soutien de la demande","classique par baisse du coût du travail","frictionnel par amélioration de l'appariement","saisonnier"],"c":1,"e":"Agir sur le coût du travail (allègements de cotisations) vise le chômage classique, dû à un coût du travail supérieur à la productivité des moins qualifiés."},{"q":"Le « sous-emploi » au sens du BIT recouvre les personnes qui :","o":["sont sans aucun emploi et cherchent activement","travaillent à temps partiel mais souhaitent et sont disponibles pour travailler davantage","sont en formation à plein temps","ont cessé toute recherche d'emploi"],"c":1,"e":"Le sous-emploi vise notamment les actifs à temps partiel subi qui veulent travailler plus et sont disponibles pour le faire ; ils sont pourtant en emploi."},{"q":"La rigidité à la baisse des salaires nominaux peut entretenir le chômage car :","o":["elle accélère l'ajustement vers l'équilibre","elle empêche les salaires de baisser en cas de chute de la demande de travail","elle supprime toute asymétrie d'information","elle réduit le coût du travail"],"c":1,"e":"Si les salaires ne peuvent pas baisser (contrats, normes sociales, salaire minimum), le marché du travail ne se rééquilibre pas par les prix et l'excès d'offre persiste."},{"q":"La protection de l'emploi (réglementation des licenciements) a sur le chômage structurel un effet :","o":["nécessairement positif sur l'emploi","nécessairement nul","ambigu : elle protège les emplois existants mais peut freiner les embauches","limité au seul secteur public"],"c":2,"e":"Une protection forte réduit les licenciements mais renchérit l'embauche (risque de ne pouvoir se séparer du salarié), d'où un effet net incertain sur le chômage."},{"q":"Le chômage « saisonnier » se caractérise par :","o":["sa liaison aux variations régulières d'activité au cours de l'année","sa durée très longue","son origine purement institutionnelle","son lien avec le progrès technique"],"c":0,"e":"Le chômage saisonnier suit les rythmes prévisibles de certaines activités (tourisme, agriculture, BTP) selon les saisons ; il est récurrent et de courte durée."},{"q":"Les politiques de soutien de la demande globale ciblent surtout le chômage :","o":["frictionnel","structurel","conjoncturel","saisonnier"],"c":2,"e":"D'inspiration keynésienne, le soutien de la demande (relance budgétaire, baisse des taux) vise le chômage conjoncturel dû à une demande insuffisante."},{"q":"Le « taux de chômage de longue durée » mesure la part des chômeurs :","o":["inscrits depuis moins d'un mois","au chômage depuis au moins un an","qui occupent un emploi à temps partiel","en formation"],"c":1,"e":"Le chômage de longue durée (≥ 1 an) signale souvent une dimension structurelle (perte d'employabilité, hystérèse) et appelle des politiques actives ciblées."},{"q":"Selon l'analyse keynésienne, le chômage involontaire s'explique par :","o":["un salaire réel trop bas","une demande effective insuffisante pour assurer le plein emploi","un excès de flexibilité des salaires","l'absence de salaire minimum"],"c":1,"e":"Pour Keynes, le niveau d'emploi dépend de la demande effective anticipée par les entreprises ; si elle est trop faible, un chômage involontaire apparaît, que la baisse des salaires ne résorbe pas."},{"q":"Un défaut d'appariement (mismatch) géographique sur le marché du travail signifie que :","o":["les emplois vacants et les chômeurs ne sont pas situés dans les mêmes territoires","tous les chômeurs refusent de travailler","les salaires sont parfaitement flexibles","la demande globale est insuffisante"],"c":0,"e":"Le mismatch géographique : des postes vacants coexistent avec des chômeurs, mais dans des zones différentes, freinant l'appariement et nourrissant le chômage structurel."},{"q":"La formation professionnelle des demandeurs d'emploi agit principalement contre le chômage :","o":["conjoncturel","d'inadéquation (structurel)","saisonnier","frictionnel de très court terme"],"c":1,"e":"La formation réduit l'écart entre les qualifications offertes par les chômeurs et celles demandées par les entreprises, ciblant le chômage structurel d'inadéquation."},{"q":"Le « chômage naturel » (Friedman) correspond :","o":["au chômage qui disparaît à long terme","au taux de chômage d'équilibre compatible avec une inflation stable","au seul chômage conjoncturel","au chômage volontaire uniquement"],"c":1,"e":"Le taux de chômage naturel agrège chômage frictionnel et structurel ; c'est le niveau vers lequel l'économie tend à long terme, indépendant de la politique de relance."},{"q":"Une subvention à l'embauche (emploi aidé) est un instrument de politique :","o":["passive de l'emploi","active de l'emploi","monétaire","commerciale"],"c":1,"e":"Subventionner l'embauche est une politique active : elle agit directement sur la demande de travail des entreprises pour ramener des publics éloignés vers l'emploi."},{"q":"Le découragement des chômeurs (qui cessent de chercher) tend à :","o":["augmenter le taux de chômage mesuré","faire baisser le taux de chômage mesuré tout en gonflant le halo du chômage","n'avoir aucun effet sur les statistiques","augmenter le taux d'emploi"],"c":1,"e":"Un chômeur découragé sort des statistiques du chômage (il ne recherche plus), ce qui réduit artificiellement le taux de chômage et augmente le halo et l'inactivité."}],"vf":[{"s":"Le NAIRU est le taux de chômage en dessous duquel l'inflation tend à accélérer.","a":true,"e":"C'est précisément la définition du NAIRU (taux de chômage n'accélérant pas l'inflation)."},{"s":"L'hystérèse signifie qu'un chômage conjoncturel prolongé peut se transformer en chômage structurel.","a":true,"e":"La persistance du chômage dégrade l'employabilité (perte de compétences, découragement) et l'enracine durablement."},{"s":"Selon la théorie insider/outsider, ce sont les chômeurs qui fixent les salaires dans l'entreprise.","a":false,"e":"Ce sont les insiders (salariés en place) qui pèsent sur la négociation salariale, au détriment des outsiders (chômeurs)."},{"s":"Le chômage classique s'explique par un coût du travail jugé trop élevé au regard de la productivité.","a":true,"e":"Le chômage classique vient d'un coût du travail supérieur à la productivité, qui décourage l'embauche."},{"s":"Le salaire d'efficience est toujours inférieur au salaire d'équilibre du marché.","a":false,"e":"Au contraire, le salaire d'efficience est fixé au-dessus de l'équilibre pour motiver et fidéliser, ce qui peut créer du chômage."},{"s":"Une politique passive de l'emploi vise surtout à indemniser les chômeurs.","a":true,"e":"Les politiques passives assurent un revenu de remplacement (indemnisation), sans action directe sur le retour à l'emploi."},{"s":"Le taux d'activité rapporte les actifs à la population en âge de travailler.","a":true,"e":"Taux d'activité = (emploi + chômage) / population en âge de travailler."},{"s":"Les allègements de cotisations sur les bas salaires augmentent le coût du travail des moins qualifiés.","a":false,"e":"Ils réduisent le coût du travail des bas salaires pour favoriser l'embauche des moins qualifiés."},{"s":"La flexisécurité combine une forte facilité de licenciement et une sécurisation généreuse des revenus et des parcours.","a":true,"e":"Modèle danois : flexibilité du marché + indemnisation élevée + accompagnement actif (formation)."},{"s":"Le découragement d'un chômeur qui cesse sa recherche fait mécaniquement baisser le taux de chômage mesuré.","a":true,"e":"Sortant des critères BIT (recherche active), il bascule dans l'inactivité (halo), ce qui réduit le taux de chômage affiché."},{"s":"Le sous-emploi inclut des personnes en emploi à temps partiel souhaitant travailler davantage.","a":true,"e":"Le sous-emploi vise notamment le temps partiel subi : des actifs en emploi qui veulent et peuvent travailler plus."},{"s":"Pour Keynes, la seule baisse des salaires suffit toujours à résorber le chômage involontaire.","a":false,"e":"Keynes conteste cela : le chômage involontaire vient d'une demande effective insuffisante, que la baisse des salaires ne corrige pas nécessairement."},{"s":"La protection de l'emploi a un effet univoque et toujours positif sur l'emploi.","a":false,"e":"Son effet est ambigu : elle protège les emplois existants mais peut freiner les embauches en renchérissant la séparation."},{"s":"La courbe de Beveridge décrit une relation négative entre taux de chômage et taux d'emplois vacants.","a":true,"e":"Plus le chômage est faible, plus les emplois vacants sont nombreux ; un déplacement de la courbe signale un défaut d'appariement."}],"trous":[{"t":"Le taux de chômage compatible avec une inflation stable, en dessous duquel l'inflation accélère, est le _____ (sigle).","a":"NAIRU","alt":["Nairu"],"e":"Non-Accelerating Inflation Rate of Unemployment : taux de chômage d'équilibre n'accélérant pas l'inflation."},{"t":"Le mécanisme par lequel un chômage conjoncturel élevé et durable finit par devenir structurel est l'_____.","a":"hystérèse","alt":["hysterese"],"e":"L'hystérèse traduit la persistance du chômage qui s'enracine via la perte d'employabilité."},{"t":"Le chômage lié à un coût du travail supérieur à la productivité est le chômage _____.","a":"classique","e":"Le chômage classique provient d'un coût du travail trop élevé qui décourage l'embauche."},{"t":"Un salaire fixé au-dessus de l'équilibre pour accroître la motivation et la productivité est un salaire d'_____.","a":"efficience","e":"Le salaire d'efficience fidélise et motive, mais son surcoût peut limiter l'embauche."},{"t":"La théorie qui oppose les salariés en place aux chômeurs dans la formation des salaires est la théorie _____ / outsider.","a":"insider","e":"Les insiders protègent leur emploi et leurs salaires au détriment des outsiders (chômeurs)."},{"t":"Le taux de chômage d'équilibre de long terme, somme du chômage frictionnel et structurel, est le chômage _____.","a":"naturel","e":"Le chômage naturel (Friedman) est indépendant des politiques de relance et défini par les caractéristiques du marché."},{"t":"La part des actifs (emploi + chômage) dans la population en âge de travailler est le taux d'_____.","a":"activité","alt":["activite"],"e":"Le taux d'activité mesure la présence sur le marché du travail, contrairement au taux d'emploi."},{"t":"Les politiques qui indemnisent les chômeurs sans agir directement sur le retour à l'emploi sont dites _____.","a":"passives","e":"Les politiques passives garantissent un revenu de remplacement, par opposition aux politiques actives."},{"t":"Les politiques de formation et d'accompagnement vers l'emploi sont des politiques _____.","a":"actives","e":"Les politiques actives agissent directement sur le retour à l'emploi, surtout contre le chômage structurel."},{"t":"La réduction du coût du travail via la baisse des _____ sociales vise à favoriser l'embauche des bas salaires.","a":"cotisations","e":"Les allègements de cotisations diminuent le coût du travail des moins qualifiés, ciblant le chômage classique."},{"t":"La mise en correspondance, parfois imparfaite, entre postes vacants et chômeurs est le processus d'_____.","a":"appariement","e":"L'appariement (matching) prend du temps et de l'information, source de chômage frictionnel."},{"t":"Les inactifs proches du chômage qui veulent travailler sans remplir tous les critères BIT forment le _____ du chômage.","a":"halo","e":"Le halo regroupe les personnes souhaitant un emploi mais non disponibles ou ne recherchant pas activement."},{"t":"Le recours aux CDD et à l'intérim pour ajuster les effectifs relève de la _____ du marché du travail.","a":"flexibilité","alt":["flexibilite"],"e":"La flexibilité externe quantitative ajuste le volume d'emploi via les contrats courts."},{"t":"Le modèle danois associant facilité de licenciement, indemnisation généreuse et formation est la _____.","a":"flexisécurité","alt":["flexisecurite"],"e":"La flexisécurité concilie flexibilité du marché et sécurisation des revenus et des parcours."},{"t":"Les actifs à temps partiel subi qui souhaitent travailler davantage relèvent du _____.","a":"sous-emploi","alt":["sous emploi","sousemploi"],"e":"Le sous-emploi concerne des personnes en emploi voulant et pouvant travailler plus."}]});
  add("eco-crises", {"qcm":[{"q":"La « sélection adverse » sur le marché du crédit désigne le fait que :","o":["les emprunteurs les plus risqués sont les plus enclins à accepter un taux d'intérêt élevé","la banque sélectionne toujours les meilleurs dossiers grâce à une information parfaite","les déposants retirent leurs fonds en cas de rumeur","l'État garantit les dépôts pour rassurer les épargnants"],"c":0,"e":"La sélection adverse (Akerlof) découle d'une asymétrie d'information ex ante : à taux élevé, seuls les emprunteurs les plus risqués restent, dégradant la qualité moyenne des emprunteurs."},{"q":"L'asymétrie d'information sur les marchés financiers signifie que :","o":["tous les agents disposent de la même information au même moment","une partie à la transaction détient plus d'informations que l'autre","les prix reflètent parfaitement toute l'information disponible","l'information circule gratuitement et instantanément"],"c":1,"e":"Une asymétrie d'information existe quand l'un des contractants (ex. l'emprunteur) en sait plus que l'autre (le prêteur), source de sélection adverse et d'aléa moral."},{"q":"La « déflation par la dette » décrite par Irving Fisher désigne :","o":["une hausse des prix qui allège mécaniquement les dettes","un cercle vicieux où la baisse des prix alourdit le poids réel des dettes","la création monétaire massive par la banque centrale","l'annulation pure et simple des dettes publiques"],"c":1,"e":"Pour Fisher (1933), le surendettement pousse à vendre des actifs, ce qui fait baisser les prix ; la dette réelle augmente, aggravant l'insolvabilité dans une spirale dépressive."},{"q":"Les crédits « subprimes » à l'origine de la crise de 2008 étaient :","o":["des prêts immobiliers accordés à des emprunteurs peu solvables","des obligations d'État notées AAA","des crédits réservés aux entreprises les plus sûres","des dépôts garantis par l'État fédéral"],"c":0,"e":"Les subprimes sont des crédits immobiliers américains octroyés à des ménages à faible solvabilité, à taux souvent variables, dont les défauts ont déclenché la crise de 2008."},{"q":"Dans les accords de Bâle III, le ratio de fonds propres « durs » (CET1) minimal exigé est d'environ :","o":["0,5 %","2 %","4,5 %","12 %"],"c":2,"e":"Bâle III fixe un minimum de fonds propres « durs » (Common Equity Tier 1) de 4,5 % des actifs pondérés par les risques, complété de coussins supplémentaires."},{"q":"Un comportement « moutonnier » sur les marchés financiers consiste à :","o":["analyser de façon indépendante la valeur fondamentale des actifs","suivre le comportement de la majorité des opérateurs plutôt que sa propre information","diversifier systématiquement son portefeuille","exiger une prime de risque élevée pour tout placement"],"c":1,"e":"Le mimétisme (comportement moutonnier) conduit chaque opérateur à imiter les autres, ce qui peut autoalimenter une bulle puis un krach indépendamment des fondamentaux."},{"q":"Le « prêteur en dernier ressort » a pour fonction de :","o":["fixer les prix des actifs sur les marchés boursiers","fournir des liquidités aux banques en difficulté pour éviter une panique généralisée","garantir un rendement minimal aux épargnants","racheter les entreprises industrielles en faillite"],"c":1,"e":"La banque centrale, prêteur en dernier ressort, refinance les banques solvables mais illiquides afin d'enrayer une panique bancaire et le risque systémique."},{"q":"Lequel de ces dispositifs relève spécifiquement de la régulation « prudentielle » des banques ?","o":["la fixation du salaire minimum","l'exigence de ratios minimaux de fonds propres","la politique de la concurrence","la taxation des plus-values boursières"],"c":1,"e":"La régulation prudentielle (Bâle) impose des règles de solvabilité et de liquidité, dont des ratios minimaux de fonds propres, pour limiter la prise de risque des banques."},{"q":"L'effet de levier permet à un investisseur de :","o":["réduire à coup sûr le risque de son placement","accroître sa capacité d'investissement en s'endettant, amplifiant gains et pertes","éviter de payer des intérêts sur ses emprunts","garantir la liquidité de ses actifs"],"c":1,"e":"L'effet de levier consiste à financer un investissement par l'endettement : il démultiplie la rentabilité des fonds propres mais aussi les pertes en cas de retournement."},{"q":"Pourquoi un fort endettement (levier élevé) rend-il une institution financière plus fragile ?","o":["parce qu'une faible baisse de la valeur des actifs peut effacer ses fonds propres","parce qu'il réduit mécaniquement ses charges d'intérêt","parce qu'il garantit sa liquidité en toutes circonstances","parce qu'il supprime tout risque de contrepartie"],"c":0,"e":"Avec un levier élevé, les fonds propres sont faibles relativement aux actifs : une petite perte sur les actifs suffit à les anéantir, d'où l'insolvabilité et la contagion."},{"q":"Lors de la crise de 2008, les agences de notation ont été critiquées car elles :","o":["avaient sous-évalué la qualité des dettes souveraines","avaient attribué des notes trop favorables à des produits titrisés très risqués","refusaient de noter les produits structurés","étaient contrôlées directement par les banques centrales"],"c":1,"e":"Les agences ont noté AAA des produits adossés aux subprimes, entretenant une illusion de sécurité ; en situation de conflit d'intérêts, elles étaient payées par les émetteurs."},{"q":"Le « risque systémique » se manifeste lorsque :","o":["une seule banque enregistre une perte sur un placement","la défaillance d'un acteur menace de se propager à l'ensemble du système financier","les prix des actifs augmentent régulièrement","un épargnant ne peut retirer ses fonds à un guichet"],"c":1,"e":"Le risque systémique est celui d'un effondrement en chaîne : l'interconnexion des institutions transforme une défaillance locale en crise globale du système financier."},{"q":"La régulation prudentielle dite « macroprudentielle » se distingue de l'approche microprudentielle car elle vise à :","o":["surveiller individuellement chaque banque sans regarder l'ensemble","limiter le risque systémique en considérant le système financier dans sa globalité","fixer le taux directeur de la banque centrale","interdire toute forme de spéculation"],"c":1,"e":"L'approche macroprudentielle cherche à contenir le risque systémique en surveillant les interconnexions et le risque agrégé, là où le microprudentiel se concentre sur chaque établissement."},{"q":"Une « ruée bancaire » (bank run) peut être auto-réalisatrice parce que :","o":["les banques détiennent l'intégralité des dépôts en réserve","la crainte d'une faillite pousse à des retraits massifs qui la provoquent effectivement","les dépôts sont toujours garantis à 100 % par l'État","les banques ne prêtent jamais les dépôts reçus"],"c":1,"e":"Comme la banque ne conserve qu'une fraction des dépôts (réserves fractionnaires), la peur d'une faillite déclenche des retraits massifs qui rendent la faillite réelle : prophétie auto-réalisatrice."},{"q":"La titrisation a contribué à diffuser la crise de 2008 à l'échelle mondiale en :","o":["concentrant tous les risques dans une seule banque","disséminant les créances risquées dans des titres détenus par de nombreux investisseurs","supprimant l'asymétrie d'information entre acteurs","empêchant toute revente des crédits"],"c":1,"e":"En transformant des crédits subprimes en titres revendus dans le monde entier, la titrisation a disséminé le risque, opacifié sa localisation et propagé la crise au-delà des États-Unis."},{"q":"Pour Hyman Minsky, le financement « Ponzi » correspond à une situation où l'emprunteur :","o":["rembourse à la fois le capital et les intérêts grâce à ses revenus","ne peut couvrir ni le capital ni les intérêts et compte sur la hausse du prix des actifs","place son épargne sans jamais s'endetter","prête à un taux supérieur à celui de la banque centrale"],"c":1,"e":"Dans le schéma de Minsky, le financement Ponzi est le plus fragile : l'emprunteur ne couvre ni capital ni intérêts et mise sur l'appréciation des actifs, rendant le système instable."},{"q":"La garantie publique des dépôts vise à prévenir les paniques bancaires mais peut :","o":["accroître l'aléa moral des banques et des déposants","supprimer tout risque systémique de façon certaine","réduire les fonds propres exigés par Bâle III","interdire la titrisation des crédits"],"c":0,"e":"En rassurant les déposants, la garantie réduit le risque de ruée, mais déresponsabilise banques et épargnants quant au risque pris : c'est une source d'aléa moral."},{"q":"La fixation d'un ratio de levier (leverage ratio) dans Bâle III a pour but de :","o":["plafonner l'endettement des banques indépendamment de la pondération des risques","supprimer les fonds propres des banques","garantir un rendement aux actionnaires","fixer le taux d'intérêt des crédits immobiliers"],"c":0,"e":"Le ratio de levier rapporte les fonds propres aux expositions totales non pondérées : il borne l'effet de levier même quand les risques sont jugés faibles par les modèles internes."},{"q":"L'expression « too big to fail » (trop grosse pour faire faillite) renvoie à l'idée que :","o":["les grandes banques ne prennent jamais de risques","l'État doit secourir certaines banques systémiques pour éviter l'effondrement, ce qui nourrit l'aléa moral","les petites banques sont les plus dangereuses","la faillite d'une grande banque n'a aucune conséquence"],"c":1,"e":"Une banque systémique sait que l'État la sauvera pour éviter la contagion : cette anticipation l'incite à prendre plus de risques, illustrant l'aléa moral lié au sauvetage."},{"q":"Lequel de ces enchaînements illustre le mieux un canal de transmission de la crise financière à l'économie réelle ?","o":["hausse des dépôts, baisse du chômage, hausse de l'investissement","krach boursier, restriction du crédit, baisse de l'investissement et de l'emploi","baisse des taux, hausse de la consommation, plein-emploi","hausse des fonds propres, baisse des prix, hausse des salaires"],"c":1,"e":"Une crise financière se transmet à l'économie réelle par le rationnement du crédit (credit crunch) et l'effet de richesse négatif, freinant investissement, consommation et emploi."},{"q":"La rationalité « mimétique » d'André Orléan suggère que sur les marchés, il est individuellement rationnel de :","o":["ignorer totalement l'opinion des autres opérateurs","imiter le marché car le prix dépend de l'opinion majoritaire, non des seuls fondamentaux","ne jamais acheter d'actifs financiers","fixer ses décisions sur la seule valeur comptable"],"c":1,"e":"Pour Orléan, comme le prix résulte de l'opinion collective, suivre la majorité peut être rationnel pour l'individu, ce qui autoalimente les bulles : la « convention » prime sur les fondamentaux."},{"q":"Un « credit crunch » (resserrement du crédit) désigne :","o":["une augmentation des dépôts bancaires","une contraction brutale de l'offre de crédit par les banques","une baisse des taux d'intérêt décidée par la banque centrale","une hausse de la consommation des ménages"],"c":1,"e":"Le credit crunch est une réduction soudaine de l'offre de crédit : fragilisées, les banques prêtent moins, ce qui étrangle le financement des entreprises et des ménages."},{"q":"Pourquoi la baisse de la valeur des actifs mis en garantie (collatéral) amplifie-t-elle une crise ?","o":["elle augmente la capacité d'emprunt des agents","elle oblige à vendre des actifs pour reconstituer les garanties, faisant encore baisser les prix","elle réduit le risque systémique","elle accroît les fonds propres des banques"],"c":1,"e":"La chute du collatéral déclenche des appels de marge et des ventes forcées (fire sales) qui dépriment davantage les prix, dans une spirale de désendettement (deleveraging)."},{"q":"Les « stress tests » imposés aux banques par les régulateurs consistent à :","o":["mesurer la satisfaction des clients","simuler des scénarios de crise pour évaluer la résistance des banques","fixer le montant des dividendes versés","noter la qualité des produits titrisés"],"c":1,"e":"Les stress tests évaluent la capacité d'une banque à absorber des chocs (récession, krach) sans devenir insolvable : ils relèvent de la supervision prudentielle post-2008."},{"q":"La séparation des activités de banque de dépôt et de banque d'investissement vise principalement à :","o":["augmenter les profits des banques","protéger les dépôts des particuliers des risques de la spéculation de marché","supprimer les fonds propres réglementaires","interdire les crédits immobiliers"],"c":1,"e":"Cette séparation (héritière du Glass-Steagall Act) cherche à éviter que les pertes sur les activités de marché ne mettent en danger les dépôts et le système de paiement."},{"q":"Le « cycle financier » de Minsky décrit une succession où :","o":["la stabilité durable supprime toute prise de risque","les périodes de calme encouragent l'endettement et préparent l'instabilité future","les crises surviennent sans aucun lien avec l'endettement","la spéculation disparaît dès qu'apparaît une bulle"],"c":1,"e":"Selon le « paradoxe de la tranquillité » de Minsky, la stabilité incite à un endettement croissant et à des montages plus fragiles, semant les germes de la crise suivante."},{"q":"Une bulle spéculative se nourrit d'anticipations « extrapolatives » lorsque les agents :","o":["anticipent un retour rapide des prix à leur valeur fondamentale","prolongent dans le futur la hausse passée des prix, alimentant encore la hausse","ignorent totalement l'évolution récente des cours","achètent uniquement en fonction des dividendes versés"],"c":1,"e":"Des anticipations extrapolatives (auto-entretenues) poussent à acheter parce que les prix montent, ce qui les fait encore monter : c'est le moteur d'une bulle, déconnectée des fondamentaux."},{"q":"La supervision bancaire confiée à la BCE depuis 2014 dans la zone euro porte le nom de :","o":["politique budgétaire commune","mécanisme de surveillance unique (MSU)","Pacte de stabilité et de croissance","marché unique des capitaux"],"c":1,"e":"Le Mécanisme de surveillance unique (MSU), pilier de l'union bancaire, confie à la BCE la supervision directe des principales banques de la zone euro depuis novembre 2014."},{"q":"Un « coussin contracyclique » de fonds propres (Bâle III) impose aux banques de :","o":["réduire leurs fonds propres en période d'expansion du crédit","constituer des réserves supplémentaires quand le crédit croît trop vite, mobilisables en crise","distribuer davantage de dividendes en haut de cycle","cesser tout crédit en période de récession"],"c":1,"e":"Le coussin contracyclique fait accumuler des fonds propres en phase d'expansion excessive du crédit ; ils sont relâchés en crise pour soutenir le crédit : un outil macroprudentiel."},{"q":"Le rôle des marchés financiers dans le financement de l'économie consiste à :","o":["empêcher la rencontre entre épargnants et investisseurs","mettre en relation agents à capacité et agents à besoin de financement et fixer le prix des actifs","garantir l'absence totale de risque pour les épargnants","fixer les salaires dans l'économie réelle"],"c":1,"e":"Les marchés financiers assurent l'allocation de l'épargne : ils relient capacités et besoins de financement, fixent le prix des actifs et permettent la liquidité, mais peuvent aussi être instables."}],"vf":[{"s":"La sélection adverse résulte d'une asymétrie d'information avant la conclusion du contrat.","a":true,"e":"La sélection adverse est un problème ex ante : le prêteur ne distingue pas les bons des mauvais emprunteurs avant de contracter."},{"s":"Pour Irving Fisher, une baisse générale des prix réduit le poids réel de la dette des agents.","a":false,"e":"C'est l'inverse : la déflation accroît le poids réel des dettes (la valeur de la dette est figée alors que prix et revenus baissent), aggravant la crise."},{"s":"L'effet de levier amplifie aussi bien les gains que les pertes d'un investisseur endetté.","a":true,"e":"En finançant l'investissement par la dette, le levier démultiplie la rentabilité des fonds propres dans les deux sens."},{"s":"Les agences de notation rémunérées par les émetteurs de titres se trouvent en situation de conflit d'intérêts.","a":true,"e":"Le modèle « émetteur-payeur » crée un conflit d'intérêts : noter sévèrement un client peut le faire fuir, ce qui a favorisé des notes trop généreuses avant 2008."},{"s":"Les crédits subprimes étaient accordés à des emprunteurs très solvables et peu risqués.","a":false,"e":"Au contraire, les subprimes visaient des ménages à faible solvabilité, d'où le taux de défaut élevé à l'origine de la crise de 2008."},{"s":"Le mécanisme de garantie des dépôts peut engendrer de l'aléa moral.","a":true,"e":"En supprimant la crainte de perdre ses dépôts, la garantie déresponsabilise déposants et banques quant au risque, ce qui relève de l'aléa moral."},{"s":"Le risque systémique provient de l'interconnexion des institutions financières.","a":true,"e":"L'interdépendance (créances croisées, marchés communs) transforme une défaillance locale en crise générale : c'est le coeur du risque systémique."},{"s":"La titrisation a permis de concentrer tout le risque des subprimes dans une seule banque.","a":false,"e":"La titrisation a au contraire disséminé le risque dans de nombreux titres détenus mondialement, opacifiant sa localisation et propageant la crise."},{"s":"Le « paradoxe de la tranquillité » de Minsky veut que la stabilité prolongée engendre la prise de risque.","a":true,"e":"Pour Minsky, le calme incite à s'endetter davantage et à adopter des montages fragiles, préparant la crise suivante."},{"s":"Les accords de Bâle relèvent de la régulation prudentielle du système bancaire.","a":true,"e":"Bâle I, II et III fixent des normes de solvabilité et de liquidité (ratios de fonds propres) : c'est le cadre de la régulation prudentielle internationale."},{"s":"Le credit crunch correspond à une expansion de l'offre de crédit par les banques.","a":false,"e":"Le credit crunch est au contraire un resserrement brutal du crédit, qui freine investissement et consommation."},{"s":"Le statut de banque « too big to fail » réduit l'aléa moral des grandes banques.","a":false,"e":"Il l'accroît : anticipant un sauvetage public, ces banques sont incitées à prendre davantage de risques."},{"s":"Les ventes forcées d'actifs (fire sales) en période de crise font baisser leur prix et aggravent la situation.","a":true,"e":"Le désendettement précipité oblige à vendre à bas prix, ce qui déprime encore les cours et alimente la spirale baissière."},{"s":"Un ratio de levier réglementaire borne l'endettement d'une banque indépendamment de la pondération des risques.","a":true,"e":"Le leverage ratio rapporte fonds propres et expositions totales non pondérées, encadrant le levier même quand les modèles jugent les risques faibles."},{"s":"Le coussin contracyclique de Bâle III demande aux banques de réduire leurs fonds propres quand le crédit s'emballe.","a":false,"e":"C'est l'inverse : il impose d'accumuler des fonds propres en phase d'expansion excessive, réserves relâchées ensuite en crise."}],"trous":[{"t":"Le problème d'information ex ante qui amène les emprunteurs les plus risqués à rester sur le marché du crédit est la sélection _____.","a":"adverse","e":"La sélection adverse découle de l'asymétrie d'information avant la signature du contrat."},{"t":"Le cercle vicieux décrit par Fisher, où la baisse des prix alourdit le poids réel des dettes, est la _____ par la dette.","a":"déflation","alt":["deflation"],"e":"La déflation par la dette (Fisher, 1933) aggrave l'insolvabilité dans une spirale dépressive."},{"t":"Les crédits immobiliers américains accordés à des ménages peu solvables, à l'origine de la crise de 2008, sont les _____.","a":"subprimes","alt":["subprime"],"e":"Les subprimes sont des prêts à risque dont les défauts ont déclenché la crise de 2008."},{"t":"S'endetter pour investir davantage, ce qui amplifie gains et pertes, c'est utiliser l'effet de _____.","a":"levier","e":"L'effet de levier démultiplie la rentabilité des fonds propres mais aussi les pertes."},{"t":"Les sociétés qui évaluent la qualité des emprunteurs et des titres, critiquées pour leurs notes trop favorables en 2008, sont les agences de _____.","a":"notation","e":"Les agences de notation ont noté AAA des produits subprimes, entretenant une illusion de sécurité."},{"t":"Le risque qu'une défaillance se propage à l'ensemble du système financier est le risque _____.","a":"systémique","e":"Le risque systémique tient à l'interconnexion des institutions financières."},{"t":"Les accords internationaux de _____ III fixent des ratios minimaux de fonds propres aux banques.","a":"Bâle","alt":["bale","bâle"],"e":"Bâle III renforce les exigences de solvabilité et de liquidité après la crise de 2008."},{"t":"Le contraire d'une approche par banque, qui surveille le risque du système financier dans sa globalité, est la régulation _____.","a":"macroprudentielle","e":"L'approche macroprudentielle vise à contenir le risque systémique au niveau agrégé."},{"t":"La situation où une banque jugée trop importante sera secourue par l'État, ce qui nourrit l'aléa moral, est résumée par l'expression « too big to _____ ».","a":"fail","e":"« Too big to fail » : l'anticipation d'un sauvetage incite à la prise de risque."},{"t":"La technique qui transforme des crédits en titres revendus à de nombreux investisseurs et a diffusé la crise de 2008 est la _____.","a":"titrisation","e":"La titrisation a disséminé mondialement le risque des subprimes."},{"t":"Le resserrement brutal de l'offre de crédit par les banques, qui freine l'activité, est le credit _____.","a":"crunch","e":"Le credit crunch transmet la crise financière à l'économie réelle."},{"t":"L'actif remis en garantie d'un prêt, dont la chute déclenche des ventes forcées, est le _____.","a":"collatéral","alt":["collateral"],"e":"La baisse du collatéral provoque des appels de marge et un désendettement amplificateur."},{"t":"Le comportement consistant à imiter la majorité des opérateurs plutôt que sa propre analyse est dit _____.","a":"mimétique","alt":["moutonnier","mimetique"],"e":"Le mimétisme peut autoalimenter une bulle puis un krach, indépendamment des fondamentaux."},{"t":"Les exercices simulant des scénarios de crise pour évaluer la solidité des banques sont des stress _____.","a":"tests","alt":["test"],"e":"Les stress tests relèvent de la supervision prudentielle renforcée après 2008."},{"t":"La supervision des grandes banques de la zone euro confiée à la BCE depuis 2014 est le mécanisme de surveillance _____.","a":"unique","e":"Le Mécanisme de surveillance unique (MSU) est un pilier de l'union bancaire européenne."}]});
  add("eco-europe", {"qcm":[{"q":"Les taux directeurs fixés par la BCE désignent :","o":["Les taux auxquels la BCE prête aux banques commerciales et rémunère leurs dépôts","Le taux d'imposition sur les bénéfices bancaires dans la zone euro","Le taux de change fixe entre l'euro et le dollar","Le taux de croissance plafond autorisé aux États membres"],"c":0,"e":"Les taux directeurs sont les taux d'intérêt de référence par lesquels la BCE pilote le coût de la liquidité pour les banques, et donc indirectement le crédit dans l'économie."},{"q":"Quel est l'instrument principal de la politique monétaire dite « conventionnelle » ?","o":["Le rachat massif d'obligations souveraines","Le contrôle des concentrations d'entreprises","La fixation des taux directeurs","L'imposition de quotas de crédit aux banques"],"c":2,"e":"La politique monétaire conventionnelle agit en priorité par la variation des taux directeurs, qui influence le coût du crédit et la demande."},{"q":"L'indépendance de la BCE vis-à-vis des gouvernements vise principalement à :","o":["Permettre aux États de financer librement leurs déficits","Accélérer la convergence réelle des économies","Crédibiliser la lutte contre l'inflation en évitant le financement politique des dépenses","Imposer une politique budgétaire commune"],"c":2,"e":"Une banque centrale indépendante ne peut être contrainte de financer les déficits publics, ce qui renforce sa crédibilité dans la stabilité des prix."},{"q":"Une politique monétaire « expansionniste » (ou accommodante) consiste à :","o":["Relever les taux directeurs pour freiner l'inflation","Baisser les taux directeurs pour stimuler le crédit et l'activité","Réduire les dépenses publiques des États","Augmenter le tarif extérieur commun"],"c":1,"e":"Baisser les taux directeurs abaisse le coût du crédit, soutient l'investissement et la consommation : c'est une politique monétaire expansionniste."},{"q":"La cible d'inflation de la BCE, fixée à 2 % à moyen terme, se justifie surtout par :","o":["La volonté d'atteindre une inflation nulle, considérée comme idéale","Le besoin de financer la dette par l'inflation","La maximisation des recettes fiscales des États","Le souci d'écarter le risque de déflation tout en préservant le pouvoir d'achat"],"c":3,"e":"Une cible légèrement positive (2 %) offre une marge de sécurité face à la déflation, jugée plus dangereuse, tout en limitant l'érosion du pouvoir d'achat."},{"q":"Dans une union monétaire, un pays touché par un choc négatif ne peut plus recourir à la dévaluation de sa monnaie ; il peut alors tenter une « dévaluation interne », c'est-à-dire :","o":["Émettre une monnaie nationale parallèle","Dévaluer l'euro face au dollar unilatéralement","Baisser les coûts salariaux et les prix internes pour restaurer sa compétitivité","Sortir temporairement du marché unique"],"c":2,"e":"Privé de l'arme du taux de change, le pays cherche à regagner en compétitivité en comprimant salaires et prix : c'est la dévaluation interne, souvent coûteuse socialement."},{"q":"Les critères de convergence de Maastricht portent notamment sur :","o":["Le taux de chômage, le taux d'emploi et la productivité","L'inflation, les taux d'intérêt longs, le déficit et la dette publics","Le PIB par habitant et l'indice de développement humain","Le solde commercial et le taux d'épargne"],"c":1,"e":"Les critères de Maastricht encadrent l'inflation, les taux d'intérêt à long terme, la stabilité du change, le déficit (3 %) et la dette publics (60 %)."},{"q":"Une union douanière se distingue d'une simple zone de libre-échange parce qu'elle ajoute :","o":["Une monnaie unique","Un tarif extérieur commun face aux pays tiers","La libre circulation des travailleurs","Une politique budgétaire fédérale"],"c":1,"e":"La zone de libre-échange supprime les droits de douane internes ; l'union douanière y ajoute un tarif extérieur commun appliqué aux pays tiers."},{"q":"Le marché unique va plus loin que l'union douanière car il garantit aussi :","o":["Un tarif extérieur commun","La libre circulation des biens, services, capitaux et personnes","Une banque centrale indépendante","Un budget commun aux États membres"],"c":1,"e":"Le marché unique (1993) instaure les quatre libertés de circulation, au-delà de la simple suppression des droits de douane de l'union douanière."},{"q":"Le « Semestre européen » est un dispositif qui vise à :","o":["Fixer les taux directeurs deux fois par an","Coordonner et surveiller en amont les politiques budgétaires et économiques nationales","Organiser l'élection du Parlement européen","Réviser le tarif extérieur commun chaque semestre"],"c":1,"e":"Le Semestre européen est un cycle annuel de coordination où la Commission examine et oriente les projets de budget et réformes des États avant leur adoption."},{"q":"La « convergence réelle » entre pays de la zone euro désigne :","o":["Le rapprochement des niveaux de vie et de productivité entre économies","L'alignement des taux de change sur l'euro","L'unification des taux directeurs","La fusion des budgets nationaux"],"c":0,"e":"La convergence réelle est le rapprochement effectif des structures économiques et des niveaux de vie, distincte de la convergence nominale (inflation, taux)."},{"q":"Le « policy mix » optimal suppose une articulation entre :","o":["Politique de la concurrence et politique commerciale","Politique monétaire et politique budgétaire","Politique sociale et politique migratoire","Tarif extérieur commun et marché unique"],"c":1,"e":"Le policy mix est la combinaison cohérente de la politique monétaire (BCE) et des politiques budgétaires nationales pour agir sur la conjoncture."},{"q":"Un « bien public européen » se caractérise par :","o":["Un bien produit uniquement par les entreprises privées","Un bien dont les bénéfices profitent à l'ensemble des États membres et que chacun seul sous-produirait","Un bien réservé aux administrations nationales","Une aide d'État autorisée par dérogation"],"c":1,"e":"Un bien public européen (défense, recherche, transition écologique) bénéficie à tous les pays ; chacun, isolément, tend à le sous-financer, d'où l'intérêt d'une action commune."},{"q":"Lorsque la BCE relève ses taux directeurs, on attend en général :","o":["Une hausse du crédit et de l'inflation","Un ralentissement du crédit et une modération de l'inflation","Une dévaluation automatique de l'euro","Une hausse du déficit public des États"],"c":1,"e":"Des taux plus élevés renchérissent le crédit, freinent la demande et tendent à modérer l'inflation : c'est une politique restrictive."},{"q":"Pourquoi une politique monétaire unique est-elle délicate dans une zone aux économies hétérogènes ?","o":["Parce qu'un même taux directeur ne convient pas à des pays en situations conjoncturelles différentes","Parce que chaque pays fixe son propre taux directeur","Parce que la BCE doit financer les déficits","Parce que le tarif extérieur commun varie selon les pays"],"c":0,"e":"Un taux unique adapté à un pays en surchauffe peut être trop restrictif pour un pays en récession, et inversement : l'hétérogénéité limite l'efficacité d'une politique commune."},{"q":"La politique monétaire « non conventionnelle » a été mobilisée par la BCE surtout :","o":["Lorsque les taux directeurs proches de zéro ne suffisaient plus à relancer l'économie","Dès la création de l'euro en 1999","Pour fixer le tarif extérieur commun","Pour contrôler les concentrations bancaires"],"c":0,"e":"Quand les taux directeurs atteignent un plancher proche de zéro, la BCE recourt à des outils non conventionnels (achats d'actifs, QE) pour soutenir l'économie."},{"q":"Les « quatre libertés » du marché unique sont la libre circulation :","o":["Des biens, des services, des capitaux et des personnes","Des biens, des monnaies, des dettes et des impôts","Des marchandises, des armes, de l'énergie et des données","Des entreprises, des banques, des États et des régions"],"c":0,"e":"Le marché unique repose sur quatre libertés de circulation : biens, services, capitaux et personnes (travailleurs)."},{"q":"Le « taux de change » de l'euro influence l'économie de la zone car :","o":["Il fixe le niveau des taux directeurs","Un euro plus faible renchérit les exportations","Un euro plus faible favorise les exportations en les rendant moins chères","Il détermine le plafond de dette autorisé"],"c":2,"e":"Une dépréciation de l'euro abaisse le prix des produits de la zone à l'étranger et soutient les exportations ; une appréciation a l'effet inverse."},{"q":"Le Pacte de stabilité et de croissance fixe une référence de dette publique à ne pas dépasser de :","o":["3 % du PIB","90 % du PIB","60 % du PIB","100 % du PIB"],"c":2,"e":"Le PSC retient deux références : 3 % du PIB pour le déficit et 60 % du PIB pour la dette publique."},{"q":"Une critique fréquente du Pacte de stabilité et de croissance est qu'il peut :","o":["Imposer l'austérité en bas de cycle et aggraver la récession","Empêcher la BCE d'être indépendante","Interdire toute aide d'État","Supprimer le tarif extérieur commun"],"c":0,"e":"En contraignant à réduire les déficits même en récession, les règles budgétaires peuvent avoir un effet procyclique et amplifier le ralentissement."},{"q":"La coordination des politiques budgétaires nationales est jugée nécessaire dans la zone euro car :","o":["Les États partagent la même monnaie et leurs décisions ont des effets sur les voisins","Chaque État dispose de sa propre banque centrale","La politique budgétaire est devenue fédérale","Le tarif extérieur diffère d'un pays à l'autre"],"c":0,"e":"En union monétaire, les déficits ou relances d'un pays affectent les partenaires (effets de débordement), d'où la nécessité de coordonner les politiques budgétaires restées nationales."},{"q":"Dans la zone euro, la responsabilité de la politique budgétaire appartient :","o":["À la BCE","Aux États membres, dans le cadre des règles européennes","Au Parlement européen exclusivement","À la Commission seule"],"c":1,"e":"La politique budgétaire reste une compétence nationale, mais elle est encadrée par les traités et le Pacte de stabilité."},{"q":"L'assouplissement quantitatif (quantitative easing) consiste pour la BCE à :","o":["Relever fortement les taux directeurs","Acheter massivement des titres (notamment publics) pour injecter des liquidités","Réduire le tarif extérieur commun","Augmenter les réserves obligatoires des banques"],"c":1,"e":"Le QE est un achat massif d'actifs financiers par la banque centrale pour accroître la liquidité, faire baisser les taux longs et soutenir l'activité."},{"q":"L'avantage d'une monnaie unique pour les échanges intra-zone est principalement :","o":["L'augmentation des droits de douane internes","La suppression du risque de change et des coûts de conversion","La hausse des taux directeurs","La fixation d'un tarif extérieur commun"],"c":1,"e":"Avec une monnaie unique, les entreprises et ménages n'ont plus à supporter le risque de change ni les coûts de conversion entre pays de la zone."},{"q":"On parle de convergence « nominale » (par opposition à réelle) lorsque l'on rapproche :","o":["Les niveaux de vie et de productivité","L'inflation, les taux d'intérêt et les soldes publics","Les systèmes éducatifs","Les politiques migratoires"],"c":1,"e":"La convergence nominale vise à rapprocher des indicateurs monétaires et budgétaires (inflation, taux, déficit), comme l'exigeaient les critères de Maastricht."},{"q":"Un choc « symétrique » dans la zone euro est un choc qui :","o":["Touche tous les pays de la zone de façon comparable","Ne touche qu'un seul pays","Provient uniquement de la politique monétaire","Affecte seulement le tarif extérieur commun"],"c":0,"e":"Un choc symétrique frappe l'ensemble des pays de manière similaire ; la politique monétaire unique y répond plus facilement qu'à un choc asymétrique."},{"q":"Selon la théorie des zones monétaires optimales (Mundell), une union monétaire fonctionne d'autant mieux que :","o":["Les pays sont éloignés économiquement","Les facteurs de production, notamment le travail, circulent et s'ajustent facilement","Chaque pays garde sa monnaie","Les budgets restent totalement indépendants"],"c":1,"e":"Mundell souligne qu'une forte mobilité des facteurs (travail, capital) et des mécanismes d'ajustement permettent d'absorber les chocs asymétriques sans taux de change national."},{"q":"Le rôle de la politique de la concurrence dans le marché unique est de :","o":["Fixer les taux directeurs","Garantir une concurrence libre et non faussée entre entreprises","Coordonner les budgets nationaux","Définir la cible d'inflation"],"c":1,"e":"La politique de la concurrence (ententes, abus de position dominante, concentrations, aides d'État) veille au bon fonctionnement concurrentiel du marché unique."},{"q":"Une difficulté de la coordination du policy mix dans la zone euro tient au fait que :","o":["La politique monétaire est unique mais les politiques budgétaires restent décentralisées","La BCE fixe aussi les budgets nationaux","Les États fixent eux-mêmes les taux directeurs","Le marché unique impose un budget commun"],"c":0,"e":"La dissociation entre une politique monétaire centralisée (BCE) et des politiques budgétaires nationales rend leur articulation (policy mix) plus complexe à coordonner."},{"q":"Le tarif extérieur commun de l'Union européenne signifie que :","o":["Chaque État applique ses propres droits de douane aux pays tiers","Les mêmes droits de douane sont appliqués aux importations venant des pays tiers","Les échanges internes sont taxés uniformément","La TVA est identique dans tous les pays"],"c":1,"e":"Dans l'union douanière, tous les États membres appliquent un tarif douanier commun aux produits importés de pays extérieurs à l'Union."}],"vf":[{"s":"Les taux directeurs sont fixés indépendamment par chaque banque centrale nationale de la zone euro.","a":false,"e":"Faux : dans la zone euro, c'est la BCE qui fixe les taux directeurs communs ; les banques centrales nationales n'ont plus cette compétence."},{"s":"La politique monétaire conventionnelle agit principalement par la variation des taux directeurs.","a":true,"e":"Vrai : l'outil classique (conventionnel) est le pilotage des taux directeurs, qui influence le coût du crédit."},{"s":"L'assouplissement quantitatif (QE) est un instrument de politique monétaire non conventionnelle.","a":true,"e":"Vrai : le QE (achats massifs d'actifs) relève des outils non conventionnels, mobilisés quand les taux sont déjà très bas."},{"s":"La dévaluation interne consiste à abaisser salaires et prix internes pour regagner en compétitivité.","a":true,"e":"Vrai : faute de pouvoir dévaluer la monnaie en union monétaire, un pays peut comprimer ses coûts internes pour restaurer sa compétitivité."},{"s":"Le critère de Maastricht sur la dette publique fixe un plafond de référence de 90 % du PIB.","a":false,"e":"Faux : la référence est de 60 % du PIB pour la dette (et 3 % pour le déficit)."},{"s":"Une union douanière se limite à supprimer les droits de douane entre ses membres, sans tarif extérieur commun.","a":false,"e":"Faux : c'est la zone de libre-échange qui se limite à cela ; l'union douanière ajoute un tarif extérieur commun."},{"s":"Le Semestre européen organise une coordination annuelle des politiques budgétaires et économiques nationales.","a":true,"e":"Vrai : c'est un cycle annuel de surveillance et de coordination en amont des budgets et réformes des États membres."},{"s":"La convergence réelle désigne le rapprochement des niveaux de vie et de productivité entre pays.","a":true,"e":"Vrai : la convergence réelle concerne les structures économiques et les niveaux de vie, à distinguer de la convergence nominale."},{"s":"Une cible d'inflation de 2 % vise notamment à écarter le risque de déflation.","a":true,"e":"Vrai : une cible légèrement positive offre une marge de sécurité contre la déflation, jugée plus dommageable."},{"s":"Lorsqu'elle relève ses taux directeurs, la BCE mène une politique monétaire expansionniste.","a":false,"e":"Faux : relever les taux est une politique restrictive ; c'est la baisse des taux qui est expansionniste."},{"s":"Un choc symétrique touche l'ensemble des pays de la zone de manière comparable.","a":true,"e":"Vrai : à la différence du choc asymétrique, le choc symétrique frappe tous les pays de façon similaire, ce qui facilite la réponse monétaire commune."},{"s":"Le policy mix désigne l'articulation entre politique monétaire et politique budgétaire.","a":true,"e":"Vrai : le policy mix est la combinaison de ces deux politiques pour agir sur la conjoncture."},{"s":"L'indépendance de la BCE l'oblige à financer les déficits des États sur demande.","a":false,"e":"Faux : l'indépendance interdit justement le financement monétaire des déficits publics, ce qui renforce sa crédibilité anti-inflation."},{"s":"Une dépréciation de l'euro tend à favoriser les exportations de la zone.","a":true,"e":"Vrai : un euro plus faible rend les produits de la zone moins chers à l'étranger, ce qui soutient les exportations."},{"s":"Les biens publics européens, comme la défense ou la recherche, tendent à être sous-financés si chaque État agit seul.","a":true,"e":"Vrai : leurs bénéfices profitant à tous, chaque État isolé est incité à en faire peu (passager clandestin), d'où l'intérêt d'une action commune."}],"trous":[{"t":"Les taux d'intérêt de référence par lesquels la BCE pilote le coût de la liquidité sont les taux _____.","a":"directeurs","e":"Les taux directeurs sont l'instrument central de la politique monétaire conventionnelle."},{"t":"La compétitivité regagnée par la baisse des salaires et des prix internes, faute de pouvoir dévaluer la monnaie, est la dévaluation _____.","a":"interne","e":"En union monétaire, l'ajustement passe par la dévaluation interne plutôt que par le taux de change."},{"t":"Le rachat massif de titres par la banque centrale pour injecter des liquidités est l'assouplissement _____, instrument non conventionnel.","a":"quantitatif","e":"Le quantitative easing (assouplissement quantitatif) est mobilisé quand les taux sont déjà très bas."},{"t":"Le dispositif annuel de coordination en amont des budgets nationaux est le _____ européen.","a":"Semestre","alt":["semestre"],"e":"Le Semestre européen permet à la Commission d'examiner et d'orienter les projets de budget et de réformes des États."},{"t":"Le rapprochement effectif des niveaux de vie et de productivité entre pays est la convergence _____.","a":"réelle","e":"La convergence réelle se distingue de la convergence nominale (inflation, taux, déficit)."},{"t":"Le traité de _____ (1992) a fixé les critères de convergence encadrant inflation, taux, déficit et dette.","a":"Maastricht","e":"Les critères de Maastricht conditionnaient l'entrée dans la monnaie unique."},{"t":"L'union _____ ajoute à la suppression des droits de douane internes un tarif extérieur commun face aux pays tiers.","a":"douanière","e":"Elle se distingue ainsi de la simple zone de libre-échange."},{"t":"Le tarif _____ commun est appliqué de façon identique par tous les membres aux importations venant des pays tiers.","a":"extérieur","e":"C'est l'élément qui caractérise l'union douanière."},{"t":"La cible d'inflation à moyen terme de la BCE est d'environ _____ %.","a":"2","alt":["deux"],"e":"Une inflation faible mais positive (2 %) préserve le pouvoir d'achat tout en écartant la déflation."},{"t":"Un choc qui touche de façon comparable tous les pays de la zone est dit _____.","a":"symétrique","e":"Il s'oppose au choc asymétrique, qui ne frappe qu'un ou quelques pays."},{"t":"L'indépendance de la BCE interdit le financement _____ des déficits publics, ce qui renforce sa crédibilité.","a":"monétaire","e":"La BCE ne peut financer directement les États, gage de lutte crédible contre l'inflation."},{"t":"Une politique monétaire qui baisse les taux directeurs pour stimuler l'activité est dite _____.","a":"expansionniste","alt":["accommodante","expansive"],"e":"À l'inverse, relever les taux correspond à une politique restrictive."},{"t":"Un bien dont les bénéfices profitent à tous les États membres et que chacun seul sous-produirait est un bien _____ européen.","a":"public","e":"Défense, recherche ou transition écologique relèvent des biens publics européens."},{"t":"La référence de dette publique du Pacte de stabilité est fixée à _____ % du PIB.","a":"60","alt":["soixante"],"e":"Le PSC retient 3 % pour le déficit et 60 % pour la dette."},{"t":"Une dépréciation de l'_____ rend les produits de la zone moins chers à l'étranger et soutient les exportations.","a":"euro","e":"Le taux de change de la monnaie unique influence la compétitivité-prix de la zone."}]});
  add("socio-structure", {"qcm":[{"q":"Chez Marx, le critère décisif qui définit l'appartenance de classe est :","o":["Le niveau de revenu atteint","La place occupée dans les rapports de production","Le prestige reconnu par autrui","Le niveau de diplôme obtenu"],"c":1,"e":"Pour Marx, ce qui fonde la classe est la position dans les rapports de production (propriété ou non des moyens de production), et non le revenu ou le prestige."},{"q":"Une « classe en soi » au sens de Marx désigne :","o":["Une classe consciente de ses intérêts et organisée pour les défendre","Un ensemble d'individus partageant objectivement la même place dans la production, sans conscience commune","La fraction dominante de la bourgeoisie","Un groupe de statut fondé sur l'honneur social"],"c":1,"e":"La classe « en soi » existe objectivement (même situation dans la production) mais sans conscience ni mobilisation : c'est le stade qui précède la classe « pour soi »."},{"q":"Chez Weber, l'ordre qui repose sur l'honneur et le prestige social, indépendamment de la richesse, est :","o":["L'ordre économique (classe)","L'ordre politique (parti)","L'ordre social (groupe de statut)","L'ordre juridique"],"c":2,"e":"Weber distingue trois ordres : économique (classes), social (groupes de statut fondés sur l'honneur/prestige) et politique (partis, recherche du pouvoir)."},{"q":"Pour Weber, une « classe » se définit avant tout par :","o":["Le partage d'un même mode de vie et d'un même honneur","Une situation commune sur le marché (chances d'accès aux biens et revenus)","La conscience d'appartenir à un même groupe","L'adhésion à une organisation politique"],"c":1,"e":"Chez Weber, la classe renvoie à une « situation de classe » définie par les chances sur le marché (biens, services, revenus), distincte du groupe de statut et du parti."},{"q":"Dire que la structure sociale s'analyse de façon « multidimensionnelle », c'est refuser de la réduire :","o":["Au seul revenu","À la seule profession (PCS)","À une seule variable, qu'elle soit la PCS, le revenu ou le diplôme","Au seul patrimoine"],"c":2,"e":"L'approche multidimensionnelle croise plusieurs facteurs (PCS, revenu, diplôme, genre, âge, lieu de résidence) plutôt que de hiérarchiser la société selon un seul critère."},{"q":"La « grande bourgeoisie » étudiée par Michel et Monique Pinçon-Charlot illustre surtout :","o":["La dissolution des classes dans une vaste classe moyenne","La persistance d'une classe dominante fortement consciente d'elle-même et mobilisée","L'individualisation des modes de vie","La fin du sentiment d'appartenance de classe"],"c":1,"e":"Les Pinçon-Charlot montrent que la grande bourgeoisie reste une classe « pour soi », dotée d'une forte conscience collective et de mécanismes d'entre-soi, contre la thèse de la moyennisation."},{"q":"Chez Goblot, la « barrière » désigne :","o":["Le mode de vie et de consommation qui distingue la bourgeoisie","Le mécanisme de sélection (notamment le diplôme) qui contrôle l'entrée dans la bourgeoisie","Le patrimoine financier des familles bourgeoises","La frontière géographique entre quartiers"],"c":1,"e":"Goblot distingue la « barrière » (le filtre, notamment scolaire, qui empêche d'entrer dans la bourgeoisie) du « niveau » (le mode de vie partagé une fois admis)."},{"q":"Selon Goblot, le « niveau » correspond :","o":["Au seuil de revenu minimal pour être bourgeois","Aux manières d'être et au mode de vie communs qui unifient la bourgeoisie","Au diplôme exigé à l'entrée","À la position dans les rapports de production"],"c":1,"e":"Le « niveau » est l'ensemble des manières de vivre et de paraître partagées qui assurent l'unité interne de la bourgeoisie, une fois la « barrière » franchie."},{"q":"La convertibilité des capitaux chez Bourdieu signifie que :","o":["Tous les capitaux ont la même valeur sociale","Une forme de capital peut, sous conditions, se transformer en une autre","Le capital culturel ne peut jamais devenir économique","Seul le capital économique compte vraiment"],"c":1,"e":"Bourdieu insiste sur la convertibilité : par exemple, le capital économique peut financer des études (capital culturel), et les diplômes peuvent ouvrir des emplois rémunérateurs (retour vers l'économique)."},{"q":"Le capital culturel « incorporé » au sens de Bourdieu renvoie :","o":["Aux diplômes obtenus","Aux livres, œuvres et instruments possédés","Aux dispositions durables, savoirs et manières intériorisés par l'individu","Au réseau de relations utiles"],"c":2,"e":"Bourdieu distingue trois états du capital culturel : incorporé (dispositions intériorisées), objectivé (biens culturels) et institutionnalisé (diplômes)."},{"q":"La « tertiarisation » de l'emploi désigne :","o":["Le recul de l'emploi agricole","La montée de la part des services dans l'emploi total","La hausse du nombre d'ouvriers","La progression de l'emploi industriel"],"c":1,"e":"La tertiarisation est la croissance du poids du secteur des services (tertiaire) dans l'emploi, au détriment des secteurs primaire et secondaire."},{"q":"Le déclin du poids de la classe ouvrière dans la société française s'explique notamment par :","o":["La désindustrialisation et la tertiarisation de l'économie","La hausse du nombre d'agriculteurs","La disparition du salariat","La baisse générale de la population active"],"c":0,"e":"La part des ouvriers a reculé sous l'effet de la désindustrialisation, de l'automatisation et de la tertiarisation, même si les ouvriers restent un groupe nombreux."},{"q":"La thèse de la « polarisation » de la société s'oppose à celle de la moyennisation car elle insiste sur :","o":["L'homogénéisation des modes de vie","Le creusement des écarts entre le haut et le bas, au détriment des classes moyennes","La disparition de toute hiérarchie sociale","La hausse continue du sentiment d'appartenance de classe"],"c":1,"e":"La polarisation décrit un éloignement des extrêmes (très aisés / précaires) et un effritement des positions intermédiaires, à rebours de la thèse d'une vaste classe moyenne unifiée."},{"q":"Le « gradient » ou continuum social mobilisé par certains sociologues suggère que :","o":["La société est strictement divisée en classes antagonistes","Les positions sociales se distribuent de façon continue, sans frontières nettes entre groupes","Seules deux classes existent","Le revenu n'a aucune influence sur la position"],"c":1,"e":"Une lecture en termes de strates ou de continuum (gradient) met en avant des écarts graduels plutôt que des classes nettement délimitées et conflictuelles."},{"q":"Le « sentiment d'appartenance de classe » désigne :","o":["La place objective dans les rapports de production","La conscience subjective de faire partie d'un groupe social donné","Le niveau de revenu d'un ménage","La nomenclature utilisée par l'INSEE"],"c":1,"e":"C'est la dimension subjective de la classe : se reconnaître soi-même comme membre d'un groupe social. Son intensité varie dans le temps et selon les groupes."},{"q":"Quel critère ne fait PAS partie de ceux que l'INSEE combine pour construire les PCS ?","o":["Le statut (salarié / indépendant)","La qualification","Le montant du patrimoine financier","Le secteur d'activité"],"c":2,"e":"Les PCS reposent sur la profession, le statut (salarié/non salarié), la qualification, la position hiérarchique et le secteur, mais pas directement sur le patrimoine."},{"q":"Dans la nomenclature des PCS, les « professions intermédiaires » désignent :","o":["Les cadres dirigeants","Des positions situées entre les cadres et les employés/ouvriers (ex. techniciens, instituteurs)","Les agriculteurs exploitants","Les chômeurs n'ayant jamais travaillé"],"c":1,"e":"Les professions intermédiaires (PCS niveau 4) regroupent des emplois intermédiaires comme techniciens, contremaîtres, instituteurs, infirmiers."},{"q":"L'« individualisation » des modes de vie tend, selon ses défenseurs, à :","o":["Renforcer la conscience de classe","Affaiblir le poids des appartenances collectives sur les comportements","Restaurer la lutte des classes","Supprimer toute inégalité de revenu"],"c":1,"e":"La thèse de l'individualisation soutient que les trajectoires et choix se détacheraient des déterminismes de classe, brouillant le poids des appartenances collectives."},{"q":"Le facteur « lieu de résidence » structure l'espace social notamment à travers :","o":["La seule densité de population","La ségrégation spatiale et l'inégale dotation des territoires","L'âge moyen des habitants uniquement","Le climat local"],"c":1,"e":"Le territoire (quartiers, métropoles/périphéries, ségrégation résidentielle) participe à la hiérarchisation sociale et au cumul des avantages ou désavantages."},{"q":"L'âge structure la société car :","o":["Il n'a aucune incidence sur les revenus","Il est lié à des écarts de patrimoine, de revenu et de mode de vie entre générations","Il détermine à lui seul la classe sociale","Il a remplacé la PCS dans les statistiques de l'INSEE"],"c":1,"e":"L'âge (et la position dans le cycle de vie) est un facteur de différenciation : accumulation de patrimoine, écarts générationnels de revenus et de modes de vie."},{"q":"Selon Weber, classe, statut et parti :","o":["Coïncident toujours parfaitement","Constituent trois dimensions distinctes qui peuvent ne pas se recouvrir","Se réduisent à la seule dimension économique","Désignent la même chose sous trois noms"],"c":1,"e":"L'apport de Weber est précisément de distinguer trois ordres autonomes : on peut être riche sans prestige, ou prestigieux sans pouvoir politique."},{"q":"La « moyennisation » selon Mendras est principalement associée à :","o":["La période 1945-1975 (Trente Glorieuses)","Les années 1880-1914","La crise de 2008","Les années 2020"],"c":0,"e":"Mendras situe la moyennisation pendant les Trente Glorieuses (forte croissance, hausse du niveau de vie, diffusion de la consommation de masse)."},{"q":"La « distinction » au sens de Bourdieu repose sur l'idée que :","o":["Les goûts sont purement individuels et aléatoires","Les pratiques culturelles servent à marquer et reproduire les écarts sociaux","Toutes les classes ont les mêmes goûts","Le goût ne dépend que du revenu"],"c":1,"e":"Pour Bourdieu, les goûts sont socialement situés : les classes dominantes se distinguent par des pratiques légitimes, ce qui reproduit la hiérarchie sociale."},{"q":"Affirmer que les PCS sont une construction « relationnelle » signifie que :","o":["Chaque PCS se définit indépendamment des autres","Une PCS ne prend sens que par sa position relative aux autres dans la nomenclature","Les PCS sont fondées sur le patrimoine","Les PCS sont fixées par les individus eux-mêmes"],"c":1,"e":"Les PCS forment un système : un groupe se définit par contraste avec les autres (cadres vs employés vs ouvriers), d'où leur caractère relationnel et hiérarchisé."},{"q":"La hausse du niveau de diplôme dans la population active depuis 1950 a notamment pour effet :","o":["De supprimer toute inégalité","De modifier la structure des emplois et de nourrir le débat sur le déclassement","De faire disparaître les PCS","De réduire la part des services"],"c":1,"e":"L'élévation du niveau de qualification transforme la structure socioprofessionnelle (plus de cadres et professions intermédiaires) et alimente les débats sur le déclassement des diplômés."},{"q":"Pour les tenants du maintien des classes sociales, le brouillage apparent des frontières :","o":["Prouve la disparition des classes","N'empêche pas la persistance d'inégalités et de reproductions sociales structurées","Signifie que la PCS est inutile","Confirme la thèse de l'individualisation totale"],"c":1,"e":"Malgré l'individualisation, les inégalités de patrimoine, de réussite scolaire et de mode de vie restent fortement structurées : les classes garderaient une pertinence."},{"q":"Le capital social, chez Bourdieu, agit comme ressource car :","o":["Il se mesure au seul revenu du ménage","Il mobilise un réseau de relations procurant des avantages (information, soutien, accès)","Il correspond aux diplômes","Il désigne le patrimoine immobilier"],"c":1,"e":"Le capital social est l'ensemble des ressources liées à la possession d'un réseau durable de relations, mobilisables pour obtenir des avantages."},{"q":"La « salarisation » de la société française renvoie :","o":["À la diffusion du statut de salarié comme forme dominante d'emploi","À la baisse du nombre de salariés","À la montée du travail indépendant","Au recul des services"],"c":0,"e":"La salarisation désigne la généralisation du salariat (aujourd'hui ~9 actifs occupés sur 10), au détriment du travail indépendant traditionnel."},{"q":"La féminisation de la population active occupée renvoie :","o":["À la baisse du nombre de femmes au travail","À la hausse de la part des femmes parmi les actifs occupés","À l'égalité salariale désormais atteinte","À la fin de la division sexuée du travail"],"c":1,"e":"La féminisation désigne l'augmentation de la part des femmes dans l'emploi, sans pour autant signifier la fin des inégalités professionnelles entre les sexes."},{"q":"Une critique adressée à la thèse de la moyennisation est que :","o":["Les inégalités auraient disparu","Elle masque le retour et le creusement des inégalités depuis les années 1980","Elle surestime le rôle des classes","Elle nie l'existence d'une classe moyenne"],"c":1,"e":"Depuis les années 1980, le creusement des inégalités de revenus et de patrimoine et la polarisation des emplois remettent en cause l'image d'une société moyennisée."}],"vf":[{"s":"Chez Marx, deux individus ayant le même revenu appartiennent forcément à la même classe.","a":false,"e":"Pour Marx, c'est la place dans les rapports de production (et non le revenu) qui définit la classe : un cadre salarié et un petit patron peuvent avoir un revenu proche sans même position de classe."},{"s":"Pour Weber, on peut disposer d'un fort prestige social (statut) sans détenir une grande richesse économique.","a":true,"e":"Weber distingue l'ordre du statut (honneur, prestige) de l'ordre économique : les deux peuvent ne pas coïncider, par exemple un notable désargenté."},{"s":"Chez Goblot, la « barrière » et le « niveau » désignent exactement la même réalité.","a":false,"e":"La barrière est le mécanisme de sélection (entrée), le niveau est le mode de vie partagé (unité interne) : ce sont deux notions complémentaires mais distinctes."},{"s":"Les trois états du capital culturel chez Bourdieu sont l'incorporé, l'objectivé et l'institutionnalisé.","a":true,"e":"Bourdieu distingue le capital culturel incorporé (dispositions), objectivé (biens culturels) et institutionnalisé (diplômes)."},{"s":"La polarisation des emplois et la moyennisation décrivent le même phénomène.","a":false,"e":"La moyennisation décrit une vaste classe moyenne qui atténue les clivages ; la polarisation décrit au contraire un creusement entre le haut et le bas au détriment du milieu."},{"s":"La salarisation désigne aujourd'hui la diffusion du statut de salarié comme forme principale d'emploi en France.","a":true,"e":"Environ 9 actifs occupés sur 10 sont salariés : la salarisation est une tendance lourde de la structure socioprofessionnelle."},{"s":"Le déclin de la part des ouvriers s'explique notamment par la désindustrialisation et la tertiarisation.","a":true,"e":"La baisse du poids des ouvriers résulte de la désindustrialisation, de l'automatisation et de la montée des services."},{"s":"Pour Weber, classe, statut et parti se confondent toujours.","a":false,"e":"Weber pose trois ordres autonomes (économique, social, politique) qui peuvent ne pas se recouvrir."},{"s":"Le capital social, chez Bourdieu, désigne le réseau de relations mobilisables par un individu.","a":true,"e":"Le capital social est l'ensemble des ressources liées à un réseau durable de relations, source d'avantages."},{"s":"Les différentes formes de capital chez Bourdieu sont totalement étanches et jamais convertibles entre elles.","a":false,"e":"Au contraire, Bourdieu insiste sur la convertibilité des capitaux (ex. économique → culturel via les études)."},{"s":"Le lieu de résidence peut renforcer le cumul d'avantages ou de désavantages sociaux.","a":true,"e":"La ségrégation spatiale fait que le territoire participe à la hiérarchisation sociale et au cumul des positions."},{"s":"La « classe en soi » de Marx suppose déjà une conscience de classe organisée.","a":false,"e":"La classe en soi existe objectivement sans conscience ; c'est la classe pour soi qui suppose conscience et mobilisation."},{"s":"L'individualisation des modes de vie tend, selon ses partisans, à atténuer le poids des appartenances de classe.","a":true,"e":"La thèse de l'individualisation soutient que les comportements se détachent des déterminismes collectifs de classe."},{"s":"Les travaux des Pinçon-Charlot sur la grande bourgeoisie illustrent la disparition des classes sociales.","a":false,"e":"Ils montrent au contraire la persistance d'une classe dominante très consciente d'elle-même et fortement mobilisée."},{"s":"Les PCS ne reposent pas directement sur le montant du patrimoine des individus.","a":true,"e":"Les PCS sont construites à partir de la profession, du statut, de la qualification et du secteur, non du patrimoine."}],"trous":[{"t":"Chez Marx, une classe qui existe objectivement par sa place dans la production mais sans conscience commune est une classe « en _____ ».","a":"soi","e":"La classe « en soi » s'oppose à la classe « pour soi », qui suppose conscience et mobilisation."},{"t":"Chez Weber, le groupe fondé sur l'honneur et le prestige social est le groupe de _____.","a":"statut","alt":["statuts"],"e":"Weber distingue classe (économique), statut (prestige/honneur) et parti (pouvoir)."},{"t":"Chez Goblot, le mécanisme de sélection, notamment scolaire, qui contrôle l'entrée dans la bourgeoisie est la _____.","a":"barrière","e":"La barrière (filtre, ex. diplôme) se complète du « niveau » (mode de vie partagé)."},{"t":"Chez Goblot, le mode de vie partagé qui assure l'unité interne de la bourgeoisie est le _____.","a":"niveau","e":"Le « niveau » désigne les manières d'être communes une fois la « barrière » franchie."},{"t":"Chez Bourdieu, le capital culturel sous forme de dispositions intériorisées est dit _____.","a":"incorporé","e":"Les trois états sont : incorporé, objectivé (biens culturels) et institutionnalisé (diplômes)."},{"t":"La possibilité de transformer une forme de capital en une autre est la _____ des capitaux.","a":"convertibilité","e":"Bourdieu souligne par exemple la conversion du capital économique en capital culturel via les études."},{"t":"La thèse selon laquelle les écarts se creusent entre le haut et le bas au détriment du milieu est la _____ de la société.","a":"polarisation","e":"La polarisation s'oppose à la thèse de la moyennisation de Mendras."},{"t":"Le processus par lequel le statut de salarié devient la forme dominante d'emploi est la _____.","a":"salarisation","e":"Environ 9 actifs occupés sur 10 sont aujourd'hui salariés en France."},{"t":"Le recul de l'emploi industriel qui réduit le poids de la classe ouvrière est la _____.","a":"désindustrialisation","e":"La désindustrialisation, avec la tertiarisation, explique le déclin de la part des ouvriers."},{"t":"La conscience subjective de faire partie d'un groupe social est le sentiment d'_____ de classe.","a":"appartenance","e":"C'est la dimension subjective de la classe, distincte de la position objective."},{"t":"L'approche qui croise PCS, revenu, diplôme, genre, âge et lieu pour décrire la société est dite _____.","a":"multidimensionnelle","e":"Elle refuse de réduire la structure sociale à un seul critère."},{"t":"Dans les PCS, les techniciens, instituteurs ou contremaîtres relèvent des professions _____.","a":"intermédiaires","e":"Les professions intermédiaires (groupe 4) se situent entre cadres et employés/ouvriers."},{"t":"Le processus par lequel les comportements se détachent des déterminismes collectifs est l'_____.","a":"individualisation","e":"L'individualisation est invoquée pour expliquer le brouillage des appartenances de classe."},{"t":"Pour Bourdieu, les pratiques culturelles servent à marquer les écarts sociaux : c'est la _____.","a":"distinction","e":"La distinction décrit l'usage des goûts comme marqueurs et reproducteurs de la hiérarchie sociale."},{"t":"Pour Weber, la stratification combine un ordre économique, un ordre social et un ordre _____.","a":"politique","e":"L'ordre politique correspond aux partis (recherche du pouvoir), aux côtés des classes et des groupes de statut."}]});
  add("socio-ecole", {"qcm":[{"q":"Le titre de l'ouvrage de 1964 où Bourdieu et Passeron analysent les inégalités d'accès des étudiants à l'université est :","o":["La Reproduction","Les Héritiers","La Distinction","L'École capitaliste"],"c":1,"e":"« Les Héritiers » (1964) précède « La Reproduction » (1970)."},{"q":"La « violence symbolique » chez Bourdieu désigne :","o":["Les châtiments corporels à l'école","L'imposition d'une culture dominante vécue comme légitime et neutre","Les brimades entre élèves","La répression policière des manifestations lycéennes"],"c":1,"e":"L'École impose l'arbitraire culturel dominant en le faisant percevoir comme universel."},{"q":"La démocratisation dite « qualitative » (ou réelle) est atteinte lorsque :","o":["Les effectifs scolarisés augmentent","Le lien entre origine sociale et réussite scolaire se desserre","Le nombre de diplômes délivrés progresse","La durée moyenne des études s'allonge"],"c":1,"e":"La démocratisation qualitative suppose une réduction des inégalités selon l'origine, au-delà de la simple hausse des effectifs."},{"q":"La « translation » des inégalités scolaires (Prost) désigne le fait que :","o":["Les inégalités disparaissent avec la massification","Les inégalités se déplacent vers des niveaux ou filières plus élevés sans disparaître","L'école traduit les diplômes en emplois","Les élèves changent d'établissement"],"c":1,"e":"La massification déplace le seuil où jouent les inégalités (du collège vers le lycée puis le supérieur) sans les supprimer."},{"q":"L'« effet de structure » lié à la dévaluation des diplômes signifie que :","o":["Les diplômes valent plus à mesure qu'ils se diffusent","La valeur relative d'un diplôme baisse quand il se généralise","Les diplômes deviennent gratuits","Les structures scolaires se réforment"],"c":1,"e":"Quand un diplôme se massifie, son rendement relatif sur le marché du travail diminue : c'est l'inflation scolaire."},{"q":"Le concept d'« inflation scolaire » désigne :","o":["La hausse du coût des études","L'augmentation des effectifs d'enseignants","La dévalorisation des diplômes liée à leur multiplication","La hausse des frais d'inscription"],"c":2,"e":"Plus un diplôme est répandu, moins il est distinctif : sa valeur sur le marché du travail se déprécie."},{"q":"Le « curriculum caché » désigne :","o":["Les programmes officiels non publiés","Les savoirs et normes implicites transmis par l'école au-delà des programmes","Les cours particuliers","Les notes confidentielles des enseignants"],"c":1,"e":"Au-delà des contenus officiels, l'école transmet des dispositions, normes et codes implicites."},{"q":"La « carte scolaire » est un dispositif qui :","o":["Note les établissements","Affecte les élèves à un établissement selon leur lieu de résidence","Recense les diplômes obtenus","Classe les lycées par résultats au bac"],"c":1,"e":"La sectorisation rattache chaque élève à un établissement selon son domicile ; sa contestation alimente la ségrégation."},{"q":"La ségrégation scolaire renvoie principalement à :","o":["La séparation des filles et des garçons","La concentration d'élèves de mêmes origines sociales ou ethniques dans certains établissements","Le redoublement des élèves faibles","L'orientation vers l'apprentissage"],"c":1,"e":"La ségrégation désigne la répartition inégale et séparée des publics scolaires entre établissements."},{"q":"L'« effet pairs » (peer effect) désigne l'influence sur la réussite d'un élève exercée par :","o":["Ses enseignants","La composition sociale et scolaire de ses camarades","Ses parents","Le ministère"],"c":1,"e":"Le niveau et l'origine sociale des camarades de classe influencent la réussite individuelle."},{"q":"Chez Bourdieu, le « rapport au langage » des classes favorisées avantage à l'école car :","o":["Elles parlent plus fort","Le langage scolaire valorisé est proche de leur langage familial","Elles connaissent des langues étrangères","Elles écrivent plus vite"],"c":1,"e":"La proximité entre le langage scolaire (abstrait, soutenu) et le langage des familles cultivées constitue un avantage."},{"q":"Pour Boudon, la « position » d'un individu influence ses choix scolaires car le coût d'un échec ou d'une poursuite d'études :","o":["Est identique pour tous","Varie selon l'origine sociale et le risque de déclassement","Dépend uniquement des notes","Est fixé par l'État"],"c":1,"e":"Boudon raisonne en termes de coûts/bénéfices/risques différenciés selon la position sociale d'origine."},{"q":"La notion d'« habitus » mobilisée pour l'école désigne :","o":["L'uniforme scolaire","Un système de dispositions durables incorporées orientant les conduites","Le règlement intérieur","Le rythme des vacances"],"c":1,"e":"L'habitus, intériorisé par la socialisation, oriente les pratiques et le rapport à l'école."},{"q":"L'effet « Pygmalion » (Rosenthal et Jacobson) montre que :","o":["Les élèves notent leurs professeurs","Les attentes des enseignants influencent les performances des élèves","Les bons élèves choisissent leurs camarades","Les parents financent le soutien scolaire"],"c":1,"e":"Les attentes (positives ou négatives) des enseignants tendent à se réaliser dans les résultats des élèves : prophétie auto-réalisatrice."},{"q":"L'objectif fixé en France d'« amener 80 % d'une classe d'âge au niveau du baccalauréat » date de :","o":["La loi de 1989","La création du collège unique en 1975","Les lois Ferry de 1882","La réforme du lycée de 2019"],"c":0,"e":"La loi d'orientation de 1989 (loi Jospin) fixe cet objectif des 80 % au niveau bac."},{"q":"Le « collège unique » (réforme Haby, 1975) visait à :","o":["Supprimer le baccalauréat","Réunir tous les élèves dans un même collège jusqu'à la 3e","Créer des filières dès la 6e","Privatiser l'enseignement"],"c":1,"e":"Le collège unique unifie le premier cycle du secondaire pour tous les élèves, retardant l'orientation."},{"q":"Les inégalités scolaires liées au genre se traduisent notamment par :","o":["De meilleures réussites scolaires des garçons à tous niveaux","De meilleurs résultats scolaires des filles mais une orientation différenciée","L'absence totale de différence","Une scolarisation plus tardive des filles"],"c":1,"e":"Les filles réussissent globalement mieux à l'école mais s'orientent moins vers les filières scientifiques prestigieuses."},{"q":"L'« autosélection » des familles populaires dans l'orientation désigne le fait qu'elles :","o":["Visent systématiquement les filières les plus longues","Limitent d'elles-mêmes leurs ambitions scolaires à niveau scolaire égal","Refusent l'école","Choisissent toujours le privé"],"c":1,"e":"À résultats équivalents, les familles populaires demandent des orientations plus modestes : un mécanisme d'autosélection."},{"q":"La massification scolaire en France après 1960 s'est traduite par un nombre de bacheliers passant d'environ :","o":["60 % à 80 % d'une génération","Moins de 10 % à plus de 70 % d'une génération","30 % à 40 % d'une génération","90 % à 95 % d'une génération"],"c":1,"e":"La part de bacheliers dans une génération est passée d'environ 5-10 % au milieu du XXe siècle à plus de 70 % aujourd'hui."},{"q":"Pour Baudelot et Establet, le système scolaire reproduit la division sociale en orientant les élèves vers deux réseaux distincts notés :","o":["Public et privé","Réseau primaire-professionnel (PP) et réseau secondaire-supérieur (SS)","Général et technologique","Urbain et rural"],"c":1,"e":"Leur thèse (« L'École capitaliste en France ») oppose le réseau PP (populaire) au réseau SS (bourgeois)."},{"q":"La distinction entre « égalité des chances » et « égalité des résultats » tient à ce que la première :","o":["Garantit à tous le même diplôme","Égalise les points de départ sans garantir les positions finales","Supprime les notes","Impose un revenu identique"],"c":1,"e":"L'égalité des chances vise des conditions de départ équitables, pas l'égalité des positions d'arrivée."},{"q":"L'École remplit une fonction de « mobilité sociale » lorsqu'elle :","o":["Reproduit les positions héritées","Permet d'accéder à une position différente de celle des parents grâce au diplôme","Maintient la carte scolaire","Sélectionne par l'argent"],"c":1,"e":"Le diplôme peut être un vecteur de mobilité ascendante en déconnectant la position de l'origine."},{"q":"La « discrimination positive » à l'école (ex. ZEP, internats d'excellence) vise à :","o":["Donner plus à ceux qui ont le moins pour compenser les inégalités","Réserver les meilleures classes aux favorisés","Supprimer les aides aux défavorisés","Uniformiser strictement les moyens"],"c":0,"e":"« Donner plus à ceux qui ont moins » : allouer des moyens supplémentaires aux territoires défavorisés."},{"q":"L'acronyme « ZEP » désigne :","o":["Zone d'éducation prioritaire","Zone d'évaluation pédagogique","Zone d'enseignement privé","Zone d'examen permanent"],"c":0,"e":"Les ZEP (puis REP/REP+) concentrent des moyens supplémentaires dans les territoires en difficulté."},{"q":"La transmission du capital culturel par la famille passe d'abord par :","o":["L'achat de cours en ligne","La socialisation primaire et les pratiques culturelles quotidiennes","Les associations sportives","Les voyages scolaires"],"c":1,"e":"Le capital culturel s'hérite via la socialisation familiale (lectures, langage, sorties culturelles) avant l'école."},{"q":"L'évitement de la carte scolaire par les familles favorisées tend à :","o":["Réduire la ségrégation","Renforcer la ségrégation sociale entre établissements","Supprimer le privé","Égaliser les niveaux"],"c":1,"e":"Les stratégies de contournement concentrent les élèves favorisés dans certains établissements, accentuant la ségrégation."},{"q":"Le « décrochage scolaire » désigne :","o":["Le redoublement","La sortie du système sans diplôme ni qualification","Le passage du public au privé","Le choix d'une filière scientifique"],"c":1,"e":"Le décrochage est l'abandon des études sans avoir obtenu de diplôme qualifiant."},{"q":"Selon la théorie de la reproduction, la note scolaire « neutre » sanctionne en réalité :","o":["Le seul mérite individuel","La maîtrise inégalement répartie de la culture dominante","L'effort fourni en classe","Le comportement en cours"],"c":1,"e":"La réussite mesure surtout la proximité avec la culture légitime, transmise inégalement selon l'origine."},{"q":"La hausse de la scolarisation des filles a contribué, à long terme, à :","o":["Réduire leur participation au marché du travail","Élever leur niveau de diplôme au-dessus de celui des garçons en moyenne","Diminuer leur réussite au bac","Supprimer toute inégalité de genre"],"c":1,"e":"Les filles ont rattrapé puis dépassé les garçons en niveau de diplôme, sans effacer les inégalités d'orientation et de carrière."},{"q":"L'idée que l'École produit du « consentement » aux inégalités tient à ce qu'elle :","o":["Interdit les diplômes","Légitime les positions par le mérite scolaire apparent","Distribue des revenus","Supprime la sélection"],"c":1,"e":"En faisant apparaître la sélection comme méritocratique, l'École légitime et fait accepter la hiérarchie sociale."}],"vf":[{"s":"La démocratisation qualitative est atteinte dès que les effectifs scolarisés augmentent.","a":false,"e":"C'est la démocratisation quantitative (massification) ; la qualitative suppose une réduction des inégalités selon l'origine."},{"s":"L'inflation scolaire désigne la dévalorisation des diplômes liée à leur multiplication.","a":true,"e":"La généralisation d'un diplôme réduit sa valeur relative sur le marché du travail."},{"s":"La violence symbolique suppose nécessairement une contrainte physique.","a":false,"e":"Elle est précisément non physique : imposition d'une culture dominante perçue comme légitime."},{"s":"« Les Héritiers » (1964) précède « La Reproduction » (1970) de Bourdieu et Passeron.","a":true,"e":"Les Héritiers (1964) puis La Reproduction (1970)."},{"s":"L'effet Pygmalion désigne l'influence des attentes des enseignants sur les résultats des élèves.","a":true,"e":"Démontré par Rosenthal et Jacobson : prophétie auto-réalisatrice des attentes."},{"s":"La carte scolaire vise à classer les lycées selon leurs résultats au baccalauréat.","a":false,"e":"Elle affecte les élèves à un établissement selon leur lieu de résidence (sectorisation)."},{"s":"L'évitement de la carte scolaire par les familles favorisées tend à accentuer la ségrégation sociale.","a":true,"e":"Le contournement concentre les publics favorisés dans certains établissements."},{"s":"Pour Boudon, à résultats scolaires égaux, le choix d'orientation est identique quelle que soit l'origine sociale.","a":false,"e":"Boudon montre que les coûts/risques et donc les choix d'orientation diffèrent selon la position sociale."},{"s":"La discrimination positive (ZEP/REP) consiste à donner davantage de moyens aux territoires défavorisés.","a":true,"e":"Principe : « donner plus à ceux qui ont moins » pour compenser les inégalités."},{"s":"Le curriculum caché désigne l'ensemble des programmes officiels publiés au Journal officiel.","a":false,"e":"Au contraire, il renvoie aux normes et savoirs implicites transmis hors programme officiel."},{"s":"Les filles réussissent globalement mieux à l'école que les garçons mais s'orientent moins vers les filières scientifiques prestigieuses.","a":true,"e":"Meilleure réussite scolaire des filles, mais orientation genrée persistante."},{"s":"Le décrochage scolaire désigne le passage d'un établissement public à un établissement privé.","a":false,"e":"C'est la sortie du système sans diplôme ni qualification."},{"s":"Le collège unique (réforme Haby, 1975) a réuni tous les élèves dans un même cursus jusqu'en 3e.","a":true,"e":"Il unifie le premier cycle du secondaire et retarde l'orientation."},{"s":"Pour Baudelot et Establet, le système scolaire oriente les élèves vers deux réseaux socialement différenciés.","a":true,"e":"Le réseau primaire-professionnel (PP) et le réseau secondaire-supérieur (SS)."},{"s":"L'égalité des chances garantit que tous les individus atteindront la même position sociale.","a":false,"e":"Elle vise l'égalité des points de départ, non l'égalité des résultats."}],"trous":[{"t":"La dévalorisation d'un diplôme liée à sa multiplication est l'_____ scolaire.","a":"inflation","e":"Plus un diplôme se diffuse, plus sa valeur relative baisse."},{"t":"Chez Bourdieu, l'imposition d'une culture dominante vécue comme légitime est la violence _____.","a":"symbolique","e":"Mécanisme central de la reproduction selon Bourdieu et Passeron."},{"t":"L'ouvrage de Bourdieu et Passeron paru en 1964 sur les étudiants s'intitule Les _____.","a":"Héritiers","e":"Les Héritiers (1964) précède La Reproduction (1970)."},{"t":"L'influence des attentes des enseignants sur la réussite des élèves est l'effet _____.","a":"Pygmalion","alt":["pygmalion"],"e":"Rosenthal et Jacobson : prophétie auto-réalisatrice."},{"t":"Le système qui affecte un élève à un établissement selon son domicile est la _____ scolaire.","a":"carte","e":"La sectorisation ; son contournement nourrit la ségrégation."},{"t":"La concentration séparée d'élèves de mêmes origines dans certains établissements est la _____ scolaire.","a":"ségrégation","e":"Répartition inégale et séparée des publics scolaires."},{"t":"Donner davantage de moyens aux territoires défavorisés relève de la discrimination _____.","a":"positive","e":"Logique des ZEP/REP : « donner plus à ceux qui ont moins »."},{"t":"Le système de dispositions durables incorporées par la socialisation est l'_____.","a":"habitus","e":"Notion de Bourdieu : matrice des pratiques et du rapport à l'école."},{"t":"La sortie du système éducatif sans diplôme ni qualification est le _____ scolaire.","a":"décrochage","e":"Abandon des études sans diplôme qualifiant."},{"t":"L'ensemble des normes et savoirs implicites transmis hors programme est le curriculum _____.","a":"caché","e":"Au-delà des contenus officiels, l'école transmet des dispositions implicites."},{"t":"La réforme Haby de 1975 instaure le _____ unique, réunissant tous les élèves jusqu'en 3e.","a":"collège","e":"Unification du premier cycle du secondaire."},{"t":"La démocratisation _____, ou réelle, suppose un desserrement du lien entre origine sociale et réussite.","a":"qualitative","e":"À distinguer de la démocratisation quantitative (massification)."},{"t":"Baudelot et Establet opposent le réseau primaire-professionnel au réseau _____-supérieur.","a":"secondaire","e":"Réseaux PP (populaire) et SS (bourgeois) dans L'École capitaliste en France."},{"t":"Le principe d'égalité des _____ vise à égaliser les points de départ sans garantir les positions finales.","a":"chances","e":"À distinguer de l'égalité des résultats."},{"t":"La loi d'orientation de 1989 fixe l'objectif d'amener _____ % d'une classe d'âge au niveau du bac.","a":"80","e":"Objectif des 80 % au niveau baccalauréat (loi Jospin)."}]});
  add("socio-mobilite", {"qcm":[{"q":"La « contre-mobilité » désigne le fait, pour un individu, de :","o":["retrouver, en fin de carrière, la position sociale de ses parents après en avoir été éloigné en début de vie active","transmettre à ses enfants une position inférieure à la sienne","connaître une mobilité descendante puis ascendante","refuser une promotion pour rester dans son milieu d'origine"],"c":0,"e":"La contre-mobilité décrit un retour, au cours de la carrière, vers la position d'origine dont on s'était d'abord écarté."},{"q":"Selon Mark Granovetter, l'accès à un emploi passe souvent par les « liens faibles » car ceux-ci :","o":["sont les relations les plus intimes et les plus fréquentes","donnent accès à des informations nouvelles, hors du cercle proche","relèvent uniquement du capital économique","garantissent un emploi mieux rémunéré"],"c":1,"e":"Les liens faibles (connaissances, relations éloignées) ouvrent sur des réseaux différents et apportent des informations inédites sur les opportunités d'emploi."},{"q":"La mobilité « horizontale » se distingue de la mobilité verticale parce qu'elle :","o":["correspond toujours à une ascension sociale","implique un changement de position sans modification claire du niveau hiérarchique","mesure les déplacements géographiques des actifs","ne concerne que les femmes"],"c":1,"e":"La mobilité horizontale est un changement de groupe social sans hiérarchisation nette entre origine et arrivée (ni ascension ni déclassement marqué)."},{"q":"Le « paradoxe d'Anderson » articule mobilité sociale et diplôme en montrant que :","o":["le diplôme n'a plus aucune valeur sur le marché du travail","être plus diplômé que son père ne garantit pas une position sociale supérieure à la sienne","les enfants de cadres réussissent moins bien que ceux d'ouvriers","la mobilité structurelle a disparu"],"c":1,"e":"Anderson constate qu'obtenir un diplôme supérieur à celui de son père ne suffit pas à occuper une position plus élevée, du fait de la dévaluation des diplômes."},{"q":"Chez Bourdieu, la transmission du capital culturel explique la reproduction sociale surtout parce que :","o":["l'école neutralise totalement les écarts d'origine","les familles favorisées transmettent des codes valorisés par l'école, convertis en réussite","le capital économique se transmet sans héritage","les diplômes sont attribués au hasard"],"c":1,"e":"L'école valorise le capital culturel des familles dominantes (langage, codes, dispositions), ce qui reproduit les positions de génération en génération."},{"q":"L'homogamie sociale tend à freiner la fluidité sociale parce qu'elle :","o":["concentre les ressources économiques et culturelles au sein des mêmes milieux","favorise systématiquement les unions entre milieux différents","supprime la transmission du capital culturel","ne concerne que la mobilité géographique"],"c":0,"e":"En choisissant un conjoint du même milieu, les individus cumulent et reproduisent les ressources de leur groupe, ce qui limite le brassage social."},{"q":"La « déformation de la structure socioprofessionnelle » est à l'origine de la mobilité :","o":["nette","structurelle","horizontale","de circulation"],"c":1,"e":"L'évolution de la structure des emplois (tertiarisation, salarisation, hausse des cadres) impose des changements de position : c'est la mobilité structurelle."},{"q":"La mobilité « de circulation » (ou nette) est obtenue en :","o":["additionnant mobilité structurelle et reproduction","retranchant la mobilité structurelle de la mobilité observée","multipliant la mobilité observée par la fluidité","mesurant uniquement les déclassements"],"c":1,"e":"Mobilité de circulation = mobilité observée − mobilité structurelle ; elle reflète le brassage indépendant des évolutions de la structure des emplois."},{"q":"Dans une table de destinée, la somme des effectifs d'une ligne correspond :","o":["à l'ensemble des individus d'une même origine sociale","à l'ensemble des individus d'une même position d'arrivée","au total de la population active","au nombre de fils devenus cadres"],"c":0,"e":"La table de destinée se lit en lignes : chaque ligne part d'une origine et répartit le devenir des enfants ; la ligne totalise une origine donnée."},{"q":"Le rôle du « capital social » dans la mobilité tient surtout à ce qu'il :","o":["se réduit aux diplômes obtenus","fournit des réseaux mobilisables pour accéder à l'information et aux postes","correspond au patrimoine financier hérité","est sans effet sur l'insertion professionnelle"],"c":1,"e":"Le capital social, ensemble des relations mobilisables, facilite l'accès à l'emploi et aux opportunités, et pèse donc sur la trajectoire sociale."},{"q":"Une « égalité parfaite des chances » sur le marché des positions correspondrait à une situation de :","o":["mobilité structurelle maximale","fluidité sociale parfaite, où l'origine n'influence plus la position","reproduction sociale totale","mobilité horizontale généralisée"],"c":1,"e":"La fluidité parfaite signifie une indépendance totale entre origine et position : tous les enfants ont les mêmes chances d'accéder à chaque position."},{"q":"La configuration familiale (nombre d'enfants, rang dans la fratrie) influence la mobilité car elle :","o":["modifie le volume de capital culturel et l'investissement éducatif par enfant","détermine mécaniquement la PCS des enfants","supprime l'effet de l'origine sociale","ne joue que pour les familles aisées"],"c":0,"e":"Le nombre d'enfants et la place dans la fratrie affectent l'investissement familial (temps, ressources) consacré à chacun, donc les trajectoires scolaires et sociales."},{"q":"On parle de mobilité « ascendante » lorsque :","o":["l'enfant occupe une position jugée supérieure à celle de ses parents","l'enfant reste dans le groupe social de ses parents","les parents changent de profession","la structure des emplois se contracte"],"c":0,"e":"La mobilité ascendante désigne une trajectoire où la position de l'enfant est supérieure à celle de son parent."},{"q":"Le déclassement « scolaire » se distingue du déclassement « social » en ce qu'il désigne :","o":["une position inférieure à celle attendue compte tenu du diplôme obtenu","une position inférieure à celle des parents","un changement de région","une perte de capital économique uniquement"],"c":0,"e":"Le déclassement scolaire mesure l'écart entre le niveau de diplôme et la position effectivement occupée ; le déclassement social compare avec l'origine."},{"q":"La « dévaluation des diplômes » résulte principalement :","o":["d'une baisse du nombre de diplômés","de la massification scolaire qui rend les diplômes plus communs à valeur de position donnée","de la suppression du baccalauréat","d'une hausse de la mobilité structurelle ascendante"],"c":1,"e":"Avec la massification, un diplôme donné devient plus répandu et donne accès à des positions relativement moins élevées : c'est sa dévaluation."},{"q":"Pour étudier la reproduction sociale, Bourdieu mobilise surtout la notion de :","o":["solidarité organique","habitus et de capital culturel","passager clandestin","destruction créatrice"],"c":1,"e":"L'habitus, dispositions intériorisées issues du milieu, et la transmission du capital culturel sont au coeur de l'analyse bourdieusienne de la reproduction."},{"q":"La mobilité sociale des femmes est plus difficile à mesurer que celle des hommes car :","o":["les femmes ne connaissent jamais de mobilité","l'origine est longtemps rapportée à la PCS du père et l'activité féminine a évolué","les tables ne concernent que les indépendants","la fluidité féminine est nulle"],"c":1,"e":"L'usage de la PCS du père comme origine et les transformations de l'activité féminine compliquent la comparaison des trajectoires des hommes et des femmes."},{"q":"Une « distance de mobilité » importante désigne le fait que :","o":["l'enfant occupe une position très éloignée, dans la hiérarchie, de celle de son origine","l'enfant a changé de région","les parents ont eu plusieurs emplois","la table comporte de nombreuses cases"],"c":0,"e":"La distance de mobilité mesure l'écart hiérarchique entre la position d'origine et la position d'arrivée ; la mobilité de proximité reste fréquente."},{"q":"La diagonale d'une table de mobilité (cases où origine = position) traduit :","o":["la mobilité ascendante","l'immobilité ou reproduction sociale","la mobilité de circulation","la mobilité structurelle"],"c":1,"e":"Sur la diagonale, l'enfant occupe la même position que son parent : ces cases mesurent l'immobilité, c'est-à-dire la reproduction sociale."},{"q":"La hausse de la part des cadres et la baisse de celle des agriculteurs depuis 1950 ont surtout alimenté la mobilité :","o":["horizontale","structurelle ascendante","de circulation","nette descendante"],"c":1,"e":"La transformation de la structure des emplois (plus de cadres, moins d'agriculteurs) a « forcé » une mobilité structurelle largement ascendante."},{"q":"Le « plafond de verre » évoqué à propos de la mobilité désigne :","o":["un obstacle invisible limitant l'accès des femmes ou de certains groupes aux positions les plus élevées","la limite physique des tables de mobilité","la barrière entre PCS agricoles et urbaines","le seuil de pauvreté"],"c":0,"e":"Le plafond de verre est un obstacle informel qui freine l'ascension de certains groupes (notamment les femmes) vers le sommet de la hiérarchie sociale."},{"q":"Si une société connaît une forte mobilité observée mais une faible fluidité, on en conclut que :","o":["l'origine sociale pèse toujours fortement, la mobilité venant surtout de la structure","l'égalité des chances est parfaite","la reproduction sociale a disparu","les tables sont mal construites"],"c":0,"e":"Une forte mobilité observée mais une faible fluidité signifie que la mobilité tient à la déformation de la structure, non à une égalisation des chances."},{"q":"L'« hérédité sociale » mise en évidence par les tables de mobilité désigne :","o":["la transmission biologique des aptitudes","la tendance des enfants à occuper une position proche de celle de leurs parents","la mobilité géographique entre générations","l'absence de toute reproduction"],"c":1,"e":"L'hérédité sociale renvoie à la forte probabilité, lisible sur la diagonale des tables, de reproduire la position sociale d'origine."},{"q":"La mobilité intragénérationnelle est aussi appelée mobilité :","o":["professionnelle, au cours de la carrière d'un même individu","intergénérationnelle ascendante","structurelle","de recrutement"],"c":0,"e":"La mobilité intragénérationnelle suit les changements de position d'un individu au fil de sa propre vie active : c'est la mobilité professionnelle."},{"q":"Les liens « forts » (famille proche, amis intimes) favorisent moins l'accès à de nouveaux emplois car ils :","o":["donnent accès à une information souvent redondante, déjà connue de l'individu","sont toujours moins nombreux que les liens faibles","relèvent du seul capital économique","sont interdits par le marché du travail"],"c":0,"e":"Granovetter montre que l'entourage proche partage les mêmes informations : les liens forts apportent peu de renseignements nouveaux sur les opportunités."},{"q":"La « reproduction sociale » au sens sociologique désigne :","o":["la perpétuation, d'une génération à l'autre, des positions et inégalités sociales","la croissance démographique d'un groupe","le renouvellement des générations d'actifs","la mobilité de circulation"],"c":0,"e":"La reproduction sociale est le maintien, entre générations, de la structure des positions et des inégalités, analysé notamment par Bourdieu et Passeron."},{"q":"Un enfant d'ouvrier devenu cadre puis redevenu employé illustre une trajectoire combinant :","o":["mobilité ascendante puis descendante au cours de la vie (mobilité intragénérationnelle)","reproduction sociale stricte","homogamie","mobilité structurelle uniquement"],"c":0,"e":"Cette trajectoire en deux temps, au sein d'une même vie active, relève de la mobilité intragénérationnelle, ici ascendante puis descendante."},{"q":"La principale limite des tables de mobilité est qu'elles :","o":["reposent le plus souvent sur la PCS des pères et des fils, négligeant les femmes et la mère","sont impossibles à construire statistiquement","ne mesurent que la mobilité géographique","ignorent totalement l'origine sociale"],"c":0,"e":"Construites traditionnellement à partir des PCS père/fils, les tables sous-estiment la mobilité des femmes et le rôle de la trajectoire maternelle."},{"q":"Quand l'école transmet aux enfants déjà dotés en capital culturel un avantage présenté comme du mérite, Bourdieu et Passeron parlent de :","o":["violence symbolique","mobilité de circulation","paradoxe d'Anderson","solidarité mécanique"],"c":0,"e":"La violence symbolique désigne l'imposition, comme légitime, de la culture dominante, ce qui transforme un héritage social en mérite scolaire apparent."},{"q":"Une politique visant à accroître la fluidité sociale cherche avant tout à :","o":["réduire le lien entre l'origine sociale et la position atteinte","augmenter le nombre total d'emplois de cadres","limiter la mobilité géographique","supprimer les tables de mobilité"],"c":0,"e":"Accroître la fluidité, c'est rendre la position de plus en plus indépendante de l'origine, donc rapprocher la société de l'égalité des chances."},{"q":"La distinction entre mobilité « observée » et « fluidité » est utile car la fluidité :","o":["neutralise l'effet de la déformation de la structure des emplois pour mesurer l'égalité des chances","mesure les seuls déplacements géographiques","additionne reproduction et mobilité structurelle","ne dépend que du diplôme"],"c":0,"e":"La fluidité raisonne « toutes choses égales par ailleurs » quant à la structure : elle isole l'égalité (ou l'inégalité) des chances entre origines."}],"vf":[{"s":"La contre-mobilité décrit le retour, en cours de carrière, vers la position sociale d'origine.","a":true,"e":"L'individu s'éloigne d'abord de la position de ses parents puis la retrouve : c'est la contre-mobilité."},{"s":"Selon Granovetter, ce sont surtout les liens forts qui apportent les informations les plus utiles pour trouver un emploi.","a":false,"e":"C'est la « force des liens faibles » : les relations éloignées ouvrent sur des informations nouvelles, contrairement aux liens forts redondants."},{"s":"La mobilité horizontale implique un changement de groupe social sans hiérarchisation nette entre l'origine et l'arrivée.","a":true,"e":"À la différence de la mobilité verticale (ascendante/descendante), la mobilité horizontale ne traduit ni montée ni descente claire."},{"s":"Le paradoxe d'Anderson affirme qu'un diplôme supérieur à celui de son père garantit toujours une position plus élevée.","a":false,"e":"Au contraire : Anderson montre qu'être plus diplômé que son père ne suffit pas à dépasser sa position, du fait de la dévaluation des diplômes."},{"s":"L'homogamie sociale tend à limiter le brassage et donc la fluidité sociale.","a":true,"e":"En s'unissant au sein du même milieu, les individus reproduisent et cumulent leurs ressources, ce qui freine la mobilité."},{"s":"La mobilité structurelle est imposée par la déformation de la structure socioprofessionnelle.","a":true,"e":"L'évolution des emplois (plus de cadres, moins d'agriculteurs) « force » des changements de position : c'est la mobilité structurelle."},{"s":"La diagonale d'une table de mobilité mesure la mobilité ascendante.","a":false,"e":"La diagonale (origine = position) mesure l'immobilité, c'est-à-dire la reproduction sociale, et non la mobilité."},{"s":"Le capital culturel se transmet notamment dans la famille, avant l'école.","a":true,"e":"Bourdieu montre que la famille transmet très tôt langage, codes et dispositions (capital culturel incorporé) que l'école valorise ensuite."},{"s":"La mobilité de circulation s'obtient en retranchant la mobilité structurelle de la mobilité observée.","a":true,"e":"Mobilité de circulation (nette) = mobilité observée − mobilité structurelle."},{"s":"Le déclassement scolaire désigne le fait d'occuper une position inférieure à celle attendue compte tenu de son diplôme.","a":true,"e":"Le déclassement scolaire mesure l'écart entre le diplôme détenu et la position effectivement occupée."},{"s":"La massification scolaire, en multipliant les diplômés, peut entraîner une dévaluation des diplômes.","a":true,"e":"Plus un diplôme est répandu, plus sa valeur de position relative baisse : c'est la dévaluation, liée à la massification."},{"s":"La mobilité des femmes est aussi simple à mesurer que celle des hommes dans les tables classiques.","a":false,"e":"L'origine longtemps rapportée à la PCS du père et l'évolution de l'activité féminine compliquent la mesure de la mobilité des femmes."},{"s":"Le « plafond de verre » désigne un obstacle invisible à l'ascension de certains groupes vers les plus hautes positions.","a":true,"e":"Le plafond de verre est une barrière informelle qui freine notamment l'accès des femmes au sommet de la hiérarchie."},{"s":"Une forte mobilité observée signifie nécessairement une forte fluidité sociale.","a":false,"e":"Une mobilité observée élevée peut tenir surtout à la mobilité structurelle, sans égalisation des chances : la fluidité peut rester faible."},{"s":"La violence symbolique (Bourdieu, Passeron) consiste à imposer la culture dominante comme légitime.","a":true,"e":"L'école impose comme méritoire la culture des dominants, transformant un héritage social en réussite apparemment méritée."}],"trous":[{"t":"Retrouver en fin de carrière la position d'origine après s'en être éloigné est la _____-mobilité.","a":"contre","e":"La contre-mobilité est un retour vers la position sociale des parents au cours de la trajectoire."},{"t":"Selon Granovetter, ce sont les liens _____ qui donnent accès à de l'information nouvelle pour trouver un emploi.","a":"faibles","alt":["faible"],"e":"La « force des liens faibles » : les relations éloignées ouvrent sur des réseaux et des informations inédites."},{"t":"Un changement de position sans hiérarchisation nette entre origine et arrivée est une mobilité _____.","a":"horizontale","e":"La mobilité horizontale s'oppose à la mobilité verticale (ascendante ou descendante)."},{"t":"Le paradoxe selon lequel un diplôme supérieur à celui du père n'assure pas une meilleure position porte le nom d'_____.","a":"Anderson","e":"Le paradoxe d'Anderson articule mobilité et dévaluation des diplômes."},{"t":"Se mettre en couple au sein du même milieu social est l'_____ sociale, qui freine la fluidité.","a":"homogamie","e":"L'homogamie reproduit et concentre les ressources d'un même milieu."},{"t":"Pour Bourdieu, les dispositions intériorisées issues du milieu d'origine forment l'_____.","a":"habitus","e":"L'habitus, ensemble de dispositions durables, sous-tend la reproduction sociale."},{"t":"Les cases de la diagonale d'une table de mobilité mesurent l'_____, c'est-à-dire la reproduction sociale.","a":"immobilité","e":"Sur la diagonale, origine et position coïncident : il y a immobilité."},{"t":"L'imposition de la culture dominante comme légitime est, chez Bourdieu et Passeron, une violence _____.","a":"symbolique","e":"La violence symbolique fait passer un héritage social pour du mérite."},{"t":"La baisse de valeur d'un diplôme devenu plus commun avec la massification est la _____ des diplômes.","a":"dévaluation","e":"Plus un diplôme est répandu, plus sa valeur de position relative diminue."},{"t":"L'ensemble des relations et réseaux mobilisables qui facilitent l'accès à l'emploi est le capital _____.","a":"social","e":"Le capital social pèse sur la mobilité via les réseaux mobilisés."},{"t":"L'obstacle invisible freinant l'accès des femmes aux positions les plus élevées est le plafond de _____.","a":"verre","e":"Le plafond de verre est une barrière informelle à l'ascension de certains groupes."},{"t":"La déformation de la structure socioprofessionnelle est à l'origine de la mobilité _____.","a":"structurelle","e":"L'évolution des emplois « force » la mobilité structurelle."},{"t":"Occuper une position inférieure à celle attendue de son diplôme est le déclassement _____.","a":"scolaire","e":"Le déclassement scolaire compare diplôme détenu et position occupée."},{"t":"La perpétuation des positions et des inégalités d'une génération à l'autre est la _____ sociale.","a":"reproduction","e":"La reproduction sociale, analysée par Bourdieu, maintient la structure des positions."},{"t":"Le savoir et les codes transmis très tôt par la famille relèvent du capital culturel _____.","a":"incorporé","e":"Le capital culturel incorporé (langage, manières) est transmis par la famille avant l'école."}]});
  add("socio-travail", {"qcm":[{"q":"La division horizontale du travail, dans l'organisation taylorienne, consiste à :","o":["Confier la conception aux ingénieurs et l'exécution aux ouvriers","Hiérarchiser les ouvriers selon leur ancienneté dans l'atelier","Faire alterner les salariés sur plusieurs postes pour réduire la monotonie","Parcelliser les tâches d'exécution entre des ouvriers spécialisés"],"c":3,"e":"La division horizontale décompose le travail d'exécution en tâches élémentaires répétitives (parcellisation) ; la division verticale, elle, sépare conception et exécution."},{"q":"Selon Georges Friedmann, le « travail en miettes » désigne :","o":["L'éclatement de la tâche en gestes parcellaires et répétitifs vidés de sens","La diversification croissante et continue des métiers proposés dans le secteur des services","Le partage du temps de travail entre plusieurs employeurs successifs","La fragmentation des syndicats en de multiples organisations rivales"],"c":0,"e":"Friedmann critique la parcellisation taylorienne qui réduit l'ouvrier à des gestes élémentaires, monotones et dépourvus de sens : le « travail en miettes »."},{"q":"Le compromis fordiste reposait sur l'idée que :","o":["Les ouvriers renoncent à toute hausse de salaire en échange de la sécurité de l'emploi","Les gains de productivité sont redistribués en hausses de salaire soutenant la demande","L'État planifie et fixe directement les prix de tous les biens de consommation","Les entreprises délocalisent leur production afin de réduire les coûts salariaux"],"c":1,"e":"Le fordisme repose sur un cercle vertueux : gains de productivité, hausse des salaires, consommation de masse, débouchés pour la production de masse."},{"q":"La flexibilité interne (ou qualitative) du travail désigne :","o":["La polyvalence et l'adaptation des salariés en poste aux variations de l'activité","Le recours aux CDD et à l'intérim pour ajuster rapidement les effectifs employés","La capacité d'une firme à délocaliser une partie de sa production à l'étranger","La sous-traitance d'activités secondaires à d'autres entreprises spécialisées"],"c":0,"e":"La flexibilité interne joue sur les salariés déjà présents (polyvalence, horaires modulables, mobilité interne) ; la flexibilité externe ajuste le volume de main-d'oeuvre (CDD, intérim, sous-traitance)."},{"q":"La qualification « du poste » se distingue de la qualification « de l'individu » en ce que la première :","o":["Renvoie aux diplômes et à l'expérience accumulée par le travailleur","Mesure le salaire effectivement perçu chaque mois par le salarié","Caractérise les compétences requises par l'emploi occupé","Désigne le statut juridique attaché au contrat de travail signé"],"c":2,"e":"La qualification du poste = niveau de compétence exigé par l'emploi. La qualification de l'individu = savoirs, diplômes et expérience que possède la personne. Les deux peuvent ne pas coïncider (déclassement, surqualification)."},{"q":"La grève est juridiquement définie en France comme :","o":["Toute absence collective non préalablement autorisée par l'employeur","Un refus individuel d'exécuter une tâche que le salarié juge dangereuse","Une cessation collective et concertée du travail appuyant des revendications professionnelles","Une manifestation revendicative organisée sur la voie publique"],"c":2,"e":"La grève est un droit constitutionnel : arrêt collectif et concerté du travail visant à faire aboutir des revendications professionnelles."},{"q":"En France, le taux de syndicalisation des salariés est aujourd'hui d'environ :","o":["Moins de 11 %","Environ 25 %","Environ 40 %","Plus de 55 %"],"c":0,"e":"Le taux de syndicalisation français est l'un des plus faibles d'Europe, autour de 10-11 % des salariés, malgré une influence syndicale réelle via les élections professionnelles."},{"q":"Le conflit du travail le plus institutionnalisé et encadré par le droit est :","o":["Le sabotage de l'outil de production","Le débrayage spontané et non déclaré","L'absentéisme répété des salariés","La grève"],"c":3,"e":"La grève est la forme de conflit du travail la plus institutionnalisée : protégée par un droit, encadrée par des règles et souvent canalisée par les syndicats."},{"q":"La tertiarisation de l'emploi désigne :","o":["La hausse continue de la part des emplois industriels","Le recul de l'emploi salarié au profit de l'indépendance","La montée du poids des services dans l'emploi total","La concentration des emplois dans les grandes métropoles"],"c":2,"e":"La tertiarisation est l'accroissement de la part du secteur des services dans l'emploi, devenu largement majoritaire dans les économies développées."},{"q":"Les risques psychosociaux (RPS) au travail renvoient principalement à :","o":["Le stress, le mal-être et les souffrances d'origine professionnelle","Les accidents corporels graves provoqués par les machines présentes dans l'atelier","Les maladies infectieuses contractées sur le lieu de travail","Les conflits ouverts entre les syndicats et la direction"],"c":0,"e":"Les RPS désignent les atteintes à la santé mentale (stress, burn-out, harcèlement) liées à l'organisation du travail ; ils relèvent de la dégradation des conditions de travail."},{"q":"L'« autonomie » comme descripteur de la qualité de l'emploi désigne :","o":["Le montant du salaire net versé chaque mois","La marge de manoeuvre du salarié dans l'organisation de ses tâches","La distance séparant le domicile du lieu de travail","La durée totale prévue par le contrat de travail"],"c":1,"e":"L'autonomie mesure le degré de liberté du salarié dans la manière de réaliser son travail ; c'est l'un des critères de la qualité de l'emploi retenus par le programme."},{"q":"Le statut d'indépendant se caractérise par :","o":["Un contrat de travail conclu à durée déterminée","Une rémunération versée sous forme de salaire mensuel","Une protection renforcée contre le licenciement économique","L'absence de lien de subordination juridique à un employeur"],"c":3,"e":"L'indépendant (non-salarié) travaille à son compte, sans lien de subordination ; il assume lui-même le risque économique de son activité."},{"q":"Le « lien de subordination » qui caractérise le salariat désigne :","o":["L'obligation pour l'employeur de verser des cotisations sociales","La dépendance économique du salarié à l'égard de ses propres clients","Le pouvoir de l'employeur de donner des ordres et de contrôler le travail","Le droit du salarié à bénéficier d'une formation professionnelle continue"],"c":2,"e":"Le salariat se définit par le lien de subordination : le salarié exécute son travail sous l'autorité de l'employeur, qui peut donner des directives, en contrôler l'exécution et sanctionner."},{"q":"Le toyotisme se distingue du fordisme notamment par :","o":["Le travail à la chaîne et la production de masse standardisée","La production en flux tendus (« juste-à-temps ») et la qualité totale","La séparation stricte entre la conception et l'exécution des tâches","La hausse des salaires indexée sur les gains de productivité réalisés"],"c":1,"e":"Le toyotisme (post-fordisme japonais) repose sur le « juste-à-temps » (zéro stock), la qualité totale, la polyvalence et l'implication des salariés, en rupture avec la rigidité fordiste."},{"q":"L'individualisation de la relation salariale se manifeste notamment par :","o":["La généralisation des conventions collectives négociées au niveau de chaque branche professionnelle","Le développement de la rémunération au mérite et des objectifs individuels","Le renforcement des solidarités syndicales au sein des entreprises","L'uniformisation des grilles de salaire pour tous les salariés"],"c":1,"e":"L'individualisation passe par les primes au mérite, les entretiens individuels et les objectifs personnalisés, qui tendent à affaiblir le collectif de travail."},{"q":"Pour Durkheim, la division du travail social remplit avant tout une fonction :","o":["De maximisation du profit des entreprises capitalistes","De domination d'une classe sociale sur une autre","D'intégration et de cohésion sociale","De réduction du temps de travail des salariés"],"c":2,"e":"Chez Durkheim, la division du travail produit de l'interdépendance entre individus : sa fonction principale est d'assurer la solidarité et la cohésion sociale, pas seulement l'efficacité économique."},{"q":"La précarité de l'emploi peut affaiblir l'intégration sociale par le travail parce qu'elle :","o":["Fragilise le revenu, le statut et les liens stables que procure l'emploi","Augmente toujours le pouvoir d'achat de l'ensemble des salariés concernés par ces contrats","Renforce systématiquement l'engagement syndical des travailleurs","Garantit une protection sociale plus complète aux personnes"],"c":0,"e":"Le travail intègre par le revenu, le statut et les liens sociaux ; la précarité (contrats courts, instabilité) fragilise ces trois dimensions et donc le pouvoir intégrateur du travail."},{"q":"Le « cumul des statuts » (être à la fois salarié et indépendant, par exemple) illustre :","o":["La disparition complète et définitive du salariat","Le retour progressif à une situation de plein-emploi","Le brouillage des frontières entre les formes d'emploi","La stricte séparation entre emploi et chômage"],"c":2,"e":"Le développement de formes hybrides (auto-entrepreneur en complément d'un emploi salarié, par exemple) brouille les frontières traditionnelles entre statuts d'emploi."},{"q":"L'essor des plateformes numériques (ubérisation) pose un problème juridique central :","o":["Le calcul précis du temps de pause des travailleurs","La qualification du lien entre la plateforme et le travailleur (salariat ou indépendance ?)","Le montant exact de la TVA applicable aux courses","La localisation effective du siège social du groupe"],"c":1,"e":"Le débat clé de l'ubérisation porte sur la requalification éventuelle des travailleurs « indépendants » des plateformes en salariés, du fait d'une subordination de fait."},{"q":"La « montée en qualification » de la population active désigne :","o":["L'élévation du niveau de formation et de diplôme des travailleurs","La baisse continue du niveau de diplôme moyen des actifs","La diminution progressive du nombre d'emplois qualifiés","Le recul net de la part des cadres dans l'emploi total"],"c":0,"e":"La population active s'est progressivement élevée en qualification : hausse du niveau de diplôme et croissance de la part des emplois qualifiés (cadres, professions intermédiaires)."},{"q":"Le « management participatif » associé au post-taylorisme vise à :","o":["Renforcer le contrôle hiérarchique strict de chaque geste productif réalisé par l'ouvrier","Impliquer davantage les salariés dans l'organisation de leur travail","Supprimer toute forme d'autonomie laissée aux équipes de production","Réintroduire la parcellisation maximale des tâches d'exécution"],"c":1,"e":"Le post-taylorisme cherche à mobiliser l'implication des salariés (cercles de qualité, équipes autonomes, suggestions), à rebours de l'organisation taylorienne purement prescriptive."},{"q":"Un salarié à temps partiel qui souhaite travailler davantage et est disponible pour le faire est en situation de :","o":["Chômage au sens du BIT","Inactivité au sens du BIT","Sous-emploi","Halo du chômage"],"c":2,"e":"Le sous-emploi regroupe les personnes en emploi mais travaillant moins qu'elles ne le souhaitent (temps partiel subi) et disponibles pour travailler plus ; elles restent comptées comme « en emploi »."},{"q":"La négociation collective en entreprise débouche principalement sur :","o":["Un décret pris par le gouvernement après consultation","Un jugement rendu par le conseil de prud'hommes compétent","Une décision unilatérale imposée par l'employeur seul","Une convention ou un accord collectif liant employeurs et salariés"],"c":3,"e":"La négociation collective entre représentants des salariés et employeurs aboutit à des accords ou conventions collectives, encadrant salaires et conditions de travail."},{"q":"La diffusion des NTIC dans le travail tend à :","o":["Renforcer le contrôle et l'intensification du travail (reporting, traçabilité)","Supprimer toute forme de contrôle de l'activité des salariés","Réduire systématiquement la charge mentale pesant sur les salariés","Faire disparaître purement et simplement le salariat classique"],"c":0,"e":"Les NTIC permettent un contrôle accru (traçabilité, indicateurs, connexion permanente) et peuvent intensifier le travail, brouillant aussi la frontière travail/hors-travail."},{"q":"La polarisation des emplois fragilise surtout :","o":["Les emplois très qualifiés situés au sommet de la hiérarchie","Les emplois peu qualifiés des services à la personne","Les emplois intermédiaires, en partie automatisables","Les emplois indépendants du secteur agricole traditionnel"],"c":2,"e":"La polarisation décrit la croissance des emplois très qualifiés et des emplois peu qualifiés au détriment des emplois intermédiaires (employés qualifiés, ouvriers qualifiés), plus facilement automatisables."},{"q":"Le « déclassement » sur le marché du travail correspond à :","o":["Changer de région afin de retrouver un emploi","Passer du statut de salarié à celui d'indépendant","Se retrouver au chômage pendant une longue durée","Occuper un emploi inférieur à sa qualification"],"c":3,"e":"Le déclassement désigne le fait d'occuper un poste dont la qualification requise est inférieure au diplôme ou à la qualification que possède l'individu (décalage qualification individu/poste)."},{"q":"Selon Robert Castel, le salariat a longtemps constitué :","o":["Un statut marginal et minoritaire dans la société industrielle","Un support central des protections sociales et de l'intégration","Une simple forme de domination dépourvue de toute contrepartie","Un frein durable à la cohésion de la société moderne"],"c":1,"e":"Pour Castel, la « société salariale » a fait du salariat le socle des protections sociales et de l'intégration ; son effritement nourrit la « désaffiliation »."},{"q":"L'expression « fin du travail » (Rifkin) renvoie à la thèse selon laquelle :","o":["Le travail conserve un rôle central et même croissant","Le chômage disparaîtrait totalement grâce au numérique","Les gains de productivité et l'automatisation réduiraient durablement le volume de travail","Le travail indépendant remplacerait entièrement le salariat"],"c":2,"e":"La thèse de la « fin du travail » soutient que l'automatisation détruirait massivement des emplois ; elle est discutée, car le progrès technique crée aussi de nouveaux emplois."},{"q":"Le travail contribue à la construction de l'identité sociale parce qu'il :","o":["Procure exclusivement un revenu monétaire à l'individu","Confère un statut, un rôle et une reconnaissance sociale","Empêche toute forme de sociabilité hors de l'entreprise","Se réduit à une simple obligation d'ordre juridique"],"c":1,"e":"Au-delà du revenu, le travail confère un statut, une utilité reconnue et des liens : il participe à l'identité et à l'intégration sociale des individus."},{"q":"Le « chômage technologique » désigne les pertes d'emploi dues :","o":["À une insuffisance générale de la demande globale","À une inadéquation géographique entre régions","À une vague de délocalisations vers l'étranger","Au remplacement du travail humain par des machines ou des automatismes"],"c":3,"e":"Le chômage technologique résulte du remplacement du travail humain par le capital technique (machines, automatisation, IA), même si de nouveaux emplois peuvent apparaître ailleurs."}],"vf":[{"s":"La division verticale du travail (Taylor) sépare la conception, confiée au bureau des méthodes, de l'exécution, confiée aux ouvriers.","a":true,"e":"Exact : la division verticale oppose ceux qui pensent le travail (ingénieurs, bureau des méthodes) à ceux qui l'exécutent."},{"s":"La flexibilité externe désigne l'ajustement du volume de main-d'oeuvre par les CDD, l'intérim ou la sous-traitance.","a":true,"e":"Vrai : la flexibilité quantitative externe ajuste les effectifs via l'emploi atypique et l'externalisation, à la différence de la flexibilité interne (polyvalence, horaires)."},{"s":"La qualification du poste et la qualification de l'individu coïncident toujours parfaitement.","a":false,"e":"Faux : elles peuvent diverger, par exemple en cas de déclassement (individu plus qualifié que le poste qu'il occupe)."},{"s":"En France, le taux de syndicalisation des salariés dépasse 50 %.","a":false,"e":"Faux : il est très faible, autour de 10-11 %, l'un des plus bas d'Europe."},{"s":"Le compromis fordiste reposait sur la redistribution des gains de productivité sous forme de hausses de salaire.","a":true,"e":"Vrai : le fordisme lie hausse de la productivité, hausse des salaires et consommation de masse dans un cercle vertueux."},{"s":"Le toyotisme repose sur la production en flux tendus et la recherche de la qualité totale.","a":true,"e":"Vrai : « juste-à-temps », zéro stock, qualité totale et polyvalence caractérisent le toyotisme."},{"s":"La grève est un conflit du travail non reconnu par le droit français.","a":false,"e":"Faux : la grève est un droit à valeur constitutionnelle, encadré par la loi."},{"s":"Pour Georges Friedmann, le travail parcellisé du taylorisme aboutit à un « travail en miettes » déshumanisant.","a":true,"e":"Vrai : Friedmann dénonce la perte de sens et la monotonie engendrées par la parcellisation taylorienne."},{"s":"La tertiarisation correspond au recul de la part des services dans l'emploi.","a":false,"e":"Faux : la tertiarisation est au contraire la montée de la part des services dans l'emploi."},{"s":"Le lien de subordination juridique est ce qui distingue le salarié de l'indépendant.","a":true,"e":"Vrai : le salarié travaille sous l'autorité d'un employeur ; l'indépendant n'a pas de lien de subordination."},{"s":"L'individualisation de la relation salariale (primes au mérite, objectifs personnels) tend à affaiblir le collectif de travail.","a":true,"e":"Vrai : l'individualisation des rémunérations et des objectifs peut éroder les solidarités collectives."},{"s":"Les risques psychosociaux relèvent de l'amélioration des conditions de travail.","a":false,"e":"Faux : les RPS (stress, burn-out, harcèlement) relèvent de la dégradation des conditions de travail."},{"s":"La diffusion des NTIC peut renforcer le contrôle et l'intensification du travail.","a":true,"e":"Vrai : traçabilité, reporting et connexion permanente accroissent le contrôle et peuvent intensifier le travail."},{"s":"L'ubérisation pose la question de la requalification des travailleurs de plateforme en salariés.","a":true,"e":"Vrai : la subordination de fait imposée par certaines plateformes alimente les contentieux en requalification."},{"s":"Pour Durkheim, la division du travail n'a qu'une fonction économique et aucune fonction d'intégration sociale.","a":false,"e":"Faux : Durkheim insiste justement sur la fonction intégratrice (solidarité organique) de la division du travail."}],"trous":[{"t":"La division _____ du travail (Taylor) sépare la conception, confiée aux ingénieurs, de l'exécution, confiée aux ouvriers.","a":"verticale","e":"La division verticale oppose conception et exécution ; la division horizontale parcellise les tâches d'exécution."},{"t":"Georges Friedmann dénonce le « travail en _____ » engendré par la parcellisation taylorienne.","a":"miettes","alt":["miette"],"e":"Le « travail en miettes » désigne l'éclatement du travail en gestes parcellaires vidés de sens."},{"t":"L'ajustement des effectifs par les CDD, l'intérim et la sous-traitance relève de la flexibilité _____.","a":"externe","e":"La flexibilité externe ajuste le volume de main-d'oeuvre ; la flexibilité interne joue sur les salariés en poste."},{"t":"La compétence requise par l'emploi occupé est la qualification du _____, par opposition à la qualification de l'individu.","a":"poste","e":"Qualification du poste = exigences de l'emploi ; qualification de l'individu = diplômes et expérience de la personne."},{"t":"La cessation collective et concertée du travail pour appuyer des revendications est la _____.","a":"grève","alt":["greve"],"e":"La grève est la forme institutionnalisée du conflit du travail, protégée par un droit constitutionnel."},{"t":"La part des salariés adhérant à un syndicat, soit le taux de _____, est en France d'environ 11 %.","a":"syndicalisation","e":"Le taux de syndicalisation français est l'un des plus faibles d'Europe."},{"t":"La montée du poids des services dans l'emploi total est la _____ de l'économie.","a":"tertiarisation","e":"La tertiarisation traduit le déplacement de l'emploi vers le secteur des services."},{"t":"Le pouvoir de l'employeur de donner des ordres et de contrôler le travail définit le lien de _____ propre au salariat.","a":"subordination","e":"Le lien de subordination distingue juridiquement le salarié de l'indépendant."},{"t":"Le travailleur qui exerce à son compte, sans lien de subordination, a le statut d'_____.","a":"indépendant","alt":["independant"],"e":"L'indépendant (non-salarié) assume lui-même le risque économique de son activité."},{"t":"Le post-fordisme japonais fondé sur le flux tendu et la qualité totale est le _____.","a":"toyotisme","e":"Le toyotisme repose sur le « juste-à-temps », la qualité totale et la polyvalence."},{"t":"Le stress, le burn-out et le harcèlement au travail font partie des risques _____ (RPS).","a":"psychosociaux","alt":["psycho-sociaux"],"e":"Les RPS relèvent de la dégradation des conditions de travail et de la santé mentale au travail."},{"t":"La marge de manoeuvre du salarié dans l'organisation de ses tâches est son _____ au travail.","a":"autonomie","e":"L'autonomie est l'un des descripteurs de la qualité de l'emploi retenus par le programme."},{"t":"Le fait d'occuper un emploi inférieur à sa qualification est un _____.","a":"déclassement","alt":["declassement"],"e":"Le déclassement traduit un décalage entre la qualification de l'individu et celle du poste occupé."},{"t":"La rémunération au mérite et les objectifs personnalisés relèvent de l'_____ de la relation salariale.","a":"individualisation","e":"L'individualisation tend à affaiblir les solidarités collectives au profit d'une gestion personnalisée."},{"t":"Le remplacement du travail humain par des machines à l'origine de pertes d'emploi est le chômage _____.","a":"technologique","e":"Le chômage technologique résulte de la substitution du capital au travail, même si de nouveaux emplois peuvent émerger."}]});
  add("socio-engagement", {"qcm":[{"q":"L'effet « de cycle de vie » sur la participation politique signifie que :","o":["les jeunes votent davantage à mesure que l'offre politique se renouvelle","la participation varie selon l'âge atteint, l'insertion sociale élevant le vote avec l'avancée en âge","chaque génération conserve toute sa vie les habitudes acquises dans sa jeunesse","l'engagement dépend uniquement du niveau de diplôme atteint"],"c":1,"e":"L'effet de cycle de vie lie la participation à l'âge : l'insertion sociale (emploi, logement, famille) accroît l'intégration et donc le vote, indépendamment de la génération d'appartenance."},{"q":"Distinguer « effet d'âge » et « effet de génération », c'est :","o":["confondre deux explications équivalentes de l'abstention","opposer l'influence de l'âge atteint à celle de la période de socialisation politique commune à une cohorte","mesurer seulement le poids du diplôme","réduire l'engagement à un choix purement rationnel"],"c":1,"e":"L'effet d'âge renvoie à la position dans le cycle de vie ; l'effet de génération renvoie au contexte historique de socialisation propre à une cohorte, qui marque durablement ses pratiques."},{"q":"Plus le diplôme est élevé, la participation politique conventionnelle tend en général à :","o":["diminuer fortement","rester strictement identique","augmenter","disparaître"],"c":2,"e":"Le diplôme, en élevant la compétence politique et le sentiment d'efficacité, est positivement corrélé à la participation (vote, militantisme, engagement associatif)."},{"q":"Le bénévolat associatif constitue une forme d'engagement parce qu'il :","o":["vise toujours la conquête du pouvoir d'État","est une activité non rémunérée au service d'une cause ou d'un collectif","relève exclusivement du vote","se confond avec le travail salarié"],"c":1,"e":"Le bénévolat est un don de temps non rémunéré au profit d'autrui ou d'une cause ; il participe de l'engagement civique sans recherche de pouvoir ni rémunération."},{"q":"L'engagement politique « en ligne » (pétitions, hashtags, partages) est parfois critiqué sous le terme de :","o":["lobbying","clientélisme","slacktivisme (militantisme de faible coût)","corporatisme"],"c":2,"e":"Le « slacktivisme » désigne un engagement numérique à très faible coût (clic, partage) dont on discute l'efficacité réelle par rapport aux formes plus coûteuses d'action."},{"q":"La professionnalisation de la politique désigne le fait que :","o":["tout citoyen exerce à tour de rôle une fonction élective","l'activité politique devient un métier durable, avec des permanents et des élus qui en vivent","les partis disparaissent au profit des associations","le vote devient obligatoire"],"c":1,"e":"La professionnalisation (analysée à la suite de Weber) renvoie à des individus qui vivent « de » la politique, en faisant une activité rémunérée et durable."},{"q":"Selon Max Weber, vivre « pour » la politique se distingue de vivre « de » la politique en ce que :","o":["le premier en fait sa source de revenu, le second un idéal","le premier en fait un idéal et une vocation, le second sa source de revenu","les deux désignent le bénévolat","aucun des deux ne concerne les élus"],"c":1,"e":"Weber oppose celui qui vit « pour » la politique (vocation, désintéressement matériel) à celui qui en vit « de », en tire ses moyens d'existence."},{"q":"Le « capital militant » désigne :","o":["l'argent investi par les partis dans les campagnes","les savoir-faire, dispositions et réseaux acquis par l'expérience de l'engagement","le patrimoine personnel des élus","le nombre d'adhérents d'un syndicat"],"c":1,"e":"Le capital militant regroupe les compétences, savoir-faire et relations accumulés au fil de l'engagement, réinvestissables dans d'autres espaces (professionnel, associatif)."},{"q":"Les femmes restent globalement, dans les instances dirigeantes des partis et syndicats français :","o":["majoritaires","surreprésentées","sous-représentées malgré les lois sur la parité","absentes de tout engagement"],"c":2,"e":"Malgré la progression de l'engagement féminin et les lois sur la parité, les femmes demeurent sous-représentées aux postes de direction politique et syndicale."},{"q":"Un « bien collectif » (ou bien public) au sens d'Olson se caractérise par :","o":["sa rivalité et son exclusivité","sa non-exclusivité : on ne peut empêcher quiconque d'en profiter","son prix élevé sur le marché","sa rareté absolue"],"c":1,"e":"Un bien collectif est non-exclusif : nul ne peut être écarté de sa jouissance, ce qui fonde la tentation du passager clandestin dans l'action collective."},{"q":"La grille « exit, voice, loyalty » d'Albert Hirschman distingue, face au mécontentement :","o":["voter, s'abstenir, militer","la défection, la prise de parole et la loyauté","l'impôt, la subvention, la norme","le boycott, le buycott, la grève"],"c":1,"e":"Hirschman oppose trois réponses au déclin d'une organisation : « exit » (défection), « voice » (protestation), « loyalty » (loyauté) qui peut retenir l'exit."},{"q":"Le « vote sur enjeu » (issue voting) désigne le fait de voter :","o":["selon l'héritage familial transmis","en fonction de positions sur des problèmes précis plutôt que d'une fidélité partisane stable","systématiquement pour le sortant","au hasard"],"c":1,"e":"Le vote sur enjeu traduit un électeur qui arbitre selon des thématiques ponctuelles, signe d'un affaiblissement des fidélités partisanes durables."},{"q":"La hausse de l'abstention « intermittente » signifie surtout que :","o":["les mêmes électeurs s'abstiennent toujours à chaque scrutin","de plus en plus d'électeurs votent à certains scrutins seulement, selon les enjeux","l'abstention a totalement disparu","seuls les diplômés s'abstiennent"],"c":1,"e":"L'abstention intermittente désigne des électeurs qui sélectionnent les scrutins auxquels ils participent, par opposition à une abstention systématique et constante."},{"q":"Le taux de syndicalisation en France figure, parmi les pays développés, parmi les :","o":["plus élevés (plus de 50 %)","plus faibles (environ 10 % des salariés)","exactement égaux à la moyenne de l'OCDE","interdits par la loi"],"c":1,"e":"La France a un taux de syndicalisation parmi les plus bas de l'OCDE (environ 10 % des salariés), ce qui n'empêche pas une forte capacité de mobilisation."},{"q":"Un groupe de pression (lobby) agit principalement par :","o":["la présentation de candidats aux élections","l'influence sur les décideurs publics pour défendre des intérêts particuliers","la conquête directe du gouvernement","l'organisation de référendums"],"c":1,"e":"Le groupe de pression cherche à peser sur les décisions publiques en faveur d'intérêts spécifiques, sans viser lui-même l'exercice du pouvoir électif."},{"q":"Les valeurs « post-matérialistes » (Inglehart), associées aux nouveaux mouvements sociaux, privilégient :","o":["la sécurité économique et l'ordre","l'autonomie, la qualité de vie, l'environnement et l'expression de soi","la croissance du PIB avant tout","la défense du salariat industriel"],"c":1,"e":"Inglehart relie l'émergence des NMS à un déplacement vers des valeurs post-matérialistes (épanouissement, écologie, identités) une fois assurés les besoins matériels."},{"q":"La « désaffiliation » des grandes organisations militantes renvoie à :","o":["la croissance continue des adhésions partisanes","le recul des adhésions stables aux partis et syndicats au profit d'engagements plus ponctuels","l'interdiction des associations","l'augmentation du vote obligatoire"],"c":1,"e":"On observe un recul des adhésions durables aux organisations traditionnelles, remplacées par des engagements plus individualisés, ponctuels et à la carte."},{"q":"Le « buycott » (achat militant), à la différence du boycott, consiste à :","o":["refuser d'acheter un produit","acheter délibérément un produit pour soutenir une cause ou un producteur","détruire des marchandises","s'abstenir de consommer"],"c":1,"e":"Le buycott est la face positive de la consommation engagée : on oriente ses achats vers des produits jugés vertueux, là où le boycott consiste à les refuser."},{"q":"L'engagement politique des catégories populaires se traduit plus souvent par :","o":["une surreprésentation dans les directions de partis","une participation conventionnelle (vote, adhésion) en moyenne plus faible et une abstention plus forte","un militantisme exclusivement en ligne","l'absence totale de toute forme d'action"],"c":1,"e":"Les catégories populaires votent et adhèrent en moyenne moins (abstention plus forte), même si elles peuvent s'investir dans des mobilisations spécifiques."},{"q":"La socialisation politique primaire désigne :","o":["l'apprentissage politique à l'âge adulte par le travail","la transmission précoce, par la famille, de dispositions et préférences politiques","la formation reçue dans les partis","le vote du premier scrutin"],"c":1,"e":"La socialisation politique primaire, surtout familiale, façonne dès l'enfance des orientations qui pèsent durablement sur l'engagement futur."},{"q":"Une « association » au sens de l'engagement civique se distingue du parti car elle :","o":["vise la conquête du pouvoir d'État","poursuit un but commun sans nécessairement rechercher le pouvoir politique","est toujours rémunérée","ne regroupe que des élus"],"c":1,"e":"L'association réunit des membres autour d'un projet commun (culturel, sportif, caritatif, civique) sans viser, contrairement au parti, la conquête du pouvoir."},{"q":"La « politisation » d'un individu désigne :","o":["son inscription d'office sur les listes électorales","le processus par lequel il acquiert intérêt et compétences pour la politique","son adhésion obligatoire à un syndicat","la perte de tout intérêt pour la politique"],"c":1,"e":"La politisation est le processus d'acquisition d'un intérêt, de repères et de compétences politiques, condition d'une participation plus active."},{"q":"Selon Daniel Gaxie, la « compétence politique » est inégalement distribuée car elle dépend :","o":["uniquement de l'âge","largement du capital scolaire et culturel, source d'un « cens caché »","du seul revenu","du lieu de résidence exclusivement"],"c":1,"e":"Gaxie parle de « cens caché » : la compétence politique, liée au capital culturel et scolaire, écarte de fait les moins dotés de la participation, sans interdiction formelle."},{"q":"La grève est une forme d'action collective qui relève :","o":["d'un engagement strictement individuel et privé","du répertoire d'action des salariés pour défendre des revendications","du vote conventionnel","de la consommation engagée"],"c":1,"e":"La grève, arrêt collectif et concerté du travail, est une modalité d'action collective protestataire propre au monde du travail."},{"q":"Le « militantisme distancié » ou intermittent se caractérise par :","o":["un engagement total et permanent dans une organisation unique","des engagements ponctuels, multiples et révisables, sans adhésion durable","le refus de toute action","l'adhésion héritée de la famille"],"c":1,"e":"Le militantisme contemporain se fait souvent plus distancié : engagements ponctuels et choisis (causes, pétitions, événements) plutôt qu'adhésion durable et exclusive."},{"q":"L'« incitation sélective négative » d'Olson correspond, par exemple, à :","o":["un avantage matériel offert à tous","une sanction ou pression (mise à l'écart, amende interne) visant les non-participants","une subvention publique universelle","le simple succès de la cause"],"c":1,"e":"Les incitations sélectives négatives sont des sanctions ou pressions réservées à ceux qui ne participent pas, complétant les incitations positives pour lever le paradoxe."},{"q":"La forme d'engagement la plus répandue et la moins coûteuse en démocratie reste :","o":["la grève générale","le vote","l'occupation de locaux","la création d'un parti"],"c":1,"e":"Le vote est la forme de participation la plus massive et la moins coûteuse (en temps et en risque) ; les formes protestataires sont plus exigeantes."},{"q":"Un « répertoire » contemporain s'enrichit notamment de :","o":["la disparition de toute manifestation","l'usage des réseaux sociaux et des mobilisations numériques","l'interdiction du boycott","le retour exclusif aux émeutes de subsistance"],"c":1,"e":"Le répertoire d'action se transforme : aux formes classiques (manifestation, grève, pétition) s'ajoutent les mobilisations en ligne et virales."},{"q":"L'intégration sociale élevée (emploi stable, insertion associative) tend, sur la participation politique, à :","o":["la faire reculer","la favoriser","n'avoir aucun effet","la rendre obligatoire"],"c":1,"e":"Plus l'intégration sociale est forte, plus la probabilité de participer est élevée : l'inscription dans des réseaux nourrit le sentiment d'appartenance et l'engagement."},{"q":"La « clôture » d'une mobilisation par les opportunités politiques se produit quand :","o":["le contexte institutionnel devient favorable aux protestataires","l'État renforce la répression et ferme les canaux d'accès, décourageant l'action","les médias relaient massivement la cause","des alliés influents soutiennent le mouvement"],"c":1,"e":"Une structure des opportunités fermée (répression, accès bloqués, absence d'alliés) freine la mobilisation, à l'inverse d'une structure ouverte qui la facilite."}],"vf":[{"s":"L'effet de cycle de vie et l'effet de génération désignent exactement le même phénomène.","a":false,"e":"L'effet de cycle de vie tient à l'âge atteint (insertion sociale), l'effet de génération à la période de socialisation d'une cohorte : ce sont deux mécanismes distincts."},{"s":"Le bénévolat associatif est une activité non rémunérée au service d'autrui ou d'une cause.","a":true,"e":"Le bénévolat se définit par le don de temps gratuit au profit d'un collectif ou d'une cause, sans rémunération ni lien de subordination."},{"s":"En France, le taux de syndicalisation figure parmi les plus élevés des pays développés.","a":false,"e":"Au contraire, la France a l'un des taux de syndicalisation les plus faibles de l'OCDE (environ 10 % des salariés)."},{"s":"La compétence politique, selon Gaxie, est socialement inégale et liée au capital culturel.","a":true,"e":"Gaxie montre que la compétence politique dépend largement du capital scolaire et culturel, créant un « cens caché » qui écarte les moins dotés."},{"s":"Vivre « de » la politique, au sens de Weber, signifie en faire un idéal désintéressé.","a":false,"e":"Vivre « de » la politique, c'est en tirer ses revenus ; vivre « pour » la politique correspond à la vocation désintéressée."},{"s":"Un groupe de pression cherche à conquérir lui-même le pouvoir d'État par les élections.","a":false,"e":"Le groupe de pression influence les décideurs pour défendre des intérêts ; contrairement au parti, il ne vise pas à exercer lui-même le pouvoir."},{"s":"Les valeurs post-matérialistes (Inglehart) valorisent l'autonomie, l'écologie et la qualité de vie.","a":true,"e":"Inglehart relie les NMS à un déplacement vers des valeurs post-matérialistes une fois les besoins matériels assurés."},{"s":"Le slacktivisme désigne un engagement numérique de faible coût dont l'efficacité est discutée.","a":true,"e":"Le slacktivisme (clic, partage, hashtag) est un militantisme peu coûteux dont on questionne l'impact réel."},{"s":"Plus le niveau de diplôme est élevé, plus la participation politique conventionnelle tend à diminuer.","a":false,"e":"C'est l'inverse : le diplôme élève la compétence et le sentiment d'efficacité, donc accroît la participation."},{"s":"Le buycott (achat militant) consiste à acheter un produit pour soutenir une cause.","a":true,"e":"Le buycott est la version positive de la consommation engagée : orienter ses achats vers des produits jugés vertueux, à l'inverse du boycott."},{"s":"La grille d'Hirschman oppose la défection (exit), la prise de parole (voice) et la loyauté (loyalty).","a":true,"e":"Hirschman distingue trois réponses au mécontentement : partir (exit), protester (voice) ou rester fidèle (loyalty)."},{"s":"Les femmes sont aujourd'hui majoritaires aux postes de direction des grands partis français.","a":false,"e":"Malgré la parité, les femmes restent sous-représentées dans les directions partisanes et syndicales."},{"s":"L'abstention intermittente désigne des électeurs qui ne votent qu'à certains scrutins selon les enjeux.","a":true,"e":"L'abstention intermittente s'oppose à l'abstention systématique : l'électeur sélectionne les scrutins auxquels il participe."},{"s":"La socialisation politique primaire, notamment familiale, n'a aucun effet sur l'engagement adulte.","a":false,"e":"La socialisation primaire transmet tôt des dispositions politiques qui pèsent durablement sur les pratiques et l'engagement à l'âge adulte."},{"s":"Le capital militant regroupe les savoir-faire et réseaux acquis au cours de l'engagement.","a":true,"e":"Le capital militant désigne les compétences, dispositions et relations accumulées par l'expérience militante, réinvestissables ailleurs."}],"trous":[{"t":"L'effet de _____ de vie lie la participation à l'âge atteint et à l'insertion sociale croissante.","a":"cycle","e":"L'effet de cycle de vie explique la hausse du vote avec l'avancée en âge par l'intégration sociale (emploi, famille, logement)."},{"t":"Une cohorte marquée durablement par le contexte de sa jeunesse illustre l'effet de _____.","a":"génération","e":"L'effet de génération renvoie à la socialisation politique propre à une cohorte, qui imprime des pratiques durables."},{"t":"L'activité non rémunérée au service d'une cause ou d'un collectif est le _____.","a":"bénévolat","e":"Le bénévolat est un don de temps gratuit au profit d'autrui ou d'une cause, sans rémunération."},{"t":"Daniel Gaxie nomme « cens _____ » le fait que la compétence politique inégale écarte de fait les moins dotés.","a":"caché","e":"Le « cens caché » de Gaxie : sans interdiction formelle, l'inégale compétence politique liée au capital culturel exclut les moins diplômés."},{"t":"Selon Weber, celui qui tire ses revenus de l'activité politique vit _____ la politique.","a":"de","e":"Weber oppose vivre « de » la politique (source de revenu) à vivre « pour » la politique (vocation désintéressée)."},{"t":"Un groupe organisé qui influence les décideurs publics sans viser le pouvoir est un groupe de _____.","a":"pression","alt":["intérêt"],"e":"Le groupe de pression (lobby) défend des intérêts en pesant sur la décision publique, sans chercher à exercer lui-même le pouvoir."},{"t":"Les valeurs _____, selon Inglehart, valorisent l'autonomie, l'écologie et la qualité de vie.","a":"post-matérialistes","alt":["postmatérialistes","post matérialistes"],"e":"Inglehart relie les nouveaux mouvements sociaux à l'essor de valeurs post-matérialistes après la satisfaction des besoins matériels."},{"t":"L'engagement numérique de faible coût (clic, partage), à l'efficacité discutée, est appelé _____.","a":"slacktivisme","e":"Le slacktivisme désigne un militantisme en ligne peu coûteux dont on questionne l'impact réel."},{"t":"Acheter délibérément un produit pour soutenir une cause s'appelle le _____.","a":"buycott","e":"Le buycott est la face positive de la consommation engagée, par opposition au boycott qui consiste à refuser d'acheter."},{"t":"Hirschman oppose la défection (exit), la prise de parole (_____) et la loyauté.","a":"voice","e":"Dans la grille d'Hirschman, « voice » désigne la prise de parole protestataire, entre « exit » (défection) et « loyalty » (loyauté)."},{"t":"Les savoir-faire et réseaux acquis par l'expérience de l'engagement forment le capital _____.","a":"militant","e":"Le capital militant regroupe les compétences, dispositions et relations accumulées au fil de l'engagement."},{"t":"L'arrêt collectif et concerté du travail pour défendre des revendications est la _____.","a":"grève","e":"La grève est une modalité protestataire d'action collective propre au monde du travail."},{"t":"L'électeur qui ne vote qu'à certains scrutins selon les enjeux pratique une abstention _____.","a":"intermittente","e":"L'abstention intermittente s'oppose à l'abstention systématique : participation sélective selon les scrutins."},{"t":"La transmission précoce de dispositions politiques par la famille relève de la socialisation politique _____.","a":"primaire","e":"La socialisation politique primaire, surtout familiale, façonne dès l'enfance des orientations durables."},{"t":"Le processus d'acquisition d'un intérêt et de compétences pour la politique est la _____.","a":"politisation","e":"La politisation est le processus par lequel un individu acquiert intérêt, repères et compétences politiques."}]});
  add("rc-justice", {"qcm":[{"q":"Dans la « position originelle » de Rawls, les individus choisissent les principes de justice :","o":["derrière un « voile d'ignorance » sur leur place future","en connaissant parfaitement leur futur rang social","en votant à la majorité simple","selon l'intérêt de la classe dominante"],"c":0,"e":"Le voile d'ignorance prive les individus de toute information sur leur position sociale future, ce qui les pousse à choisir des principes impartiaux."},{"q":"Le premier principe de justice de Rawls porte sur :","o":["l'égalité des revenus","l'égale liberté pour tous","la propriété privée des moyens de production","le plein-emploi"],"c":1,"e":"Rawls pose d'abord un principe d'égale liberté (libertés de base identiques pour tous), prioritaire sur le principe de différence."},{"q":"Selon le principe de différence de Rawls, les inégalités sont acceptables si elles sont attachées à des positions ouvertes à tous dans des conditions :","o":["d'une stricte égalité des situations garantie par l'État","de loterie sociale","d'équité dans l'égalité des chances","de stricte uniformité"],"c":2,"e":"Le second principe associe le principe de différence à l'égalité équitable des chances : les positions doivent être accessibles à tous."},{"q":"Pour les utilitaristes, transférer un euro d'un riche à un pauvre peut accroître l'utilité collective en raison :","o":["de l'effet de levier financier des ménages aisés","du multiplicateur keynésien","de la courbe de Lorenz","de l'utilité marginale décroissante du revenu"],"c":3,"e":"Un euro procure plus d'utilité à un pauvre qu'à un riche (utilité marginale décroissante) : la redistribution peut donc augmenter l'utilité totale."},{"q":"Pour Nozick, une distribution des richesses est juste si :","o":["elle résulte d'acquisitions et de transferts légitimes","elle réduit autoritairement l'écart entre les riches et les pauvres","elle maximise le bien-être des plus pauvres","elle égalise les patrimoines"],"c":0,"e":"La théorie de l'habilitation (entitlement) de Nozick juge juste toute distribution issue d'appropriations et d'échanges libres et légitimes, quel que soit le résultat."},{"q":"L'approche de Sen déplace l'attention des ressources possédées vers :","o":["le revenu monétaire disponible brut perçu par le ménage","la liberté réelle de mener la vie qu'on a raison de valoriser","la somme des utilités","le patrimoine net"],"c":1,"e":"Sen juge la justice à l'aune des capabilités, c'est-à-dire des libertés réelles de réaliser différents modes de vie, et pas seulement des ressources détenues."},{"q":"Un impôt est dit progressif lorsque :","o":["tout le monde paie le même montant","son taux est constant quel que soit le revenu","son taux moyen augmente avec le revenu","il frappe surtout la consommation"],"c":2,"e":"Dans un impôt progressif, le taux moyen croît avec le revenu (ex. impôt sur le revenu), ce qui réduit les écarts de revenu disponible."},{"q":"La TVA est souvent qualifiée d'impôt régressif car :","o":["son taux baisse quand on consomme plus","elle ne frappe que les ménages aisés","son taux augmente avec le revenu","elle pèse proportionnellement plus sur les bas revenus"],"c":3,"e":"Les ménages modestes consomment une part plus élevée de leur revenu : la TVA, à taux uniforme, ampute donc relativement davantage leur revenu."},{"q":"La redistribution horizontale consiste à :","o":["opérer des transferts entre individus exposés à un même risque (maladie, vieillesse)","prélever sur les riches pour donner aux pauvres","aligner tous les revenus","supprimer l'impôt sur le patrimoine"],"c":0,"e":"La redistribution horizontale couvre des risques (santé, retraite, chômage) par mutualisation, indépendamment du niveau de revenu, contrairement à la redistribution verticale."},{"q":"La logique d'assurance de la protection sociale se distingue de la logique d'assistance car :","o":["elle est financée par l'impôt et versée sans aucune condition","les prestations sont liées à des cotisations versées","elle ne concerne que les plus pauvres","elle est entièrement privée"],"c":1,"e":"L'assurance ouvre des droits en contrepartie de cotisations (logique bismarckienne) ; l'assistance verse des prestations sous condition de ressources, financées par l'impôt."},{"q":"Le RSA relève d'une logique :","o":["d'assurance contributive ouvrant des droits par cotisations","de redistribution horizontale","d'assistance sous condition de ressources","de services collectifs"],"c":2,"e":"Le RSA est une prestation d'assistance, versée sous condition de ressources et financée par l'impôt, sans contrepartie de cotisations."},{"q":"Les services collectifs (école, hôpital publics) réduisent les inégalités par :","o":["une redistribution monétaire directe","la baisse des cotisations","la progressivité de la TVA","une redistribution en nature"],"c":3,"e":"L'accès quasi gratuit à des services finance une redistribution « en nature » qui profite relativement plus aux ménages modestes."},{"q":"Dans la typologie d'Esping-Andersen, le régime « social-démocrate » (pays nordiques) se caractérise par :","o":["des prestations minimales sous conditions de ressources","des droits universels et un haut niveau de démarchandisation","une protection liée au seul emploi","l'absence d'État-providence"],"c":1,"e":"Le régime social-démocrate offre des prestations universelles et généreuses, forte démarchandisation, financées par l'impôt."},{"q":"Le régime « libéral » d'État-providence (Esping-Andersen) repose surtout sur :","o":["des assurances liées au travail","l'universalité des droits","des prestations ciblées sous condition de ressources et le marché","la cogestion par les syndicats"],"c":2,"e":"Le régime libéral (ex. États-Unis) privilégie des aides résiduelles sous condition de ressources et laisse une large place au marché privé."},{"q":"Le régime « conservateur-corporatiste » (Esping-Andersen) lie principalement les droits sociaux :","o":["à la seule citoyenneté, indépendamment de l'emploi","au seuil de pauvreté","au patrimoine détenu","au statut professionnel et aux cotisations"],"c":3,"e":"Le régime conservateur (ex. Allemagne, France) repose sur des assurances sociales liées à l'emploi et au statut professionnel."},{"q":"Le « plafond de verre » désigne :","o":["l'ensemble des obstacles invisibles freinant l'accès des femmes aux postes élevés","un seuil de revenu au-delà duquel l'impôt est nul","la limite des prestations sociales","le plafond de la Sécurité sociale"],"c":0,"e":"Le plafond de verre renvoie aux barrières informelles qui empêchent les femmes (ou des minorités) d'accéder aux plus hautes responsabilités."},{"q":"L'égalité formelle se distingue de l'égalité réelle en ce qu'elle :","o":["garantit des résultats identiques","proclame des droits identiques en droit, sans garantir l'égalité effective","supprime les inégalités de patrimoine","impose des quotas"],"c":1,"e":"L'égalité formelle (de droit) reconnaît à tous les mêmes droits ; l'égalité réelle vise leur exercice effectif, qui suppose souvent une intervention publique."},{"q":"Une « trappe à inactivité » désigne une situation où :","o":["les inactifs sont exclus de toute aide","l'impôt devient progressif","reprendre un emploi rapporte peu une fois les aides perdues","les cotisations financent les retraites"],"c":2,"e":"Quand le gain net d'un retour à l'emploi est faible (perte de prestations + frais), la redistribution peut désinciter au travail : c'est un effet pervers discuté."},{"q":"Le « top 1 % » mobilisé pour mesurer les inégalités correspond à :","o":["le taux marginal d'imposition appliqué à la dernière tranche de revenu","le seuil de pauvreté","le rapport D9/D1","la part du revenu ou du patrimoine détenue par le centile le plus riche"],"c":3,"e":"La part détenue par le 1 % le plus riche (travaux de Piketty) éclaire la concentration au sommet, que le Gini perçoit mal."},{"q":"Les inégalités de patrimoine, en France, sont généralement :","o":["plus fortes que les inégalités de revenu","plus faibles que les inégalités de revenu","du même ordre que les inégalités de revenu","nulles"],"c":0,"e":"Le patrimoine est nettement plus concentré que le revenu, du fait notamment de l'accumulation et de la transmission héréditaire."},{"q":"Le « consentement à l'impôt » est une notion clé car la redistribution suppose :","o":["une croissance forte","l'acceptation sociale des prélèvements","la suppression des services collectifs","l'absence de cotisations"],"c":1,"e":"La légitimité et la soutenabilité de la redistribution reposent sur l'adhésion des contribuables au prélèvement."},{"q":"Le revenu disponible d'un ménage est obtenu :","o":["en additionnant tous les revenus primaires bruts","avant tout impôt","après prélèvements obligatoires et ajout des prestations sociales","en ne comptant que les salaires"],"c":2,"e":"Le revenu disponible = revenus primaires − prélèvements + prestations (transferts) : il intègre l'effet de la redistribution."},{"q":"Selon Rawls, le principe de différence donne la priorité à l'amélioration de la situation :","o":["des classes moyennes salariées","des détenteurs de capital productif","de la majorité","des plus défavorisés (maximin)"],"c":3,"e":"Le principe de différence suit une logique de maximin : maximiser le sort du groupe le plus désavantagé."},{"q":"Une critique libertarienne classique de la redistribution est qu'elle :","o":["porte atteinte aux droits de propriété légitimement acquis","accroît trop les libertés individuelles","ne profite jamais aux pauvres","supprime le marché"],"c":0,"e":"Pour Nozick, prélever par l'impôt pour redistribuer revient à disposer du travail d'autrui sans son consentement, ce qui viole les droits individuels."},{"q":"La méritocratie, comme idéal de justice, valorise une distribution fondée sur :","o":["le hasard de la naissance et l'origine sociale","le talent et l'effort individuels","l'égalité stricte des résultats","l'ancienneté seule"],"c":1,"e":"La méritocratie justifie les inégalités issues du mérite (talent + effort), à condition d'une réelle égalité des chances au départ."},{"q":"Les cotisations sociales se distinguent des impôts car elles :","o":["financent le budget général de l'État sans affectation précise","sont toujours progressives","ouvrent des droits à prestations (retraite, santé)","sont versées par les seuls ménages pauvres"],"c":2,"e":"Les cotisations, prélevées sur les salaires, financent la protection sociale contributive et ouvrent des droits, contrairement à l'impôt non affecté."},{"q":"L'expression « inégalités multiformes et cumulatives » souligne que :","o":["les inégalités se compensent toujours","seul le revenu compte","les inégalités sont temporaires","des désavantages dans plusieurs domaines se renforcent mutuellement"],"c":3,"e":"Les inégalités touchent de multiples dimensions (revenu, école, santé, logement) qui souvent se cumulent et s'auto-renforcent."},{"q":"Pour Amartya Sen, deux personnes au même revenu peuvent avoir des libertés réelles très différentes à cause :","o":["de facteurs de conversion (handicap, âge, environnement)","du seul taux marginal d'imposition sur le revenu","de la TVA","du coefficient de Gini"],"c":0,"e":"Les facteurs de conversion font qu'un même revenu n'offre pas les mêmes capabilités : un handicap, par exemple, exige plus de ressources pour un même niveau de vie."},{"q":"L'impôt proportionnel se caractérise par :","o":["un taux qui augmente avec l'assiette imposable du contribuable","un montant forfaitaire identique pour tous","un taux unique appliqué à tous les niveaux de revenu","une exonération des hauts revenus"],"c":2,"e":"L'impôt proportionnel applique un taux constant : il ne modifie pas, en lui-même, la hiérarchie des revenus relatifs (ex. CSG)."}],"vf":[{"s":"Derrière le voile d'ignorance, les individus connaissent leurs talents mais pas leur fortune.","a":false,"e":"Le voile d'ignorance masque aussi bien la position sociale que les talents et la conception du bien : les individus ignorent tout de leur situation future."},{"s":"Le principe de différence de Rawls admet des inégalités si elles profitent aux plus défavorisés.","a":true,"e":"C'est la définition même du principe de différence : les inégalités ne sont justes que si elles améliorent le sort des plus désavantagés."},{"s":"Pour Nozick, la redistribution par l'impôt est un instrument légitime de justice sociale.","a":false,"e":"Les libertariens comme Nozick considèrent la redistribution forcée comme une atteinte aux droits de propriété : seule la justice des procédures compte."},{"s":"L'approche par les capabilités de Sen se limite à mesurer le revenu monétaire.","a":false,"e":"Sen critique justement l'approche par le seul revenu : il évalue les libertés réelles (capabilités) de mener différentes vies."},{"s":"Un impôt progressif réduit davantage les inégalités qu'un impôt proportionnel de même rendement.","a":true,"e":"La progressivité prélève proportionnellement plus sur les hauts revenus, réduisant donc plus les écarts de revenu disponible."},{"s":"La logique d'assurance ouvre des droits en contrepartie de cotisations.","a":true,"e":"L'assurance sociale (logique bismarckienne) lie les prestations aux cotisations versées, contrairement à l'assistance."},{"s":"La redistribution horizontale transfère des riches vers les pauvres.","a":false,"e":"C'est la redistribution verticale qui réduit l'écart riches/pauvres ; l'horizontale couvre des risques entre individus, quel que soit leur revenu."},{"s":"Les services collectifs constituent une forme de redistribution en nature.","a":true,"e":"L'accès gratuit ou quasi gratuit à l'école, à la santé publique, etc. transfère du pouvoir d'achat réel, surtout aux ménages modestes."},{"s":"La discrimination positive vise l'égalité réelle des chances, pas seulement formelle.","a":true,"e":"En accordant un traitement préférentiel temporaire, elle compense des handicaps de départ pour rendre effective l'égalité des chances."},{"s":"Selon Esping-Andersen, il existe un seul modèle universel d'État-providence.","a":false,"e":"Esping-Andersen distingue trois régimes : libéral, conservateur-corporatiste et social-démocrate."},{"s":"Le plafond de verre illustre une inégalité réelle malgré une égalité formelle des droits.","a":true,"e":"Les femmes ont les mêmes droits formels mais se heurtent à des obstacles invisibles : l'égalité de droit ne suffit pas à l'égalité réelle."},{"s":"Les inégalités de patrimoine sont en général plus fortes que les inégalités de revenu.","a":true,"e":"Le patrimoine, accumulé et hérité, est nettement plus concentré que le revenu."},{"s":"La TVA est un impôt progressif favorable aux ménages modestes.","a":false,"e":"La TVA est régressive : elle pèse relativement plus sur les bas revenus, qui consomment une plus grande part de leur revenu."},{"s":"Une « trappe à inactivité » peut résulter d'un faible gain net au retour à l'emploi.","a":true,"e":"Si la reprise d'un emploi entraîne la perte d'aides et des frais, le gain net devient faible : c'est un effet pervers possible de la redistribution."},{"s":"Pour l'utilitarisme, ce qui importe est la somme totale des utilités, pas sa répartition entre individus.","a":true,"e":"L'utilitarisme classique (Bentham) maximise le bonheur agrégé ; il ne se soucie pas en soi de la manière dont les utilités sont réparties."}],"trous":[{"t":"Chez Rawls, le dispositif qui prive les individus de toute information sur leur position future est le voile d'_____.","a":"ignorance","e":"Le voile d'ignorance garantit l'impartialité du choix des principes de justice dans la position originelle."},{"t":"La théorie de la justice de Nozick, fondée sur la légitimité des acquisitions et des transferts, est le _____.","a":"libertarisme","alt":["libertarianisme"],"e":"Le libertarisme juge une distribution juste si elle résulte de procédures légitimes, sans considérer le résultat."},{"t":"L'approche d'Amartya Sen évalue la justice selon les libertés réelles appelées les _____.","a":"capabilités","alt":["capabilites","capacités"],"e":"Les capabilités sont les libertés réelles de réaliser différents modes de vie que l'on a raison de valoriser."},{"t":"Un impôt dont le taux moyen croît avec le revenu est dit _____.","a":"progressif","e":"La progressivité de l'impôt est un levier de réduction des inégalités de revenu disponible."},{"t":"Un impôt à taux unique, identique quel que soit le revenu, est dit _____.","a":"proportionnel","e":"L'impôt proportionnel (ex. CSG) applique le même taux à tous et ne modifie pas les écarts relatifs de revenu."},{"t":"La redistribution qui transfère des plus aisés vers les plus modestes est dite _____.","a":"verticale","e":"La redistribution verticale réduit les écarts de revenu, par opposition à la redistribution horizontale qui couvre des risques."},{"t":"La redistribution qui opère entre individus exposés à un même risque, sans tenir compte du revenu, est dite _____.","a":"horizontale","e":"La redistribution horizontale mutualise des risques (maladie, vieillesse) indépendamment du niveau de revenu."},{"t":"La logique de protection sociale liée aux cotisations et ouvrant des droits est la logique d'_____.","a":"assurance","e":"La logique assurantielle (bismarckienne) lie prestations et cotisations, à la différence de l'assistance."},{"t":"La logique de prestations versées sous condition de ressources et financées par l'impôt est la logique d'_____.","a":"assistance","e":"L'assistance (ex. RSA) vise les plus démunis sous condition de ressources, sans contrepartie contributive."},{"t":"L'accès gratuit à l'école et à l'hôpital publics relève d'une redistribution en _____.","a":"nature","e":"Les services collectifs procurent une redistribution en nature qui profite surtout aux ménages modestes."},{"t":"Accorder un traitement préférentiel temporaire à un groupe défavorisé pour viser l'égalité réelle, c'est la discrimination _____.","a":"positive","e":"La discrimination positive compense des inégalités de départ pour rendre effective l'égalité des chances."},{"t":"Le sociologue qui distingue trois régimes d'État-providence (libéral, conservateur, social-démocrate) est _____.","a":"Esping-Andersen","alt":["Esping Andersen"],"e":"Esping-Andersen a construit une typologie des États-providence selon leur degré de démarchandisation."},{"t":"L'ensemble des obstacles invisibles freinant l'accès des femmes aux postes les plus élevés est le plafond de _____.","a":"verre","e":"Le plafond de verre illustre une inégalité réelle persistante malgré l'égalité formelle des droits."},{"t":"Proclamer les mêmes droits pour tous en droit, sans en garantir l'exercice effectif, relève de l'égalité _____.","a":"formelle","e":"L'égalité formelle s'oppose à l'égalité réelle, qui suppose l'égalité effective des conditions d'exercice des droits."},{"t":"L'utilitarisme de Bentham juge une société juste si elle maximise la somme des _____.","a":"utilités","alt":["utilité"],"e":"L'utilitarisme classique vise le plus grand bonheur agrégé, sans se soucier en soi de sa répartition."}]});
  add("rc-environnement", {"qcm":[{"q":"Le coût supporté uniquement par le producteur d'un bien est appelé :","o":["coût social","coût privé","coût externe","coût marginal collectif"],"c":1,"e":"Le coût privé est celui que l'agent supporte directement ; le coût social ajoute les externalités subies par les tiers."},{"q":"Lorsqu'il existe une externalité négative, on a la relation :","o":["coût social = coût privé","coût social < coût privé","coût social > coût privé","coût privé = coût marginal nul"],"c":2,"e":"L'externalité négative ajoute un coût pour la collectivité : le coût social dépasse le coût privé, d'où une surproduction par rapport à l'optimum."},{"q":"La taxe carbone agit principalement en :","o":["interdisant purement et simplement les énergies fossiles","modifiant le prix relatif des biens polluants pour réorienter les comportements","distribuant gratuitement des droits à polluer aux entreprises","fixant un plafond global négocié chaque année"],"c":1,"e":"La taxe carbone renchérit le carbone : elle agit par le signal-prix, incitant producteurs et consommateurs à réduire leurs émissions."},{"q":"Selon le théorème de Coase, une externalité peut être réglée sans intervention de l'État si :","o":["l'État fixe une taxe optimale","les droits de propriété sont définis et les coûts de transaction faibles","on crée un marché de quotas mondial","le pollueur est nationalisé"],"c":1,"e":"Coase montre que des agents peuvent négocier et internaliser l'externalité dès lors que les droits de propriété sont clairs et les coûts de transaction faibles."},{"q":"Le rapport Brundtland (1987) définit le développement durable comme un développement qui :","o":["maximise la croissance du PIB à court terme","répond aux besoins du présent sans compromettre ceux des générations futures","supprime toute activité industrielle polluante","repose uniquement sur le pilier environnemental"],"c":1,"e":"La définition canonique de Brundtland insiste sur l'équité intergénérationnelle : satisfaire les besoins présents sans compromettre ceux des générations futures."},{"q":"La soutenabilité « forte » se distingue de la soutenabilité « faible » car elle suppose que :","o":["le capital naturel est entièrement substituable par du capital technique","certains éléments du capital naturel sont irremplaçables et doivent être préservés","seule la croissance économique compte","la pollution n'a aucun coût"],"c":1,"e":"La soutenabilité forte considère le capital naturel comme non substituable (critique) ; la soutenabilité faible admet sa substitution par du capital produit."},{"q":"Le GIEC est :","o":["un marché international de quotas carbone","un groupe d'experts qui synthétise l'état des connaissances scientifiques sur le climat","une ONG militante qui organise les COP","une taxe mondiale sur les émissions"],"c":1,"e":"Le GIEC (Groupe d'experts intergouvernemental sur l'évolution du climat) produit des rapports de synthèse ; il joue le rôle d'expert dans la construction du problème public climatique."},{"q":"L'Accord de Paris (COP21, 2015) a notamment fixé l'objectif de :","o":["limiter le réchauffement bien en dessous de 2 °C","interdire toute émission de CO₂ dès 2020","créer une taxe carbone mondiale unique","supprimer le GIEC"],"c":0,"e":"L'Accord de Paris vise à contenir le réchauffement nettement sous 2 °C, en poursuivant les efforts pour le limiter à 1,5 °C."},{"q":"Contrairement à un bien commun, un bien public pur est :","o":["rival et exclusif","non rival et non exclusif","rival et non exclusif","exclusif et payant"],"c":1,"e":"Le bien public pur est non rival et non exclusif ; le bien commun est non exclusif mais rival (d'où le risque de surexploitation)."},{"q":"Le « double dividende » d'une taxe environnementale désigne le fait qu'elle peut :","o":["réduire la pollution et, via son produit, financer une baisse d'autres prélèvements","doubler automatiquement les émissions de CO₂","être versée deux fois aux entreprises","supprimer le besoin de toute réglementation"],"c":0,"e":"Le double dividende : la taxe réduit la pollution (1er dividende) et son produit peut alléger d'autres impôts ou financer la transition (2e dividende)."},{"q":"Une limite fréquemment opposée à la taxe carbone est :","o":["son absence totale d'effet sur les prix","son caractère potentiellement régressif, pesant plus sur les ménages modestes","l'impossibilité de la mettre en œuvre techniquement","qu'elle interdit la consommation d'énergie"],"c":1,"e":"La taxe carbone est souvent jugée régressive : à consommation énergétique comparable, elle pèse proportionnellement davantage sur les ménages modestes (cf. contestations type gilets jaunes)."},{"q":"Un avantage du marché de quotas par rapport à la taxe est :","o":["il garantit la quantité totale d'émissions via le plafond fixé","il garantit à l'avance le prix du carbone","il supprime toute incitation à innover","il ne nécessite aucune autorité publique"],"c":0,"e":"Le marché de quotas fixe la quantité (le plafond) et laisse le prix s'ajuster ; la taxe fixe le prix et laisse la quantité s'ajuster."},{"q":"Le « principe de précaution » consiste à :","o":["agir seulement une fois le dommage scientifiquement certain","prendre des mesures préventives malgré une incertitude scientifique sur un risque grave","réparer les dommages après qu'ils sont survenus","laisser le marché corriger les risques"],"c":1,"e":"Le principe de précaution autorise (voire impose) l'action préventive face à un risque grave et irréversible même en l'absence de certitude scientifique complète."},{"q":"Le « principe de prévention » se distingue du principe de précaution car il s'applique à des risques :","o":["incertains et hypothétiques","avérés et identifiés","inexistants","sans aucun coût"],"c":1,"e":"La prévention vise des risques connus et avérés ; la précaution vise des risques incertains mais potentiellement graves."},{"q":"Le SEQE-UE (marché européen du carbone) fonctionne selon le principe :","o":["d'une taxe uniforme par tonne","du « cap-and-trade » : plafonnement puis échange de quotas","de la subvention directe aux énergies fossiles","de l'interdiction de toute émission"],"c":1,"e":"Le SEQE-UE est un système de plafonnement et d'échange (cap-and-trade) : un plafond décroissant d'émissions et des quotas échangeables."},{"q":"« Internaliser » une externalité négative signifie :","o":["l'ignorer dans les décisions économiques","intégrer son coût dans le prix payé par l'agent qui la génère","la transférer entièrement à l'État","la rendre non rivale"],"c":1,"e":"Internaliser, c'est faire en sorte que le coût externe soit pris en compte par l'agent (par une taxe, un quota, etc.), rapprochant coût privé et coût social."},{"q":"Une critique adressée au PIB comme indicateur face aux enjeux environnementaux est qu'il :","o":["mesure trop bien le capital naturel","ne déduit pas la dégradation de l'environnement et peut compter la pollution comme activité","intègre parfaitement le bien-être","est calculé par le GIEC"],"c":1,"e":"Le PIB ignore l'épuisement du capital naturel et peut même croître avec des dépenses de réparation des dommages ; d'où des indicateurs alternatifs (empreinte écologique, PIB vert)."},{"q":"L'« effet rebond » désigne le fait que :","o":["une norme est toujours respectée","des gains d'efficacité énergétique sont en partie annulés par une hausse de la consommation","la taxe carbone double les émissions","les quotas s'échangent à un prix nul"],"c":1,"e":"L'effet rebond : les économies d'énergie permises par une technologie plus efficace sont partiellement compensées par une consommation accrue."},{"q":"Parmi ces acteurs, lequel relève des « pouvoirs publics » dans l'action environnementale ?","o":["Greenpeace","l'Union européenne","une entreprise pétrolière","le GIEC"],"c":1,"e":"L'UE, l'État et les collectivités sont des pouvoirs publics ; les ONG, entreprises et experts sont d'autres catégories d'acteurs."},{"q":"Les mouvements citoyens et ONG environnementales agissent surtout en :","o":["fixant eux-mêmes les taxes","exerçant une pression et en participant à la mise à l'agenda des problèmes","émettant des quotas carbone","remplaçant le GIEC"],"c":1,"e":"ONG et mouvements citoyens font du lobbying, alertent l'opinion et participent à la construction et à la mise à l'agenda des problèmes publics."},{"q":"Une limite de la réglementation (normes, interdictions) par rapport aux instruments économiques est :","o":["elle laisse toujours le choix du moyen le moins coûteux","elle est uniforme et n'incite pas à réduire la pollution au-delà du seuil fixé","elle rapporte des recettes à l'État","elle fixe un prix du carbone"],"c":1,"e":"La norme impose un seuil uniforme : elle n'incite pas à faire mieux que la limite ni à le faire au moindre coût, contrairement à la taxe ou au quota."},{"q":"Le caractère « rival » d'un bien commun signifie que :","o":["personne ne peut être exclu de son usage","la consommation par l'un réduit ce qui reste disponible pour les autres","son usage est gratuit et illimité","il est produit par l'État"],"c":1,"e":"La rivalité implique que l'usage par un agent diminue la quantité disponible pour les autres, d'où le risque de surexploitation des communs."},{"q":"Pour Ostrom, la préservation durable d'un bien commun repose surtout sur :","o":["la seule privatisation","des règles collectives et des dispositifs de gouvernance locale","l'absence de toute règle","la seule nationalisation"],"c":1,"e":"Ostrom montre que des communautés peuvent gérer durablement les communs par des règles auto-organisées, sans recourir nécessairement au marché ou à l'État."},{"q":"Un marché de quotas où le plafond global est fixé trop haut entraîne :","o":["un prix du carbone élevé et très incitatif","un prix des quotas très bas et une faible incitation à dépolluer","la disparition du marché","une taxe automatique"],"c":1,"e":"Si le plafond est trop généreux, l'offre de quotas est abondante, leur prix s'effondre et l'incitation à réduire les émissions devient faible (critique historique du SEQE)."},{"q":"La justice climatique pose notamment la question :","o":["de la répartition inégale des responsabilités et des impacts entre pays","de la suppression du GIEC","de l'interdiction des COP","du calcul du PIB"],"c":0,"e":"La justice climatique souligne que les pays les moins émetteurs subissent souvent le plus les effets du réchauffement, d'où le principe de responsabilités communes mais différenciées."},{"q":"Le principe de « responsabilités communes mais différenciées » signifie que :","o":["tous les pays doivent fournir exactement le même effort","les pays développés, historiquement plus émetteurs, doivent un effort accru","seuls les pays pauvres doivent agir","aucun pays n'a de responsabilité"],"c":1,"e":"Ce principe des négociations climatiques reconnaît une responsabilité partagée mais module l'effort selon le niveau de développement et les émissions historiques."},{"q":"Donner gratuitement des quotas aux entreprises plutôt que de les mettre aux enchères a pour inconvénient de :","o":["augmenter fortement les recettes publiques","priver l'État de recettes et pouvoir créer des effets d'aubaine","rendre le plafond inutile","supprimer le marché"],"c":1,"e":"L'allocation gratuite ne rapporte rien à l'État et peut offrir des rentes aux entreprises (effets d'aubaine), à la différence de la mise aux enchères."},{"q":"Un point commun entre taxe carbone et marché de quotas est qu'ils :","o":["fixent tous deux directement la quantité d'émissions","donnent un prix au carbone pour internaliser l'externalité","interdisent toute émission","ne reposent sur aucune action publique"],"c":1,"e":"Tous deux sont des instruments économiques qui attribuent un prix au carbone afin d'internaliser l'externalité, mais l'un fixe le prix, l'autre la quantité."},{"q":"L'empreinte écologique est un indicateur qui :","o":["mesure la richesse monétaire d'un pays","évalue la pression humaine sur les ressources rapportée à la biocapacité","fixe le prix des quotas","remplace les normes"],"c":1,"e":"L'empreinte écologique compare la consommation de ressources et l'absorption des déchets à la capacité régénératrice de la planète (biocapacité)."},{"q":"La difficulté à coordonner les États sur le climat tient surtout au fait que :","o":["le climat est un bien commun mondial exposé au passager clandestin","aucun pays n'émet de CO₂","il n'existe aucune institution internationale","le GIEC interdit la coopération"],"c":0,"e":"Le climat est un bien commun planétaire : chaque État est tenté de profiter des efforts des autres sans contribuer (passager clandestin), ce qui freine les accords."}],"vf":[{"s":"Le coût social est égal au coût privé augmenté du coût des externalités.","a":true,"e":"Coût social = coût privé + coût externe ; en présence d'externalité négative, le coût social dépasse le coût privé."},{"s":"En présence d'une externalité négative, le marché tend à sous-produire le bien polluant.","a":false,"e":"Au contraire, le pollueur ne supportant pas le coût externe, il surproduit par rapport à l'optimum social."},{"s":"Le théorème de Coase suppose des droits de propriété bien définis et de faibles coûts de transaction.","a":true,"e":"Coase montre que la négociation privée peut résoudre l'externalité sous ces conditions, sans intervention directe de l'État."},{"s":"La soutenabilité faible suppose que le capital naturel est substituable par du capital produit.","a":true,"e":"La soutenabilité faible admet la substitution capital naturel/capital technique ; la soutenabilité forte la refuse pour le capital naturel critique."},{"s":"Le GIEC fixe le prix mondial du carbone.","a":false,"e":"Le GIEC n'a aucun pouvoir de tarification : il synthétise les connaissances scientifiques. Le prix du carbone relève des taxes ou des marchés de quotas."},{"s":"La taxe carbone est souvent critiquée pour son caractère régressif.","a":true,"e":"À consommation comparable, elle pèse proportionnellement plus sur les ménages modestes, ce qui pose un problème d'acceptabilité sociale."},{"s":"Le marché de quotas fixe la quantité d'émissions et laisse le prix s'ajuster.","a":true,"e":"Le cap-and-trade plafonne la quantité (le cap) ; le prix résulte de l'offre et de la demande de quotas, à l'inverse de la taxe qui fixe le prix."},{"s":"Le principe de précaution s'applique à des risques avérés et certains.","a":false,"e":"La précaution vise des risques incertains mais graves et irréversibles ; ce sont des risques avérés que vise le principe de prévention."},{"s":"Un bien public pur est non rival et non exclusif.","a":true,"e":"Bien public pur : non rival et non exclusif. Le bien commun, lui, est rival mais non exclusif."},{"s":"L'effet rebond peut annuler une partie des gains d'une amélioration de l'efficacité énergétique.","a":true,"e":"Les économies d'énergie réalisées sont en partie compensées par une consommation accrue : c'est l'effet rebond."},{"s":"Le PIB déduit la dégradation du capital naturel.","a":false,"e":"Le PIB n'intègre pas l'épuisement des ressources et peut même croître avec les dépenses de réparation des dommages environnementaux."},{"s":"Le principe de responsabilités communes mais différenciées module l'effort climatique selon le niveau de développement.","a":true,"e":"Il reconnaît une responsabilité partagée mais demande un effort accru aux pays développés, historiquement plus émetteurs."},{"s":"Allouer gratuitement les quotas prive l'État des recettes qu'apporterait une mise aux enchères.","a":true,"e":"L'allocation gratuite ne génère pas de recettes publiques et peut créer des effets d'aubaine pour les entreprises."},{"s":"La taxe carbone et le marché de quotas donnent tous deux un prix au carbone.","a":true,"e":"Ce sont deux instruments économiques visant à internaliser l'externalité ; ils diffèrent selon qu'ils fixent le prix (taxe) ou la quantité (quotas)."},{"s":"L'Accord de Paris vise à contenir le réchauffement nettement en dessous de 2 °C.","a":true,"e":"Adopté lors de la COP21 (2015), il fixe l'objectif de rester bien en deçà de 2 °C, en visant si possible 1,5 °C."}],"trous":[{"t":"Le coût supporté par le seul producteur, hors externalités, est le coût _____.","a":"privé","alt":["prive"],"e":"Coût privé : supporté par l'agent. Le coût social y ajoute les externalités subies par les tiers."},{"t":"Coût social = coût privé + coût _____.","a":"externe","alt":["externalité"],"e":"Le coût social intègre le coût externe (l'externalité) que le coût privé ignore."},{"t":"La taxe carbone agit par le signal-_____ en renchérissant les biens polluants.","a":"prix","e":"En augmentant le prix relatif du carbone, la taxe réoriente les comportements de production et de consommation."},{"t":"Selon le théorème de _____, une externalité peut être réglée par la négociation si les droits de propriété sont définis.","a":"Coase","alt":["coase"],"e":"Coase : avec des droits de propriété clairs et de faibles coûts de transaction, les agents internalisent l'externalité sans intervention directe de l'État."},{"t":"Le rapport _____ (1987) a popularisé la définition du développement durable.","a":"Brundtland","alt":["brundtland"],"e":"Le rapport Brundtland définit le développement durable comme répondant aux besoins du présent sans compromettre ceux des générations futures."},{"t":"La soutenabilité _____ refuse la substitution du capital naturel par du capital produit.","a":"forte","e":"Soutenabilité forte : le capital naturel critique est irremplaçable. La soutenabilité faible admet sa substitution."},{"t":"Le groupe d'experts qui synthétise l'état des connaissances sur le climat est le _____.","a":"GIEC","alt":["giec"],"e":"Le GIEC produit des rapports de synthèse et joue le rôle d'expert dans la construction du problème public climatique."},{"t":"Intégrer le coût d'une externalité dans le prix payé par celui qui la génère, c'est l'_____.","a":"internaliser","alt":["internalisation"],"e":"Internaliser l'externalité rapproche coût privé et coût social (par taxe, quota, négociation)."},{"t":"Le système européen de quotas fonctionne selon le principe du « plafonner-et-_____ » (cap-and-trade).","a":"échanger","alt":["echanger"],"e":"Le cap-and-trade fixe un plafond d'émissions et autorise l'échange des quotas entre acteurs."},{"t":"Le bien public pur est non rival et non _____.","a":"exclusif","e":"Non exclusif : on ne peut empêcher quiconque d'en bénéficier ; non rival : l'usage de l'un n'enlève rien aux autres."},{"t":"Quand des gains d'efficacité énergétique sont compensés par une hausse de la consommation, on parle d'effet _____.","a":"rebond","e":"L'effet rebond réduit l'efficacité réelle des progrès techniques en matière d'économies d'énergie."},{"t":"L'indicateur qui compare la pression humaine sur les ressources à la biocapacité est l'empreinte _____.","a":"écologique","alt":["ecologique"],"e":"L'empreinte écologique mesure si la consommation de ressources dépasse la capacité régénératrice de la planète."},{"t":"Le principe de _____ autorise l'action face à un risque grave malgré l'incertitude scientifique.","a":"précaution","alt":["precaution"],"e":"La précaution vise les risques incertains et irréversibles ; la prévention vise les risques avérés."},{"t":"L'accord adopté lors de la COP21 en 2015 est l'Accord de _____.","a":"Paris","alt":["paris"],"e":"L'Accord de Paris fixe l'objectif de contenir le réchauffement nettement sous 2 °C."},{"t":"Le principe de responsabilités communes mais _____ module l'effort climatique selon le développement.","a":"différenciées","alt":["differenciees","différenciée"],"e":"Il demande un effort accru aux pays développés, historiquement les plus gros émetteurs."}]});
})();
